-- Poems batch 298
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('152a93cd-fec9-4923-83a9-d8a7f8c48d64','青青西門槐','王安石','宋','宋诗','song-poetry','','[]','人情甘阿諛，我獨倦請謁。',48,'全唐诗/poet.song.31000.json','["人情甘阿諛，我獨倦請謁。", "尤於權門疏，萬事亦已拙。", "平生江湖期，夢寐不可遏。", "青青西門槐，少解馬上暍。"]'),
('457118d4-0498-44ad-a45c-37d4fbe26c91','天下不用車','王安石','宋','宋诗','song-poetry','','[]','天下不用車，人人乘馬馳。',96,'全唐诗/poet.song.31000.json','["天下不用車，人人乘馬馳。", "王良雖善御，攬轡欲從誰。", "漢武伐大宛，殺人若京坻。", "孝文却走馬，獨行先安之。", "萬物命在天，取舍各有時。", "陰陽更用事，冬暖豈所宜。", "卞氏强獻玉，兩刖亦已癡。", "幸終遇良工，已剖得不疑。"]'),
('e6499abf-472a-4652-bfe4-46f1e93b3dd1','山田久欲拆','王安石','宋','宋诗','song-poetry','','[]','山田久欲拆，秋至尚求雨。',96,'全唐诗/poet.song.31000.json','["山田久欲拆，秋至尚求雨。", "婦女喜秋凉，踏車多笑語。", "朔雲卷衆水，慘淡吹平楚。", "橫陂與直塹，疑即沒洲渚。", "霍霍反照中，散絲魚幾縷。", "鴻蒙不可問，且往知何許。", "欹眠露下舸，側見星月吐。", "龍骨已嘔啞，田家真作苦。"]'),
('f4a54e4c-4549-4fae-9a4e-2887ac14854f','聖賢何常施','王安石','宋','宋诗','song-poetry','','[]','聖賢何常施，所遇有伸屈。',48,'全唐诗/poet.song.31000.json','["聖賢何常施，所遇有伸屈。", "曲士守一隅，欲以齊萬物。", "喪非不欲富，言爲南宮出。", "世無子有子，誰敢救其失。"]'),
('14f15aa1-c8d0-4bb7-aacf-b941ab556b5d','散髮一扁舟','王安石','宋','宋诗','song-poetry','','[]','散髮一扁舟，夜長眠屢起。',48,'全唐诗/poet.song.31000.json','["散髮一扁舟，夜長眠屢起。", "秋水瀉明河，迢迢藕花底。", "愛此露的皪，復憐雲綺靡。", "諒無與歌絃，幽獨亦可喜。"]'),
('1eefca21-919b-440c-820d-0e1194674a88','道人北山來','王安石','宋','宋诗','song-poetry','','[]','道人北山來，問松我東岡。',72,'全唐诗/poet.song.31000.json','["道人北山來，問松我東岡。", "舉手指屋脊，云今如此長。", "開田故歲收，種果今年嘗。", "告叟去復來，耘鋤尚康强。", "死狐正首丘，遊子思故鄉。", "嗟我行老矣，墳墓安可忘。"]'),
('ad9750a6-4640-46c6-b3e8-547e71cc10a7','今日非昨日','王安石','宋','宋诗','song-poetry','','[]','今日非昨日，昨日已可思。',120,'全唐诗/poet.song.31000.json','["今日非昨日，昨日已可思。", "明日異今日，如何能勿悲。", "當門五六樹，上有蟬鳴枝。", "朝聽尚壯急，暮聞已衰遲。", "仰看青青葉，亦復少華滋。", "萬物同一氣，固知當爾爲。", "我友南山居，笑談解人頤。", "分我秋柏實，問言歸何時。", "衣冠污窮塵，苟得猶苦饑。", "低徊歲已晚，恐負平生期。"]'),
('c211c1fc-d3bc-4f07-bff9-23061c8f95b5','秋日不可見','王安石','宋','宋诗','song-poetry','','[]','秋日不可見，林端但餘黄。',48,'全唐诗/poet.song.31000.json','["秋日不可見，林端但餘黄。", "杖藜思平野，俛仰畏無光。", "栗栗澗谷風，吹我衣與裳。", "娟娟空山月，照我冠上霜。"]'),
('fb6d2bc3-59bb-4f8b-afd0-55f9891c0374','騏驥在霜野','王安石','宋','宋诗','song-poetry','','[]','騏驥在霜野，低徊向衰草。',48,'全唐诗/poet.song.31000.json','["騏驥在霜野，低徊向衰草。", "入櫪聞秋風，悲鳴思長道。", "黄金作鞭轡，粲粲空外好。", "人生貴得意，不必恨枯槁。"]'),
('a29bbe03-438e-45ac-86be-30b9e7890a6e','悲哉孔子沒','王安石','宋','宋诗','song-poetry','','[]','悲哉孔子沒，千歲無麒麟。',48,'全唐诗/poet.song.31000.json','["悲哉孔子沒，千歲無麒麟。", "蚩蚩盡鉏商，此物誰能珍。", "漢武得一角，燔烹誣鬼神。", "更以鑄黄金，傳夸後世人。"]'),
('9ff8a112-49c3-4e47-bcea-f45c7dce342f','秋庭午吏散','王安石','宋','宋诗','song-poetry','','[]','秋庭午吏散，予亦歸息偃。',48,'全唐诗/poet.song.31000.json','["秋庭午吏散，予亦歸息偃。", "豈無嘉賓客，欲往心獨懶。", "北窗古人篇，一讀三四反。", "悲哉不蚤計，失道行晼晚。"]'),
('bd5926a6-ebfb-4e09-8b32-72b5c34f3983','秋日在梧桐','王安石','宋','宋诗','song-poetry','','[]','秋日在梧桐，轉陰如急轂。',48,'全唐诗/poet.song.31000.json','["秋日在梧桐，轉陰如急轂。", "冥冥蔽中庭，下視今可暴。", "高蟬不復嘒，稍得寒鴉宿。", "百繞有衰翁，行歌待春綠。"]'),
('969a9c4c-4843-499e-b24b-2d848c3db111','我欲往滄海','王安石','宋','宋诗','song-poetry','','[]','我欲往滄海，客來自河源。',72,'全唐诗/poet.song.31000.json','["我欲往滄海，客來自河源。", "手探囊中膠，救此千載渾。", "我語客徒爾，當還治崑崙。", "歎息謝不能，相看涕翻盆。", "客止我且往，濯髮扶桑根。", "春風吹我舟，萬里空目存。"]'),
('b18ed0a4-9bea-462b-ae13-3cc917c0f5a4','前日石上松  其一','王安石','宋','宋诗','song-poetry','','[]','前日石上松，斸移沙水際。',24,'全唐诗/poet.song.31000.json','["前日石上松，斸移沙水際。", "青青折釵股，俯映幽人砌。"]'),
('76ee856d-6ef4-4149-b6f3-e241905c5a6c','日出堂上飲','王安石','宋','宋诗','song-poetry','','[]','日出堂上飲，日西未云休。',144,'全唐诗/poet.song.31000.json','["日出堂上飲，日西未云休。", "主人笑而歌，客子歎以愀。", "指此堂上柱，始生在巖幽。", "雨露飽所滋，凌雲亦千秋。", "所託願求久，何言值君收。", "乃令卑濕地，百蟻上窮鎪。", "丹青空外好，鎮壓已堪憂。", "爲君重去之，不使一蟻留。", "蟻力雖云小，能生萬蚍蜉。", "又能高其礎，不爾繼者稠。", "語客且勿然，百年等浮漚。", "爲客當酌酒，何豫主人謀。"]'),
('946aac45-e999-4c58-bf66-2341df5de153','孔子','王安石','宋','宋诗','song-poetry','','[]','聖人道大能亦博，學者所得皆秋毫。',64,'全唐诗/poet.song.31000.json','["聖人道大能亦博，學者所得皆秋毫。", "雖傳古未有孔子，蠛蠓何足知天高。", "桓魋武叔不量力，欲撓一草摇蟠桃。", "顔回已自不可測，至死鑽仰忘身勞。"]'),
('883c2d3a-0f5c-4877-a06c-34db7967aa64','揚雄二首  其一','王安石','宋','宋诗','song-poetry','','[]','子雲游天祿，華藻銳初學。',120,'全唐诗/poet.song.31000.json','["子雲游天祿，華藻銳初學。", "覃思晚有得，晦顯無適莫。", "寥寥鄒魯後，於此歸先覺。", "豈嘗知符命，何苦自投閣。", "長安諸愚儒，操行自爲薄。", "謗嘲出異己，傳載因疏略。", "孟軻勸伐燕，伊尹干說亳。", "叩馬觸兵鋒，食牛要祿爵。", "少知羞不爲，况彼皆卓犖。", "史官蔽多聞，自古喜穿鑿。"]'),
('847e0d59-0188-4f9f-b201-a9a62f325389','揚雄二首  其二','王安石','宋','宋诗','song-poetry','','[]','子雲平生人莫知，知者乃獨稱其辭。',64,'全唐诗/poet.song.31000.json','["子雲平生人莫知，知者乃獨稱其辭。", "今尊子雲者皆是，得子雲心亦無幾。", "聖賢樹立自有師，人知不知無以爲。", "俗人賤今常貴古，子雲今存誰女數。"]'),
('2172d7f2-2796-47a1-a540-bb49c6402cc4','漢文帝','王安石','宋','宋诗','song-poetry','','[]','輕刑死人衆，喪短生者偷。',48,'全唐诗/poet.song.31000.json','["輕刑死人衆，喪短生者偷。", "仁孝自此薄，哀哉不能謀。", "露臺惜百金，灞陵無高丘。", "淺恩施一時，長患被九州。"]'),
('1aef45bf-f0f1-4b22-8e83-bc6175f430fa','秦始皇','王安石','宋','宋诗','song-poetry','','[]','天方獵中原，狐兔在所憎。',84,'全唐诗/poet.song.31000.json','["天方獵中原，狐兔在所憎。", "傷哉六孱王，當此鷙鳥膺。", "搏取已掃地，翰飛尚憑凌。", "遊將跨蓬萊，以海爲丘陵。", "勒石頌功德，群臣助驕矜。", "舉世不讀易，但以刑名稱。", "蚩蚩彼少子，何用辨堅冰。"]'),
('0d636044-e98a-49b1-9e3a-709a882b61e8','韓信','王安石','宋','宋诗','song-poetry','','[]','韓信寄食常歉然，邂逅漂母能哀憐。',112,'全唐诗/poet.song.31000.json','["韓信寄食常歉然，邂逅漂母能哀憐。", "當時噲等何由伍，但有淮陰惡少年。", "誰道蕭曹刀筆吏，從容一語知人意。", "壇上平明大將旗，舉軍盡驚王不疑。", "捄兵半楚濰半沙，從初龍且聞信怯。", "鴻溝天下已橫分，談笑重來卷楚氛。", "但以怯名終得羽，誰爲孔費兩將軍。"]'),
('0281062d-ab99-446a-bdaa-a7d5d03ef880','叔孫通','王安石','宋','宋诗','song-poetry','','[]','先生秦博士，秦禮頗能熟。',60,'全唐诗/poet.song.31000.json','["先生秦博士，秦禮頗能熟。", "量主欲有爲，兩生皆不欲。", "草具一王儀，群豪果知肅。", "黄金既遍賜，短衣亦已續。", "儒術自此凋，何爲反初服。"]'),
('7a530d69-c353-4f6c-a7a2-ba23c5ba7c6d','東方朔','王安石','宋','宋诗','song-poetry','','[]','平原狂先生，隠翳世上塵。',96,'全唐诗/poet.song.31000.json','["平原狂先生，隠翳世上塵。", "材多不可數，射覆亦絕倫。", "談辭最詼怪，發口如有神。", "以此得親幸，賜予頗不貧。", "金玉本光瑩，泥沙豈能堙。", "時時一悟主，驚動漢庭臣。", "不肯下兒童，敢言詆平津。", "何知夷與惠，空復忤時人。"]'),
('eabe4884-9162-4adf-afc6-2f8a4158e793','楊劉','王安石','宋','宋诗','song-poetry','','[]','人各有是非，犯時爲患害。',96,'全唐诗/poet.song.31000.json','["人各有是非，犯時爲患害。", "唯詩以譎諫，言者得無悔。", "汾王昔監謗，變雅今尚載。", "末俗忌諱繁，此理寧復在。", "南山咏種豆，議法過四罪。", "玄都戲桃花，母子受顛沛。", "疑似已如此，况欲諄諄誨。", "事變故不同，楊劉可爲戒。"]'),
('479d7fea-bba8-4c7d-bfa8-112f1f02e563','臧倉','王安石','宋','宋诗','song-poetry','','[]','位在萬乘師，孟軻猶不遇。',48,'全唐诗/poet.song.31000.json','["位在萬乘師，孟軻猶不遇。", "豈云貧與賤，世道非吾趣。", "意行天下福，事忤由然去。", "命也固有在，臧倉汝何與。"]'),
('c380c925-7d6d-4a05-8dc3-d687251188aa','田單','王安石','宋','宋诗','song-poetry','','[]','湣王萬乘齊，走死區區燕。',72,'全唐诗/poet.song.31000.json','["湣王萬乘齊，走死區區燕。", "田單一即墨，掃敵如風旋。", "舞鳥怪不測，騰牛怒無前。", "飄颻樂毅去，磊砢功名傳。", "掘葬與劓降，論乃愧儒先。", "深誠可奮士，王蠋豈非賢。"]'),
('b7ebc31a-de60-4da4-afc3-c5c8794e1794','戴不勝','王安石','宋','宋诗','song-poetry','','[]','昔在宋王所，皆非薛居州。',48,'全唐诗/poet.song.31000.json','["昔在宋王所，皆非薛居州。", "區區一不勝，辛苦亦何求。", "懷祿詎有耻，知命乃無憂。", "此士自可憐，能復識此不。"]'),
('8a61458d-4178-4a57-8358-a7024e195e3a','陸忠州','王安石','宋','宋诗','song-poetry','','[]','虞人以士招，御者與射比。',48,'全唐诗/poet.song.31000.json','["虞人以士招，御者與射比。", "當時尚羞爲，况乃天下士。", "英英陸忠州，學問輔明智。", "低徊得坎坷，勳業終不遂。"]'),
('101f311f-b4a7-45ae-bcfb-5f184f3bad60','開元行','王安石','宋','宋诗','song-poetry','','[]','君不聞開元盛天子，糾合儁傑披奸猖。',115,'全唐诗/poet.song.31000.json','["君不聞開元盛天子，糾合儁傑披奸猖。", "幾年辛苦補四海，始得完好無疽瘡。", "一朝寄託誰家子，威福顛倒那復理。", "那知赤子偏愁毒，祇見狂胡倉卒起。", "茫茫孤行西萬里，偪仄歸來竟憂死。", "子孫險不失故物，社稷陵夷從此始。", "由來犬羊著冠坐廟堂，安得四鄙無豺狼。"]'),
('f3e95800-6b2c-420d-b2d6-21d2e04492c5','相送行效張籍','王安石','宋','宋诗','song-poetry','','[]','一車南，一車北，身世悤悤俱有役。',64,'全唐诗/poet.song.31000.json','["一車南，一車北，身世悤悤俱有役。", "憶昔論心兩綢繆，那知相送不得留。", "但聞馬嘶覺已遠，欲望應須上前坂。", "秋風忽起吹泥塵，雙目空回不見人。"]'),
('c50b69f4-af95-493c-b2bb-35d6aca31ff4','陰漫漫行','王安石','宋','宋诗','song-poetry','','[]','愁雲怒風相追逐，青山滅沒滄江覆。',64,'全唐诗/poet.song.31000.json','["愁雲怒風相追逐，青山滅沒滄江覆。", "少留燈火就空床，更聽波濤圍野屋。", "憶昨踏雪度長安，夜宿木瘤還苦寒。", "誰云當春便妍暖，十日九八陰漫漫。"]'),
('9ca8cb22-5ebc-4f7f-a722-53168c7c0767','一日歸行','王安石','宋','宋诗','song-poetry','','[]','賤貧奔走食與衣，百日奔走一日歸。',64,'全唐诗/poet.song.31000.json','["賤貧奔走食與衣，百日奔走一日歸。", "平生歡意苦不盡，正欲老大相因依。", "空房蕭瑟施繐帷，青燈半夜哭聲稀。", "音容想像今何處，地下相逢果是非。"]'),
('5b1a33a7-9323-4088-9a4d-c2c9cb06e60d','汴水','王安石','宋','宋诗','song-poetry','','[]','汴水無情日夜流，不肯爲我少淹留。',64,'全唐诗/poet.song.31000.json','["汴水無情日夜流，不肯爲我少淹留。", "相逢故人昨夜去，不知今日到何州。", "州州人物不相似，處處蟬鳴令客愁。", "可憐南北意不就，二十起家今白頭。"]'),
('7891f91d-538c-4025-a749-ae65a8c5fddd','陰山畫虎圖','王安石','宋','宋诗','song-poetry','','[]','陰山健兒鞭鞚急，走勢能追北風及。',168,'全唐诗/poet.song.31000.json','["陰山健兒鞭鞚急，走勢能追北風及。", "逶迤一虎出馬前，白羽橫穿更人立。", "回旗倒戟四邊動，抽矢當前放蹄入。", "爪牙蹭蹬不得施，磧上流丹看來濕。", "胡天朔漠殺氣高，煙雲萬里埋弓刀。", "穹廬無工可貌此，漢使自解丹青包。", "堂上絹素開欲裂，一見猶能動毛髮。", "低徊使我思古人，此地摶兵走戎羯。", "禽逃獸遁亦蕭然，豈若封疆今晏眠。", "契丹弋獵漢耕作，飛將自老南山邊，還能射虎隨少年。"]'),
('c9be51f1-7319-4128-b13b-3f5c7ba4b6e9','杜甫畫像','王安石','宋','宋诗','song-poetry','','[]','吾觀少陵詩，爲與元氣侔。',182,'全唐诗/poet.song.31000.json','["吾觀少陵詩，爲與元氣侔。", "力能排天斡九地，壯顔毅色不可求。", "浩蕩八極中，生物豈不稠。", "醜妍巨細千萬殊，竟莫見以何雕鎪。", "惜哉命之窮，顛倒不見收。", "青衫老更斥，餓走半九州。", "瘦妻僵前子仆後，攘攘盜賊森戈矛。", "吟哦當此時，不廢朝廷憂。", "常願天子聖，大臣各伊周。", "寧令吾廬獨破受凍死，不忍四海寒颼颼。", "傷屯悼屈止一身，嗟時之人死所羞。", "所以見公像，再拜涕泗流。", "惟公之心古亦少，願起公死從之游。"]'),
('c92a4921-6a91-4f5b-ba7b-94c205012536','吳長文新得顔公壞碑','王安石','宋','宋诗','song-poetry','','[]','魯公之書既絕倫，歲久更爲時所珍。',176,'全唐诗/poet.song.31000.json','["魯公之書既絕倫，歲久更爲時所珍。", "荒壇壞冢朽崖屋，剝落風雨埋煨塵。", "斷碑數尺誰所得，點畫入紙完如新。", "延陵公子好事者，拓取持寄情相親。", "六書篆籀數變改，訓詁後世多失真。", "誰初妄鑿妍與醜，坐使學士勞骸筋。", "堂堂魯公勇且仁，出遇世難親經綸。", "揮毫卓犖又驚俗，豈亦以此誇常民。", "但疑技巧有天得，不必勉强方通神。", "詩歌甘棠美召伯，愛惜蔽芾由思人。", "時危忠誼常恨少，寶此勿復令埋堙。"]'),
('0b1530c2-12da-46f7-aa5e-8e714e925760','答揚州劉原甫','王安石','宋','宋诗','song-poetry','','[]','少食苦不足，一官聊自謀。',72,'全唐诗/poet.song.31000.json','["少食苦不足，一官聊自謀。", "爲生晚更拙，懷祿尚遲留。", "黽勉詎有補，强顔包衆羞。", "謂我古人風，知君以相優。", "君實高世才，主恩正綢繆。", "哿矣哀此民，華簪寧易投。"]'),
('ea03b351-a461-4bac-9df8-a8664b5a16f3','寄岳州張使君','王安石','宋','宋诗','song-poetry','','[]','昔人寧飲建業水，共道不食武昌魚。',80,'全唐诗/poet.song.31000.json','["昔人寧飲建業水，共道不食武昌魚。", "公來建業每自如，亦復不厭武昌居。", "武昌山川今可想，綠水逶迤煙莽蒼。", "白鷗晴飛隨兩槳，岸薺茸茸映魚網。", "投老留連陌上塵，思公一語何由往。"]'),
('47908e28-eee8-4fa2-9623-315b1da2655d','送元厚之待制知福州','王安石','宋','宋诗','song-poetry','','[]','海隅山谷閒，人物最多處。',132,'全唐诗/poet.song.31000.json','["海隅山谷閒，人物最多處。", "平旦息相吹，連城黕如霧。", "閩王舊宮室，丹漆美無度。", "今爲大帥府，千里來赴愬。", "元侯文章翁，更以吏能著。", "峨峨中天閣，鳴玉新改步。", "銜詔出梨嶺，方爲遠人慕。", "旌旗滿流水，冠蓋東門駐。", "四坐共咨嗟，疑侯不當去。", "張仲稱孝友，樊侯正求助。", "名城雖云樂，行矣未宜遽。"]'),
('725562c9-81f5-48dc-842f-3a53a95ab42a','悼四明杜醇','王安石','宋','宋诗','song-poetry','','[]','杜生四五十，孝友稱鄉里。',120,'全唐诗/poet.song.31000.json','["杜生四五十，孝友稱鄉里。", "隠約不外求，耕桑有妻子。", "藜杖牧鷄豚，筠筒釣魴鯉。", "歲時沽酒歸，亦不乏甘旨。", "天涯一杯飯，夙昔相逢喜。", "談辭足詩書，篇咏又清泚。", "都城問越客，安否常在耳。", "日月未渠央，如何棄予死。", "古風久凋零，好學少爲己。", "悲哉四明山，此士今已矣。"]'),
('ca5c7b93-ad6b-4dd2-89eb-213a439c7117','哭梅聖俞','王安石','宋','宋诗','song-poetry','','[]','詩行於世先春秋，國風變衰始柏舟。',264,'全唐诗/poet.song.31000.json','["詩行於世先春秋，國風變衰始柏舟。", "文辭感激多所憂，律呂尚可諧鳴球。", "先王澤竭士已偷，紛紛作者始可羞。", "其聲與節急以浮，真人當天施再流。", "篤生梅公應時求，頌歌文武功業優。", "經奇緯麗散九州，衆皆少銳老則不。", "翁獨辛苦不能休，惜無采者人名遒。", "貴人憐公青兩眸，吹噓可使高岑樓。", "坐令隠約不見收，空能乞錢助饙餾。", "疑此有物司諸幽，棲棲孔孟葬魯鄒。", "後始卓犖稱軻丘，聖賢與命相楯矛。", "勢欲强達誠無由，詩人况又多窮愁。", "李杜亦不爲公侯，公窺窮阨以身投。", "坎軻坐老當誰尤，吁嗟豈即非善謀。", "虎豹雖死皮終留，飄然載喪下陰溝。", "粉書軸幅懸無旒，高堂萬里哀白頭。", "東望使我商聲謳。"]'),
('6fd26a70-b045-4dff-b5b4-e9e9acf2ea28','遊章義寺','王安石','宋','宋诗','song-poetry','','[]','九日章義寺，倦遊因解鑣。',120,'全唐诗/poet.song.31000.json','["九日章義寺，倦遊因解鑣。", "拂榻寄午夢，起尋北山椒。", "岑蔚鳥絕迹，悲鳴唯一蜩。", "歡言與僧期，於此共簞瓢。", "斬松八九根，窗壁具一朝。", "伏檻何所見，蒼蒼圍寂寥。", "巖谷寒更靜，水泉清不摇。", "安得有車馬，尚無漁與樵。", "神茂真觀復，心明衆塵消。", "陰嶺有嘉客，儻來不須招。"]'),
('4aed5a60-b9ba-48df-b227-68cc4cede02f','飯祈澤寺','王安石','宋','宋诗','song-poetry','','[]','駕言東南遊，午飯投僧館。',72,'全唐诗/poet.song.31000.json','["駕言東南遊，午飯投僧館。", "山白梅蕊長，林黄柳芽短。", "笭箵沙際來，略彴桑閒斷。", "春映一川明，雪消千壑漫。", "魚隨竹影浮，鳥誤人聲散。", "翫物豈能留，干時吾自懶。"]'),
('de11fbd5-0e78-4d47-b3f5-748ba421f74e','答瑞新十遠','王安石','宋','宋诗','song-poetry','','[]','遠水悠然碧，遠山天際蒼。',48,'全唐诗/poet.song.31000.json','["遠水悠然碧，遠山天際蒼。", "中有山水人，寄我十遠章。", "我時在高樓，徙倚觀八荒。", "亦復有遠意，千載不相忘。"]'),
('5c776db2-2e14-48df-9a01-29cb97d0dd81','送文學士倅邛州','王安石','宋','宋诗','song-poetry','','[]','文翁出治蜀，蜀士始文章。',120,'全唐诗/poet.song.31000.json','["文翁出治蜀，蜀士始文章。", "司馬唱成都，嗣音得王揚。", "犖犖漢守孫，千秋起相望。", "操筆賦上林，脫巾選爲郎。", "擁書天祿閣，奇字校偏傍。", "忽乘駟馬車，牛酒過故鄉。", "時平無諭檄，不訪碧雞祥。", "問君行何爲，關隴正繁霜。", "中和助宣布，循吏綴前芳。", "豈特爲親榮，區區夸一方。"]'),
('ae5be805-16d1-4b46-a336-57f00a1d1c29','送宋中道倅洺州','王安石','宋','宋诗','song-poetry','','[]','漳水不灌鄴，不知幾何時。',77,'全唐诗/poet.song.31000.json','["漳水不灌鄴，不知幾何時。", "後世有史起，乃能爲可爲。", "余嘗憐洺民，{舃臼=血}鹵半不治。", "頗覺漳可引，但爲談者嗤。", "高議不同俗，功成人始思。", "夫子到官日，勿忘吾此詩。"]'),
('b51c031d-a3ee-4795-9235-ade0a069a1ed','送張公儀宰安豐','王安石','宋','宋诗','song-poetry','','[]','楚客來時雁爲伴，歸期祇待春冰泮。',64,'全唐诗/poet.song.31000.json','["楚客來時雁爲伴，歸期祇待春冰泮。", "雁飛南北三兩回，回首湖山空夢亂。", "祕書一官聊自慰，安豐百里誰復嘆。", "揚鞭去去及芳時，壽酒千觴花爛熳。"]'),
('500a4b4b-ed85-4bee-a231-fbcf7f12182c','送陳諤','王安石','宋','宋诗','song-poetry','','[]','有司昔者患不公，糊名謄書今故密。',64,'全唐诗/poet.song.31000.json','["有司昔者患不公，糊名謄書今故密。", "論才相若子獨棄，外物有命真難必。", "鄉閭孝友莫如子，我願卜鄰非一日。", "朱門奕奕行多慚，歸矣無爲惡蓬蓽。"]'),
('d53f3761-bae0-4549-8e8c-ea59be946bbf','送孫長倩歸輝州','王安石','宋','宋诗','song-poetry','','[]','溪澗得雨潦，奔溢不可航。',48,'全唐诗/poet.song.31000.json','["溪澗得雨潦，奔溢不可航。", "江海收百川，浩浩誰能量。", "溪澗之日短，江海之日長。", "願生畜道德，江海以自方。"]'),
('c4f7c190-e089-4399-9eb8-e2380264f7b3','送喬執中秀才歸高郵','王安石','宋','宋诗','song-poetry','','[]','薄飯午不羹，空爐夜無炭。',120,'全唐诗/poet.song.31000.json','["薄飯午不羹，空爐夜無炭。", "寥寥日避席，烈烈風欺幔。", "謂予勿惡此，何爲向子歎。", "長年客塵沙，無婦助親爨。", "寒暄慰白首，我弟纔將冠。", "邅迴歲又晚，想見淮湖漫。", "古人一日養，不以三公換。", "田園在戮力，且欲歸鋤灌。", "行矣子誠然，光陰未宜翫。", "負米力有餘，能無讀書伴。"]'),
('76401a63-20cc-4543-abec-6ce417810e13','雲山詩送正之','王安石','宋','宋诗','song-poetry','','[]','雲山參差碧相圍，溪水詰曲带城陴。',64,'全唐诗/poet.song.31000.json','["雲山參差碧相圍，溪水詰曲带城陴。", "溪窮壤斷至者誰，予獨與子相諧熙。", "山城之西鼓吹悲，水風蕭蕭不滿旗。", "子今去此來無時，予有不可誰予規。"]'),
('c7e86a84-f2f3-46e1-8c16-746fef0a1afb','和甫如京師微之置酒','王安石','宋','宋诗','song-poetry','','[]','季子將北征，貂裘解亭皋。',120,'全唐诗/poet.song.31000.json','["季子將北征，貂裘解亭皋。", "使君擁鳴騶，出餞載酒醪。", "作詩寵行色，坐客多賢豪。", "信知大夫才，能賦在登高。", "陟峯憂未已，强歌反哀號。", "問言歸何時，逮此冬風饕。", "川塗良阻脩，箠轡慎所操。", "黄屋初啟聖，萬靈歸一陶。", "詢謀及疏賤，拔取皆時髦。", "往矣果有合，可辭州縣勞。"]'),
('ac8ebf03-89e8-4a41-bfc2-3549ea27567e','別孫莘老','王安石','宋','宋诗','song-poetry','','[]','逢原未熟我，已與子相知。',192,'全唐诗/poet.song.31000.json','["逢原未熟我，已與子相知。", "自吾得逢原，知子更不疑。", "把手湖上舟，望子欲歸時。", "茫然乃分散，獨背東南馳。", "寥寥西城居，邂逅與子期。", "鷄鳴入省門，朱墨來紛披。", "含意不自得，强顔聊爾爲。", "會合常在夜，青燈照書詩。", "往往並衾語，至明不言疲。", "悤悤捨我去，使我當從誰。", "送子不出門，我身方羈縻。", "我心得自如，今與子相隨。", "隨子至湖上，逢原所嘗嬉。", "想見荷葉盡，北風卷寒漪。", "已懷今日愁，更念昔日悲。", "相逢亦何有，但有鏡中絲。"]'),
('faa66ce2-890d-4f81-92ae-3e2d3db22bc5','寄丁中允','王安石','宋','宋诗','song-poetry','','[]','人生九州閒，泛泛水中木。',204,'全唐诗/poet.song.31000.json','["人生九州閒，泛泛水中木。", "漂浮隨風波，邂逅得相觸。", "始我與夫子，得官同一州。", "相逢皆偶然，情義乃綢繆。", "我於人事疏，而子久矣修。", "磨礱以成我，德大不可酬。", "乖離今六年，念子未嘗休。", "豈不道相逢，但得頃刻留。", "歡喜不滿顔，長年抱離憂。", "古人有所思，千里駕車牛。", "如何咫尺間，而不與予遊。", "顧惜五斗米，無辜自拘囚。", "念彼磊落者，心顔兩慚羞。", "剡山碧榛榛，剡水日夜流。", "山行苦無巇，水淺亦可舟。", "使君子所善，來檄自可求。", "何時子來意，待子南山頭。"]'),
('b7be252f-cec9-4234-9199-feff292f1739','示平甫弟','王安石','宋','宋诗','song-poetry','','[]','汴渠西受崑崙水，五月奔湍射黄矢。',160,'全唐诗/poet.song.31000.json','["汴渠西受崑崙水，五月奔湍射黄矢。", "高淮夜入忽倒流，碕岸相看欲生嘴。", "萬檣如山矻不動，嗟我仲子行亦止。", "自聞留連且一月，每得問訊猶千里。", "老工取河天上落，伏礫邅沙卷無底。", "土橋立馬望城東，數日知有相逢喜。", "牆隅返照媚槐穀，池面過雨蘇篁葦。", "欣然把手相與閑，所願此時無一詭。", "豈無他憂能老我，付與天地從今始。", "閉門爲謝載酒人，外慕紛紛吾已矣。"]'),
('f74ea1e4-a06b-4e35-b101-626903dce25a','憶北山送勝上人','王安石','宋','宋诗','song-poetry','','[]','蒼藤翠木江南山，激激流水兩山間。',64,'全唐诗/poet.song.31000.json','["蒼藤翠木江南山，激激流水兩山間。", "山高水深魚鳥樂，車馬迹絕人長閑。", "雲埋樵聲隔葱蒨，月弄釣影臨潺湲。", "黄塵滿眼衣可濯，夢寐惆悵何時還。"]'),
('5ae06be9-6b13-41b4-89b3-f42566e496d8','相國寺啟同天節道場行香院觀戲者','王安石','宋','宋诗','song-poetry','','[]','侏優戲場中，一貴復一賤。',24,'全唐诗/poet.song.31000.json','["侏優戲場中，一貴復一賤。", "心知本自同，所以無欣怨。"]'),
('3b6308b1-883f-4261-96a6-a811db86ffc5','馬上轉韵','王安石','宋','宋诗','song-poetry','','[]','三月楊花迷眼白，四月柳條空老碧。',64,'全唐诗/poet.song.31000.json','["三月楊花迷眼白，四月柳條空老碧。", "年光如水儘東流，風物看看又到秋。", "人世百年能幾許，何須戚戚長辛苦。", "富貴功名自有時，簞瓢捽茹亦山雌。"]'),
('cb7e08ec-6089-4e34-8037-280566d795c1','乙巳九月登冶城作','王安石','宋','宋诗','song-poetry','','[]','欲望鍾山岑，因知冶城路。',48,'全唐诗/poet.song.31000.json','["欲望鍾山岑，因知冶城路。", "躋攀隠木杪，稍記曾遊處。", "紅沉渚上日，蒼起榛中霧。", "即事有哀傷，山川自如故。"]'),
('21637d76-4720-40cb-b8f1-ada79123aa2e','過劉貢甫','王安石','宋','宋诗','song-poetry','','[]','去年約子遊山陂，今者仍爲大梁客。',128,'全唐诗/poet.song.31000.json','["去年約子遊山陂，今者仍爲大梁客。", "天旋日月不少留，稱意人閒寧易得。", "天明徑欲相就語，雲雪填城萬家白。", "冬風吹鬣馬更驕，一出何由問行迹。", "能言奇字世已少，終欲追攀豈辭劇。", "枕中鴻寶舊所傳，飲我寧辭酒或索。", "吾願與子同醉醒，顔狀雖殊心不隔。", "故知今有可憐人，回首紛紛斗筲窄。"]'),
('7de9ed5f-be5b-48ec-95a6-97fdef2d9e31','估玉','王安石','宋','宋诗','song-poetry','','[]','潼關西山古藍田，有氣鬰鬰高拄天。',192,'全唐诗/poet.song.31000.json','["潼關西山古藍田，有氣鬰鬰高拄天。", "雄虹雌霓相結纏，晝夜不散非雲煙。", "秦人挾斤上其巔，視氣所出深鑱鎸。", "得物盈尺方且堅，以斤試叩聲泠然。", "持歸市上求百錢，人皆疑嗟莫愛憐。", "大梁老估聞不眠，操金喜取走蹁躚。", "深藏牢包三十年，光怪鄰里驚相傳，欲獻天子無由緣。", "朝廷昨日鍾鼓縣，呼工琢圭寘神筵。", "玉材細瑣不中權，賈孫抱物詔使前。", "紅羅複疊帕紫氈，發視紺碧光屬聯。", "詔問與價當幾千，衆工讓口無敢先。", "嗟我豈識真與全。"]'),
('6b793988-77c0-4317-92fa-475b9873911b','信都公家白兔','王安石','宋','宋诗','song-poetry','','[]','水精爲宮玉爲田，姮娥縞衣洗朱鉛。',160,'全唐诗/poet.song.31000.json','["水精爲宮玉爲田，姮娥縞衣洗朱鉛。", "宮中老兔非日浴，天使潔白宜嬋娟。", "揚鬚弭足桂樹間，桂花如霜亂後前。", "赤鴉相望窺不得，空疑兩瞳射日丹。", "東西跳梁自長久，天畢橫施亦何有。", "憑光下視罝網繁，衣褐紛紛漫回首。", "去年驚墮滁山雲，出入虛莽猶無群。", "奇毛難藏果亦得，千里今以窮歸君。", "空衢險幽不可返，食君庭除嗟亦窘。", "令予得爲此兔謀，豐草長林且遊衍。"]'),
('897074fb-f746-4915-8199-a0faa172f905','車螯二首  其一','王安石','宋','宋诗','song-poetry','','[]','車螯肉甚美，由美得烹燔。',72,'全唐诗/poet.song.31000.json','["車螯肉甚美，由美得烹燔。", "殻以無味棄，棄之能久存。", "予嘗憐其肉，柔弱甘咀吞。", "又嘗怪其殻，有功不見論。", "醉客快一噉，散投牆壁根。", "寧能爲收拾，持用訊醫門。"]'),
('e0980ec8-8de8-45bf-a375-b53efcd0b93f','車螯二首  其二','王安石','宋','宋诗','song-poetry','','[]','車螯肉之弱，恃殻保厥身。',120,'全唐诗/poet.song.31000.json','["車螯肉之弱，恃殻保厥身。", "自非身有求，不敢微啟唇。", "尚恐擉者得，泥沙常埋堙。", "往往湯火間，身盡殻空存。", "維海錯萬物，口牙且咀吞。", "爾無如彼何，可畏寧獨人。", "無爲久自苦，含匿不暴陳。", "豁然從所如，游蕩四海滣。", "清波濯其汙，白日曬其昏。", "死生或有在，豈遽得烹燔。"]'),
('6284f2ba-33c7-4c8a-bcd2-bc2c3fff57d5','與平甫同賦槐','王安石','宋','宋诗','song-poetry','','[]','冰雪泊楚岸，萬株同飄零。',48,'全唐诗/poet.song.31000.json','["冰雪泊楚岸，萬株同飄零。", "春風都城居，初見葉青青。", "歲行如車輪，蔭翳忽滿庭。", "秋子今在眼，何時動江舲。"]'),
('b2a16ba3-3fbb-4fcf-98d2-5579f5ca5eba','甘棠梨','王安石','宋','宋诗','song-poetry','','[]','甘棠詩所歌，自足誇衆果。',120,'全唐诗/poet.song.31000.json','["甘棠詩所歌，自足誇衆果。", "愛其凌秋霜，萬玉懸磊砢。", "園夫盛採摘，市賈爭包裹。", "車輸動盈箱，舟載輒連柁。", "朝分不知數，暮在知幾顆。", "但使甘有餘，何傷小而橢。", "主人捐千金，飣餖留四坐。", "柑椑與橙栗，在口亦云可。", "都城紛華地，內熱易生火。", "問客當此時，蠲煩孰如我。"]'),
('ba7dd0ec-c11b-4787-aa1c-9ba8c0541419','獨山梅花','王安石','宋','宋诗','song-poetry','','[]','獨山梅花何所似，半開半謝荆棘中。',64,'全唐诗/poet.song.31000.json','["獨山梅花何所似，半開半謝荆棘中。", "美人零落依草木，志士憔悴守蒿蓬。", "亭亭孤艷带寒日，漠漠遠香隨野風。", "移栽不得根欲老，回首上林顔色空。"]'),
('cef51536-7052-4307-b95c-35e0cc8c1ed9','同昌叔賦雁奴','王安石','宋','宋诗','song-poetry','','[]','雁雁無定棲，隨陽以南北。',120,'全唐诗/poet.song.31000.json','["雁雁無定棲，隨陽以南北。", "嗟哉此爲奴，至性能懇惻。", "人將伺其殆，奴輒告之亟。", "舉群寤而飛，機巧無所得。", "夜或以火取，奴鳴火因匿。", "頻驚莫我捕，顧謂奴不直。", "嗷嗷身百憂，泯泯衆一息。", "相隨入矰繳，豈不聽者惑。", "偷安與受紿，自古有亡國。", "君看雁奴篇，禍福甚明白。"]'),
('399ec26c-3786-4175-acf7-0934a515054a','老樹','王安石','宋','宋诗','song-poetry','','[]','去年北風吹瓦裂，牆頭老樹凍欲折。',96,'全唐诗/poet.song.31000.json','["去年北風吹瓦裂，牆頭老樹凍欲折。", "蒼葉蔽屈忽扶疏，野禽從此相與居。", "禽鳴無時不可數，雌雄各自應律呂。", "我床撥書當午眠，能驚我眠聒我語。", "古詩鳥鳴山更幽，我念不若鳴聲收。", "但憂此物一朝去，狂風還來欺老樹。"]'),
('c9c6a47e-b579-4a6f-9f92-5f1feefe72a0','賦棗','王安石','宋','宋诗','song-poetry','','[]','種桃昔所傳，種棗予所欲。',123,'全唐诗/poet.song.31000.json','["種桃昔所傳，種棗予所欲。", "在實爲美果，論材又良木。", "餘甘入鄰家，尚得饞婦逐。", "况余秋盤中，快噉取饜足。", "風包墮朱繒，日顆皺紅玉。", "贄享古已然，豳詩自宜錄。", "{糹丐}懷青齊間，萬樹蔭平陸。", "誰云食之昏，匿知乃成俗。", "廣庭觴聖壽，以此參肴蔌。", "願比赤心投，皇明儻予燭。"]'),
('b87dd8bd-a2a9-4e93-ad52-2a2a44fc8e4e','飛雁','王安石','宋','宋诗','song-poetry','','[]','雁飛冥冥時下泊，稻粱雖少江湖樂。',64,'全唐诗/poet.song.31000.json','["雁飛冥冥時下泊，稻粱雖少江湖樂。", "人生何必慕輕肥，辛苦將身到沙漠。", "漢時蘇武與張騫，萬里生還值偶然。", "丈夫許國當如此，男子辭親亦可憐。"]'),
('2c3d8b0f-1c6b-4fef-a82a-d59d812f5246','寓言九首  其一','王安石','宋','宋诗','song-poetry','','[]','詵詵古之士，出必見禮樂。',48,'全唐诗/poet.song.31000.json','["詵詵古之士，出必見禮樂。", "群游與群飲，仁義待揚搉。", "心疲歌舞荒，耳聒米鹽濁。", "所以後世賢，絕俗乃爲學。"]'),
('da698d3d-84dd-4ef6-a45f-42c0cac988fc','寓言九首  其二','王安石','宋','宋诗','song-poetry','','[]','不得君子居，而與小人游。',96,'全唐诗/poet.song.31000.json','["不得君子居，而與小人游。", "疵瑕不相摩，况乃禍釁稠。", "高語不敢出，鄙辭强顔酬。", "始云避世患，自覺日已偷。", "如傅一齊人，以萬楚人咻。", "云復學齊言，定復不可求。", "仁義多在野，欲從苦淹留。", "不悲道難行，所悲累身修。"]'),
('ca603a15-983c-4548-8416-6d9a66d7540f','寓言九首  其三','王安石','宋','宋诗','song-poetry','','[]','周公歌七月，耕稼乃王術。',48,'全唐诗/poet.song.31000.json','["周公歌七月，耕稼乃王術。", "宣王追祖宗，考牧與宮室。", "甘棠能聽訟，召伯聖人匹。", "後生論常高，於世復何實。"]'),
('3e4dbe77-2ba1-4a4d-9c1e-62e9853fedde','寓言九首  其四','王安石','宋','宋诗','song-poetry','','[]','婚喪孰不供，貸錢免爾縈。',48,'全唐诗/poet.song.31000.json','["婚喪孰不供，貸錢免爾縈。", "耕收孰不給，傾粟助之生。", "物贏我收之，物窘出使營。", "後世不務此，區區挫兼并。"]'),
('5f2690ca-3199-4b50-a186-6201b31818ac','寓言九首  其五','王安石','宋','宋诗','song-poetry','','[]','貞觀業萬世，經營豈非艱。',48,'全唐诗/poet.song.31000.json','["貞觀業萬世，經營豈非艱。", "其子一摇之，宗廟靈幾殫。", "開元始聰明，一眚奔岷山。", "功高後毀易，德薄人存難。"]'),
('37d7d1c1-6915-4a54-a0a3-5fe07a45d298','寓言九首  其六','王安石','宋','宋诗','song-poetry','','[]','言失於須臾，百世不可除。',48,'全唐诗/poet.song.31000.json','["言失於須臾，百世不可除。", "行失几席間，惡名滿八區。", "百年養不足，一日毀有餘。", "諒彼耻不仁，戒哉惟厥初。"]'),
('9d3bbf53-0ece-4b83-8e53-3e751c4d2974','寓言九首  其七','王安石','宋','宋诗','song-poetry','','[]','鐘鼓非樂本，本末猶相因。',48,'全唐诗/poet.song.31000.json','["鐘鼓非樂本，本末猶相因。", "仁聲入人深，孟子言之醇。", "如何貞觀君，從古同隋陳。", "風俗不粹美，惜哉世無臣。"]'),
('5e29e57d-3a7f-4920-aca8-ccc4ed618923','寓言九首  其八','王安石','宋','宋诗','song-poetry','','[]','遊鯨厭海濁，出戲清江湄。',48,'全唐诗/poet.song.31000.json','["遊鯨厭海濁，出戲清江湄。", "風濤助翻騰，網罟不敢窺。", "失身洲渚間，螻蟻乘其機。", "物大苦易窮，一窮無所歸。"]'),
('80c800de-b1ae-48cb-88ba-bb7cb1d87773','寓言九首  其九','王安石','宋','宋诗','song-poetry','','[]','猛虎卧草間，群鳥從噪之。',48,'全唐诗/poet.song.31000.json','["猛虎卧草間，群鳥從噪之。", "萬物忌强梁，寧獨以其私。", "虎終機械得，鳥亦彈丸隨。", "山鷄不忤物，默與鳳凰期。"]'),
('fa60b002-42df-48cf-874e-7b26302e2202','舟中讀書','王安石','宋','宋诗','song-poetry','','[]','冉冉木葉下，蕭蕭山水秋。',48,'全唐诗/poet.song.31000.json','["冉冉木葉下，蕭蕭山水秋。", "浮雲带田野，落日抱汀洲。", "歸卧無與語，出門何所求。", "未能忘感慨，聊以古人謀。"]'),
('2810bc1c-1163-4cd3-a21e-dea7250770de','和王樂道讀進士試卷','王安石','宋','宋诗','song-poetry','','[]','文章始隋唐，進取歸一律。',84,'全唐诗/poet.song.31000.json','["文章始隋唐，進取歸一律。", "安知鴻都事，竟用程人物。", "變今嗟未能，於己空自咄。", "流波亦已漫，高論常見屈。", "故令俶儻士，往往棄堙鬰。", "皋陶敘九德，固有知人術。", "聖世欲爾爲，徐觀異人出。"]'),
('f12e1339-dfb4-4600-8482-77bd6abace0c','自訟','王安石','宋','宋诗','song-poetry','','[]','孔子見南子，子路爲不怡。',96,'全唐诗/poet.song.31000.json','["孔子見南子，子路爲不怡。", "欲從公山氏，勃鬰見色辭。", "道如天之蒼，萬物不能緇。", "弟子尚不信，况余乏才資。", "明知古人仁，語默各有時。", "苟出不自慎，果爲聽者疑。", "白圭尚有磨，駟馬猶能追。", "一言成不智，雖悔欲何爲。"]'),
('2b9fa5d6-7c7f-4ef1-b6e7-6cf76fc43dc1','彼狂','王安石','宋','宋诗','song-poetry','','[]','上古杳默無人聲，日月不忒山川平。',160,'全唐诗/poet.song.31000.json','["上古杳默無人聲，日月不忒山川平。", "人與鳥獸相隨行，祖孫一死十百生。", "萬物不給乃相兵，伏羲畫法作後程。", "漁蟲獵獸寬群爭，勢不得已當經營。", "非以示世爲聰明，方分類別物有名。", "夸賢尚功列耻榮，蠱僞日巧雕元精。", "至言一出衆輒驚，上智閉匿不敢成。", "因時就俗救刖黥，惜哉彼狂以文鳴。", "强取色樂要聾盲，震蕩沈濁終無清。", "詼詭徒亂聖人氓，豈若泯默死蠶耕。"]'),
('94e043a6-84b6-4b98-9bfd-6561802ba925','衆人','王安石','宋','宋诗','song-poetry','','[]','衆人紛紛何足競，是非吾喜非吾病。',64,'全唐诗/poet.song.31000.json','["衆人紛紛何足競，是非吾喜非吾病。", "頌聲交作莽豈賢，四國流言旦猶聖。", "唯聖人能輕重人，不能銖兩爲千鈞。", "乃知輕重不在彼，要之美惡由吾身。"]'),
('b2101281-2a14-41a9-98ed-3648c9590f02','寄題郢州白雪樓','王安石','宋','宋诗','song-poetry','','[]','折楊黄華笑者多，陽春白雪和者少。',128,'全唐诗/poet.song.31000.json','["折楊黄華笑者多，陽春白雪和者少。", "知音四海無幾人，况乃區區郢中小。", "千載相傳始欲慕，一時獨唱誰能曉。", "古心以此分冥冥，俚耳至今徒擾擾。", "朱樓碧瓦何年有，榱桷連空欲驚矯。", "郢人爛漫醉浮雲，郢女參差躡飛鳥。", "丘墟餘響難再得，欄檻茲名復誰表。", "我來欲歌聲更吞，石城寒江暮雲繞。"]'),
('8005a7ff-3fcc-4df4-8359-773ce7a66847','聖俞爲狄梁公孫作詩要予同作','王安石','宋','宋诗','song-poetry','','[]','虎豹不食子，鴟梟不乘雄。',96,'全唐诗/poet.song.31000.json','["虎豹不食子，鴟梟不乘雄。", "人惡甚鳥獸，吾能與成功。", "愛有以計留，去有勢不容。", "吾謀適合意，幾亦齒奸鋒。", "時恩淪九泉，褒取異代忠。", "堂堂社稷臣，近世孰如公。", "空使苗裔孫，稱揚得詩翁。", "一讀亦使我，慨然想餘風。"]'),
('b80d68d0-7ffc-44c5-aa05-d4cb5cdb8d29','蒙亭','王安石','宋','宋诗','song-poetry','','[]','隠者委所逢，在物無不足。',144,'全唐诗/poet.song.31000.json','["隠者委所逢，在物無不足。", "山林與城市，語道歸一轂。", "詩人論巨細，此指尚局束。", "頗知區區者，自屏忍所欲。", "孰識古之人，超然遺耳目。", "豈於喧與靜，趣舍有偏獨。", "命亭今何爲，似乃畏驚俗。", "至意不標揭，小名聊自屬。", "夏風簷楹寒，冬雪窗戶燠。", "春樊亂梅柳，秋徑深松菊。", "壺觴日笑傲，裙屣相追逐。", "此樂已難言，持琴作新曲。"]'),
('e0bd4f47-543f-4550-bf84-a586f704bafb','和王樂道烘蝨','王安石','宋','宋诗','song-poetry','','[]','秋暑汗流如炙輠，敝衣濕蒸塵垢涴。',256,'全唐诗/poet.song.31000.json','["秋暑汗流如炙輠，敝衣濕蒸塵垢涴。", "施施衆蝨當此時，擇肉甘於虎狼餓。", "咀嚙侵膚未云已，爬搔次骨終無那。", "時時對客輒自捫，千百所除纔幾箇。", "皮毛得氣强復活，爪甲流丹真暫破。", "未能湯沐取一空，且以火攻令少挫。", "踞爐熾炭已不暇，對竈張衣誠未過。", "飄零乍若蛾赴燈，驚擾端如蟻旋磨。", "欲毆百惡死焦灼，肯貸一凶生棄播。", "已觀細黠無所容，未放老奸終不墮。", "然臍郿塢患溢世，焚寶鹿臺身易貨。", "冢中燎入化秦屍，池上焮隨遷莽坐。", "彼皆勢極就煙埃，况汝命輕侔涕唾。", "逃藏壞絮尚欲索，埋沒死灰誰復課。", "熏心得禍爾莫悔，爛額收功吾可賀。", "猶殘衆蟣恨未除，自計寧能久安卧。"]'),
('e91f223f-9cc2-49a7-8609-d35da6833255','和聖俞農具詩十五首 田廬','王安石','宋','宋诗','song-poetry','','[]','田父結田廬，聊容一身息。',48,'全唐诗/poet.song.31000.json','["田父結田廬，聊容一身息。", "呼兒取茅竹，不借鄉人力。", "起行廬旁朝，歸卧廬下夕。", "悠悠各有願，勿笑田廬窄。"]'),
('b61993ad-f834-4e7e-a9d6-d15cded569e8','和聖俞農具詩十五首 樵斧','王安石','宋','宋诗','song-poetry','','[]','百金聚一冶，所賦以所遭。',48,'全唐诗/poet.song.31000.json','["百金聚一冶，所賦以所遭。", "此豈異莫耶，奈何獨當樵。", "朝出在人手，暮歸在人腰。", "用捨各有時，此日兩無邀。"]'),
('68496f11-088e-496b-aed5-6487c251cdce','和聖俞農具詩十五首 耕牛','王安石','宋','宋诗','song-poetry','','[]','朝耕草茫茫，暮耕水潏潏。',48,'全唐诗/poet.song.31000.json','["朝耕草茫茫，暮耕水潏潏。", "朝耕及露下，暮耕連月出。", "自無一毛利，主有千箱實。", "睆彼天上星，空名豈余匹。"]'),
('b2b9a08a-2d1f-4343-953b-07533de3a3d4','和聖俞農具詩十五首 水車','王安石','宋','宋诗','song-poetry','','[]','取車當要津，膏潤及遠野。',48,'全唐诗/poet.song.31000.json','["取車當要津，膏潤及遠野。", "與天常斡旋，如雨自潀瀉。", "置心亦何有，在物偶相假。", "此理乃可言，安得圓機者。"]'),
('ee98374d-0137-4859-9040-b50f4d7a0afa','和聖俞農具詩十五首 牧笛','王安石','宋','宋诗','song-poetry','','[]','綠草無端倪，牛羊在平地。',48,'全唐诗/poet.song.31000.json','["綠草無端倪，牛羊在平地。", "芊綿杳靄間，落日一橫吹。", "超遥送逸響，澶漫寫真意。", "豈比賣餳人，吹簫販童稚。"]'),
('12f176ea-2476-4a52-a83f-2a2247def7ce','和聖俞農具詩十五首 颺扇','王安石','宋','宋诗','song-poetry','','[]','精良止如留，疏惡去如擯。',48,'全唐诗/poet.song.31000.json','["精良止如留，疏惡去如擯。", "如擯非爾憎，如留豈吾吝。", "無心以擇物，誰喜亦誰慍。", "翁乎勤簸颺，可使糠粃盡。"]'),
('48c0566a-e511-4941-be17-d529a115a764','和聖俞農具詩十五首 田漏','王安石','宋','宋诗','song-poetry','','[]','占星昏曉中，寒暑已不疑。',48,'全唐诗/poet.song.31000.json','["占星昏曉中，寒暑已不疑。", "田家更置漏，寸晷亦欲知。", "汗與水俱滴，身隨陰屢移。", "誰當哀此勞，往往奪其時。"]'),
('0966e0a9-1ca4-41be-8065-6a0987247123','和聖俞農具詩十五首 牛衣','王安石','宋','宋诗','song-poetry','','[]','百獸冬自暖，獨牛非氄毛。',48,'全唐诗/poet.song.31000.json','["百獸冬自暖，獨牛非氄毛。", "無衣與卒歲，坐恐得空牢。", "主人覆護恩，豈啻一綈袍。", "問爾何以報，離離滿東皋。"]'),
('0177c482-aca2-4280-94c4-ec62064fa899','和聖俞農具詩十五首 耬種','王安石','宋','宋诗','song-poetry','','[]','富家種論石，貧家種論斗。',48,'全唐诗/poet.song.31000.json','["富家種論石，貧家種論斗。", "富貧同一時，傾瀉應心手。", "行看萬壟空，坐使千箱有。", "利物博如此，何慚在牛後。"]'),
('a907cfd7-5b55-4e70-abc4-f86f3560c10e','和聖俞農具詩十五首 耒耜','王安石','宋','宋诗','song-poetry','','[]','耒耜見於易，聖人取風雷。',48,'全唐诗/poet.song.31000.json','["耒耜見於易，聖人取風雷。", "不有仁智兼，利端誰與開。", "神農后稷死，般爾相尋來。", "山林盡百巧，揉斲無良材。"]'),
('6c5c7666-5d8e-4cad-984a-d984d1e604b9','和聖俞農具詩十五首 錢鎛','王安石','宋','宋诗','song-poetry','','[]','於易見耒耜，於詩聞錢鎛。',48,'全唐诗/poet.song.31000.json','["於易見耒耜，於詩聞錢鎛。", "百工聖人爲，此最功不薄。", "欲收禾黍善，先去蒿萊惡。", "願同欹器悟，更使臣工作。"]'),
('08cb170a-ba36-4110-a6f3-46dc7e39ab81','和聖俞農具詩十五首 耰耡','王安石','宋','宋诗','song-poetry','','[]','鍛金以爲曲，揉木以爲直。',48,'全唐诗/poet.song.31000.json','["鍛金以爲曲，揉木以爲直。", "直曲相後先，心手始兩得。", "秦人望屋食，以此當金革。", "君勿易耰耡，耰耡勝鋒鏑。"]'),
('2d130972-0ae1-4358-b916-e7f765d25cd5','和聖俞農具詩十五首 襏襫','王安石','宋','宋诗','song-poetry','','[]','采采霜露下，披披煙雨中。',48,'全唐诗/poet.song.31000.json','["采采霜露下，披披煙雨中。", "蒲茅以爲友，短褐相與同。", "勿妒市門人，綺紈被奴僮。", "當慚邊城戍，擐甲徂春冬。"]'),
('a366fffe-1777-4bea-bd3c-947b8ba7d819','和聖俞農具詩十五首 臺笠','王安石','宋','宋诗','song-poetry','','[]','耕有春雨濡，耘有秋陽暴。',48,'全唐诗/poet.song.31000.json','["耕有春雨濡，耘有秋陽暴。", "二物應時須，九州同我服。", "欲爲生少慕，得此自云足。", "君思周伯陽，所願豈華轂。"]'),
('ab6f3ba8-d2b1-41ba-b3de-8ffd971a2d02','和聖俞農具詩十五首 耘鼓','王安石','宋','宋诗','song-poetry','','[]','逢逢戲場聲，壤壤戰時伍。',48,'全唐诗/poet.song.31000.json','["逢逢戲場聲，壤壤戰時伍。", "日落未云休，田家亦良苦。", "問兒今壟上，聽此何莽鹵。", "昨日應官繇，州前看歌舞。"]'),
('aaaea579-f6ed-4c71-912c-1d9879476169','次韵酬微之贈池紙并詩','王安石','宋','宋诗','song-poetry','','[]','微之出守秋浦時，椎冰看擣萬穀皮。',208,'全唐诗/poet.song.31000.json','["微之出守秋浦時，椎冰看擣萬穀皮。", "波工龜手咤今樣，魚網肯數荆州池。", "霜紈奪色賈不售，虹玉喪氣山無輝。", "方船穩載獻天子，善價徐取供吾私。", "十年零落尚百一，持以贈我隨清詩。", "君寧久寄金穀地，方執賜筆磨坳螭。", "當留此物朝上國，日侍帝側書新儀。", "不然名山副史本，褒拔元凱誅窮奇。", "咨予文章非世用，畫鏤空爾靡冰脂。", "揮毫才足記姓字，竊學又恥從師宜。", "匆匆點汙亦何忍，嘉貺但覺難爲辭。", "篇終有意責趙璧，窮國恐誤連城歸。", "傾囊倒篋聊一報，安敢坐以秦爲雌。"]'),
('52b5c98f-478e-458d-a05c-7332b3748401','酬沖卿月晦夜有感','王安石','宋','宋诗','song-poetry','','[]','夜雲不見天，况乃星與月。',96,'全唐诗/poet.song.31000.json','["夜雲不見天，况乃星與月。", "蕭蕭暗塵走，坎坎寒更發。", "樓歌客尚飲，酩酊不畏雪。", "巷哭復有人，鄰風送幽咽。", "紛然各所遇，悲喜孰優劣。", "君方感莊周，浩蕩擺羈絏。", "歸來亦置酒，玉指調絃撥。", "獨我坐無爲，青燈對明滅。"]'),
('eef8250f-114a-4731-b313-0310e0b0f6af','送子思兄參惠州軍','王安石','宋','宋诗','song-poetry','','[]','沄沄曲江水，天借九秋色。',288,'全唐诗/poet.song.31000.json','["沄沄曲江水，天借九秋色。", "樓臺飛半空，秀氣盤韶石。", "載酒填里閭，吹花換朝夕。", "笙簫震河漢，錦繡爛冠幘。", "地靈瘴癘絕，人物傾南極。", "先朝有名臣，卧理訟隨息。", "稍稍延諸生，談笑與賓客。", "子來適妙年，謁入交履舄。", "寂寥九齡後，此獨望一國。", "虞翻禮丁覽，韓愈俟趙德。", "孤岸鎮頹波，俗流未易識。", "我方文葆中，旋逐旌旗蹟。", "去思今豈忘，耳目熟遺迹。", "吏含殷勤言，俛仰問乖隔。", "當時府中兒，侵尋鬢邊白。", "下帷雖著書，不捄寒饑迫。", "謂宜門闌士，宦路久烜赫。", "奈何猶差池，更捧丞掾檄。", "驥摧千里蹄，鵬墮九霄翮。", "人生無巧愚，天運有通塞。", "試觀馳騁人，意氣宇宙窄。", "榮華去路塵，謗辱與山積。", "優游祿仕間，較計誰失得。", "送君强成歌，陟岵翻感激。"]'),
('6a309484-47db-4617-93a8-51a4cdd13657','送董伯懿歸吉州','王安石','宋','宋诗','song-poetry','','[]','我來以喪歸，君至因謫徙。',216,'全唐诗/poet.song.31000.json','["我來以喪歸，君至因謫徙。", "蒼黄憂患中，邂逅遇於此。", "去年服初除，聽赦相助喜。", "看君數歸月，但屈兩三指。", "茫然冬更秋，一笑非願始。", "籃輿楊柳下，明月芙蕖水。", "僮饑屢闚門，客罷方隠几。", "是非評衆詩，成敗斷前史。", "時時對奕石，漫浪爭生死。", "送迎皆幅巾，設食但陳米。", "亦曾戲篇章，揮翰疾蒿矢。", "君豪才有餘，我老憊先止。", "東城景陽陌，南望長干紫。", "欲斸三畝蔬，於焉寄殘齒。", "經過許後日，唱和猶在耳。", "新恩忽捨我，欣悵生彼己。", "江湖北風帆，捩柂即千里。", "相逢知何時，莫惜縑與紙。"]'),
('a8d85999-b4c3-4e60-8b9f-e39f9836d529','八月十九日試院夢沖卿','王安石','宋','宋诗','song-poetry','','[]','空庭得秋長漫漫，寒露入幕愁衣單。',64,'全唐诗/poet.song.31000.json','["空庭得秋長漫漫，寒露入幕愁衣單。", "喧喧人語已成市，白日未到扶桑間。", "永懷所好却成夢，玉色彷彿開心顔。", "逆知後應不復隔，談笑明月相與閒。"]'),
('28fff585-dddc-4305-9530-89687980e4fc','平甫歸飲','王安石','宋','宋诗','song-poetry','','[]','無田士相弔，亦以廢燕樂。',120,'全唐诗/poet.song.31000.json','["無田士相弔，亦以廢燕樂。", "我官雖在朝，得飲乃不數。", "詩書向牆戶，賓至無杯杓。", "空取上古言，酬之等糟粕。", "有如揚子雲，歲晚天祿閣。", "但無載酒人，識字真未博。", "叔兮歸自東，一笑堂上酌。", "緒餘不及客，兒女聊相酢。", "高談非世歡，自慰亦不惡。", "寄言繁華子，此趣由來各。"]'),
('63174a8b-6798-48cd-b374-a6088bc581ae','答陳正叔','王安石','宋','宋诗','song-poetry','','[]','天馬志萬里，駕鹽不如閑。',96,'全唐诗/poet.song.31000.json','["天馬志萬里，駕鹽不如閑。", "壯士困局束，不如棄之完。", "利行有阨轍，勢涉無恬瀾。", "明明千年羞，促促一日歡。", "孰肯避此世，引身取平寬。", "超然子有意，爲我歌考槃。", "予方慕孔氏，委吏久盤桓。", "得失未云殊，聊各趨所安。"]'),
('e33fa7a5-8bef-40e6-8263-e40eca54a283','過食新城藕','王安石','宋','宋诗','song-poetry','','[]','他年過食新城藕，枕藉船中載親友。',96,'全唐诗/poet.song.31000.json','["他年過食新城藕，枕藉船中載親友。", "今年却到經行處，獨坐昏煙對舞柳。", "甘酸向口無所適，牢落盤餐與樽酒。", "冰房玉節漫自好，欲御還休涕垂手。", "曾參宦學居常近，陽城離別初不久。", "人間此願兩未能，西風落日空迴首。"]'),
('6f6f247c-9d46-48b2-8030-a51edffbffd9','明州錢君倚衆樂亭','王安石','宋','宋诗','song-poetry','','[]','使君幕府開東部，名高海曲人知慕。',144,'全唐诗/poet.song.31000.json','["使君幕府開東部，名高海曲人知慕。", "艤船談笑政即成，洗滌山川作嘉趣。", "平泉浩蕩銀河注，想見明星弄機杼。", "載沙築成天上路，投虹爲橋取孤嶼。", "掃除荆棘水中央，碧瓦朱甍隨指顧。", "春風滿城金版舫，來看置酒新亭上。", "百女吹笙綵鳳悲，一夫伐鼓靈鼉壯。", "安期羨門相與遊，方丈蓬萊不更求。", "酒酣忽跨鯨魚去，陳迹空令此地留。"]'),
('2d204793-3191-4b56-b282-c625873f3437','愛日','王安石','宋','宋诗','song-poetry','','[]','雁生陰沙春，冬息陽海澨。',120,'全唐诗/poet.song.31000.json','["雁生陰沙春，冬息陽海澨。", "冥冥取南北，豈以食爲累。", "咨予愁病軀，朴鄙人所戲。", "無才治時難，量力當自棄。", "豈知塞上霜，飄然亦何事。", "高堂已白髮，愛日負明義。", "悲風吹平原，秣馬聊一愒。", "含懷孰與語，仰屋思嘆喟。", "孟母知身從，萊妻恥人制。", "一肉儻易謀，萬鍾非得計。"]'),
('4b693c5b-b84e-4907-866a-7e239b4c634d','答裴煜道中見寄','王安石','宋','宋诗','song-poetry','','[]','君遊苦數歸苦晚，一驛險有千里遠。',64,'全唐诗/poet.song.31000.json','["君遊苦數歸苦晚，一驛險有千里遠。", "知君陟降旦暮間，馬力不勁厭長坂。", "雨脚墜地花枝低，風頭入溪蒲葉偃。", "此處登臨不奈愁，瓊樹森森遮疊巘。"]'),
('03b0604e-e3a9-40be-9730-e33adaa009cd','餘寒','王安石','宋','宋诗','song-poetry','','[]','餘寒駕春風，入我征衣裳。',120,'全唐诗/poet.song.31000.json','["餘寒駕春風，入我征衣裳。", "捫鬢只得凍，蔽面尚疑創。", "士耳恐猶墜，馬毛欲吹僵。", "牢持有失箸，疾飲無留湯。", "曈曈扶桑日，出有萬里光。", "可憐當此時，不濕地上霜。", "冥冥鴻雁飛，北望去成行。", "誰言有百鳥，此鳥知陰陽。", "豈時有必至，前識聖所臧。", "把酒謝高翰，我知思故鄉。"]'),
('6daad5c6-3911-43c9-b50c-79ce5bfbcf22','孤城','王安石','宋','宋诗','song-poetry','','[]','孤城回望距幾何，記得好處常經過。',64,'全唐诗/poet.song.31000.json','["孤城回望距幾何，記得好處常經過。", "最思東山煙樹色，更憶南湖秋水波。", "百年顛倒如夢寐，萬事乖隔徒悲歌。", "應須飲酒不復道，今夜江頭明月多。"]'),
('e035ae1a-776b-4cd7-9c12-6c147e76d261','和微之藥名勸酒','王安石','宋','宋诗','song-poetry','','[]','赤車使者錦帳郎，從客珂馬留閑坊。',120,'全唐诗/poet.song.31000.json','["赤車使者錦帳郎，從客珂馬留閑坊。", "紫芝眉宇傾一坐，笑語但聞雞舌香。", "藥名勸酒詩實好，陟釐爲我書數行。", "真珠的皪鳴槽床，金罌琥珀正可嘗。", "史君子細看流光，莫惜覓醉衣淋浪。", "獨醒至死誠可傷，歡華易盡悲酸早，人間沒藥能醫老。", "寄言歌管衆少年，趁取烏頭未白前。"]'),
('6136570f-67f2-486c-bc3d-48e3dd4aec66','客至當飲酒二首  其一','王安石','宋','宋诗','song-poetry','','[]','結屋在牆陰，閉門讀詩書。',72,'全唐诗/poet.song.31000.json','["結屋在牆陰，閉門讀詩書。", "懷我平生友，山水異秦吳。", "杖藜出柴荆，豈無馬與車。", "窮通適異趣，談笑不相愉。", "豈復求古人，浩蕩與之俱。", "客至當飲酒，日月無根株。"]'),
('0854d495-9bf0-4680-88df-c40e1ddc6214','客至當飲酒二首  其二','王安石','宋','宋诗','song-poetry','','[]','天提兩輪光，環我屋角走。',72,'全唐诗/poet.song.31000.json','["天提兩輪光，環我屋角走。", "自從紅顔時，照我至白首。", "纍纍地上土，往往平生友。", "少年所種樹，磥砢行復朽。", "古人有真意，獨在無好醜。", "冥冥誰與論，客至當飲酒。"]'),
('51addcdc-3726-4f94-8f2a-f8a48b6ac3ad','乙未冬婦子病至春不已','王安石','宋','宋诗','song-poetry','','[]','天旋無窮走日月，青髮能禁幾回首。',64,'全唐诗/poet.song.31000.json','["天旋無窮走日月，青髮能禁幾回首。", "兒呻婦嘆冬復春，强欲笑歌難發口。", "黄卷幽尋非貴嗜，藜床穩卧雖貧有。", "二物長乖亦可憐，一生所得猶多苟。"]'),
('bfff53f0-e2b4-4aa5-985d-d08c3954f8c5','强起','王安石','宋','宋诗','song-poetry','','[]','寒堂耿不寐，轆轆聞車聲。',72,'全唐诗/poet.song.31000.json','["寒堂耿不寐，轆轆聞車聲。", "不知誰家兒，先我霜上行。", "歎息夜未央，遽呼置前楹。", "推枕欲强起，問知星正明。", "昧旦聖所勉，齊詩有雞鳴。", "嗟予以竊食，更覺負平生。"]'),
('a8d9bbd7-2640-4413-a52a-6be07874bd3d','飲裴侯家','王安石','宋','宋诗','song-poetry','','[]','裴侯飲我日向中，四坐賓客顔皆紅。',144,'全唐诗/poet.song.31000.json','["裴侯飲我日向中，四坐賓客顔皆紅。", "掃除高館邀我入，自出糶麥憐民窮。", "天邊眼力破萬里，桑麻冥冥山四起。", "野心探尋殊未已，更欲湔衣北城水。", "忽見碧樹櫻桃懸，下馬恣食不論錢。", "赤星磊落入我眼，恐是半醉遊青天。", "裴侯方坐塵沙裏，役身救物當如此。", "我曹偶脫簿領閒，何忍愛惜一日閑。", "且歸拂席飽眠睡，明日更看滁南山。"]'),
('2afbfeff-9591-4bb7-9836-3679df6fb6e1','送謝師宰赴任楚州  其一','王安石','宋','宋诗','song-poetry','','[]','珠玉不自貴，故爲人所憐。',96,'全唐诗/poet.song.31000.json','["珠玉不自貴，故爲人所憐。", "賢愚亦如此，好惡有自然。", "聞子欲東南，使我抱幽悁。", "炎風沙土中，甘與子留連。", "大梁非無客，跪起廢食眠。", "相看獨不厭，以此知子賢。", "衰氣已難强，壯心方少年。", "才高豈易得，勗子在雕鎸。"]'),
('99ca4bb0-339e-47b1-87f5-17d5f6e2fb31','送謝師宰赴任楚州  其二','王安石','宋','宋诗','song-poetry','','[]','崑崙一支流向東，七月八月船如風。',64,'全唐诗/poet.song.31000.json','["崑崙一支流向東，七月八月船如風。", "愛君少壯此行樂，恨我留連成老翁。", "神頭兩岸水無窮，伏檻荷花滿地紅。", "當時不得君携手，今日山川在眼中。"]'),
('9e25f063-51c7-4b54-be30-c9bea352e0d0','次韵遊山門寺望文脊山','王安石','宋','宋诗','song-poetry','','[]','宣城百山間，文脊尤奇峰。',96,'全唐诗/poet.song.31000.json','["宣城百山間，文脊尤奇峰。", "拔出飛鳥上，圖畫難爲容。", "聞昔有幽人，捫蘿追赤松。", "遺形此古室，孤坐鹿裘重。", "人去邈不反，洞壑空藏龍。", "側行蒼崖煙，俯仰求靈蹤。", "遊者如可得，甘棄萬戶封。", "安能久塵土，傾倒相迎逢。"]'),
('9c05dc8f-9527-4806-9d9f-d1cd19029daf','車螯','王安石','宋','宋诗','song-poetry','','[]','海於天地間，萬物無不容。',108,'全唐诗/poet.song.31000.json','["海於天地間，萬物無不容。", "車螯亦其一，埋沒沙水中。", "獨取常苦易，衛生乏明聰。", "機緘誰使然，含蓄略相同。", "坐欲腸胃得，要令湯火攻。", "置之先生盤，噉客爲一空。", "蠻夏怪四坐，不論殻之功。", "狼籍堆左右，棄置任兒童。", "何當强收拾，持問大醫工。"]'),
('16874d98-9d30-4c71-bb17-021011f91055','疥','王安石','宋','宋诗','song-poetry','','[]','浮陽燥欲出，陰濕與之戰。',72,'全唐诗/poet.song.31000.json','["浮陽燥欲出，陰濕與之戰。", "燥濕相留連，蟲出乃投間。", "搔膚血至股，解衣燎鑪炭。", "方其愜心時，更自無可患。", "呼醫急治之，莫惜千金散。", "有樂即有苦，愜心非所願。"]'),
('61b08d86-5d72-4374-9cb2-db3f5a4a8f80','和平甫舟中望九華山二首  其一','王安石','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u4e5d\u534e\u5c71"]','楚越千萬山，雄奇此山兼。',288,'全唐诗/poet.song.31000.json','["楚越千萬山，雄奇此山兼。", "盤根雖巨壯，其末乃脩纖。", "去縣尚百里，側身勇前瞻。", "蕭條煙嵐上，縹緲浮青尖。", "徐行稍復逼，所矚亦已添。", "精神去亹亹，氣象來漸漸。", "卸席取近岸，移船傍蒼蒹。", "窺觀坐窮晡，未覺晷刻淹。", "江空萬物息，四面波瀾恬。", "峨然九女鬟，爭出一鏡匳。", "卧送秋月沒，起看朝陽暹。", "遊氛蕩無餘，瑣細得盡覘。", "陵空翠纛直，照影寒鋩銛。", "冢木立紺髮，崖林張紫髯。", "變態生倏忽，雖神詎能占。", "當留老吾身，少駐誰云饜。", "惜哉秦漢君，黄屋上衡灊。", "等之事嬉遊，捨此何其廉。", "我疑二后荒，神物久已厭。", "埋藏在雲霧，不欲登昏憸。", "又疑避褒封，蔽匿以爲謙。", "或是古史書，脫落簡與籤。", "當時備巡遊，今不在緗縑。", "終南秦之望，泰山魯所詹。"]'),
('ac29d945-a0b6-48ac-9de7-0b4686e96374','和平甫舟中望九華山二首  其二','王安石','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','誰謂九華遠，吾身未嘗詹。',288,'全唐诗/poet.song.31000.json','["誰謂九華遠，吾身未嘗詹。", "唱篇每起予，予口安能箝。", "憶在秋浦北，空江上新蟾。", "光潔寫一鏡，迴環兩堤奩。", "露坐引衣襋，風行欹帽檐。", "維舟當此時，巨細得盡瞻。", "試嘗論大略，次乃述微纖。", "此山廣以深，包畜萬物兼。", "噓雲吐霧雨，生育靡不漸。", "巍然如九皇，德澤四海沾。", "此山相後先，各出群峰尖。", "毅然如九官，羅立在堂廉。", "挺身百辟上，附麗無奸憸。", "此山高且寒，五月不覺炎。", "草樹萋已綠，冰霜尚涵淹。", "頹然如九老，白髮連蒼髯。", "此山當無雲，秀色鬰以添。", "姹然如九女，靚飾出重簾。", "珮環與巾裙，紺玉青紈縑。", "遠之妍西施，近或醜無鹽。", "變態不可窮，詩者徒呫呫。", "我初勇一往，役世難安恬。", "浪荒不走職，民瘼當誰砭。", "乖離今數旬，夢想欲窺覘。"]'),
('4b09d285-555b-4c79-883f-573172fa3c50','和中甫兄春日有感','王安石','宋','宋诗','song-poetry','','[]','雪釋沙輕馬蹄疾，北城可遊今暇日。',160,'全唐诗/poet.song.31000.json','["雪釋沙輕馬蹄疾，北城可遊今暇日。", "濺濺溪谷水亂流，漠漠郊原草爭出。", "嬌梅過雨吹爛熳，幽鳥迎陽語啾唧。", "分香欲滿錦樹園，剪綵休開寶刀室。", "胡爲我輩坐自苦，不念茲時去如失。", "飽聞高徑動車輪，甘卧空堂守經帙。", "淮蝗蔽天農久餓，越卒圍城盜少逸。", "至尊深拱罷簫韶，元老相看進刀筆。", "春風生物尚有意，壯士憂民豈無術。", "不成歡醉但悲歌，回首功名古難必。"]'),
('b097ef09-c4ee-4a9a-9af5-8411e0ea19d2','信陵坊有籠山樂官','王安石','宋','宋诗','song-poetry','','[]','萬里山林姿，羽毛何璀璀。',48,'全唐诗/poet.song.31000.json','["萬里山林姿，羽毛何璀璀。", "鳴聲應律呂，唯有知者愛。", "都門市井兒，誰翫汝文采。", "應須鎖樊籠，勿受丸矰害。"]'),
('97acc1db-e710-4e2e-9b75-9a6debeaa281','收鹽','王安石','宋','宋诗','song-poetry','','[]','州家飛符來比櫛，海中收鹽今復密。',96,'全唐诗/poet.song.31000.json','["州家飛符來比櫛，海中收鹽今復密。", "窮囚破屋正嗟欷，吏兵操舟去復出。", "海中諸島古不毛，島夷爲生今獨勞。", "不煎海水餓死耳，誰肯坐守無亡逃。", "爾來賊盜往往有，劫殺賈客沈其艘。", "一民之生重天下，君子忍與爭秋毫。"]'),
('fbaaaae7-8d38-461a-ae0f-e011377f4b09','省兵','王安石','宋','宋诗','song-poetry','','[]','有客語省兵，兵省非所先。',168,'全唐诗/poet.song.31000.json','["有客語省兵，兵省非所先。", "方今將不擇，獨以兵乘邊。", "前攻已破散，後距方完堅。", "以衆亢彼寡，雖危猶幸全。", "將既非其才，議又不得專。", "兵少敗孰繼，胡來飲秦川。", "萬一雖不爾，省兵當何緣。", "驕惰習已久，去歸豈能田。", "不田亦不桑，衣食猶兵然。", "省兵豈無時，施置有後前。", "王功所由起，古有七月篇。", "百官勤儉慈，勞者已息肩。", "游民慕草野，歲熟不在天。", "擇將付以職，省兵果有年。"]'),
('b0c2d740-b527-4d9d-afbe-20ee98398ad5','發廩','王安石','宋','宋诗','song-poetry','','[]','先王有經制，頒賫上所行。',168,'全唐诗/poet.song.31000.json','["先王有經制，頒賫上所行。", "後世不復古，貧窮主兼并。", "非民獨如此，爲國頼以成。", "築臺尊寡婦，入粟至公卿。", "我嘗不忍此，願見井地平。", "大意苦未就，小官苟營營。", "三年佐荒州，市有棄餓嬰。", "駕言發富藏，云以救鰥惸。", "崎嶇山谷間，百室無一盈。", "鄉豪已云然，罷弱安可生。", "茲地昔豐實，土沃人良耕。", "他州或呰窳，貧富不難評。", "豳詩出周公，根本詎宜輕。", "願書七月篇，一寤上聰明。"]'),
('e9b2edad-6c56-45a3-8b11-1494a2a8cabb','感事','王安石','宋','宋诗','song-poetry','','[]','賤子昔在野，心哀此黔首。',180,'全唐诗/poet.song.31000.json','["賤子昔在野，心哀此黔首。", "豐年不飽食，水旱尚何有。", "雖無剽盜起，萬一且不久。", "特愁吏之爲，十室災八九。", "原田敗粟麥，欲訴嗟無賕。", "間關幸見省，笞扑隨其後。", "況是交冬春，老弱就僵仆。", "州家閉倉庾，縣吏鞭租負。", "鄉鄰銖兩徵，坐逮空南畝。", "取貲官一毫，奸桀已云富。", "彼昏方怡然，自謂民父母。", "朅來佐荒郡，懔懔常慚疚。", "昔之心所哀，今也執其咎。", "乘田聖所勉，况乃余之陋。", "內訟敢不勤，同憂在僚友。"]'),
('5ece3f62-311d-4a59-9a03-01500e0fee59','美玉','王安石','宋','宋诗','song-poetry','','[]','美玉小瑕疵，國工猶珍之。',48,'全唐诗/poet.song.31000.json','["美玉小瑕疵，國工猶珍之。", "大賢小玷缺，良交豈其絕。", "小缺可以補，小瑕可以磨。", "不補亦不磨，人爲奈爾何。"]'),
('9ae8aea3-65d9-4ac7-b782-2bf11a4124a4','寄曾子固','王安石','宋','宋诗','song-poetry','','[]','吾少莫與合，愛我君爲最。',288,'全唐诗/poet.song.31000.json','["吾少莫與合，愛我君爲最。", "君名高山嶽，嵑𡾹嵩與泰。", "低心收憃友，似不讓塵𡏖。", "又如滄江水，不逆溝畎澮。", "君身揭日月，遇輒破氛靄。", "我材特窮空，無用補倉廥。", "謂宜從君久，垢污得洮汰。", "人生不可必，所願每顛沛。", "乖離五年餘，牢落千里外。", "投身落俗穽，薄宦自鉗釱。", "平居每自守，高論從誰丐。", "摇摇西南心，夢想與君會。", "思君挾奇璞，願售無良儈。", "窮閻抱幽憂，凶禍費禳禬。", "州窮吉士少，誰可婿諸妹。", "仍聞病連月，醫藥誰可頼。", "家貧奉養狹，誰與通貨貝。", "詩人刺曹公，賢者荷戈祋。", "奈何遭平時，德澤盛汪濊。", "鸞鳳鳴且下，萬羽來翽翽。", "呦呦林間鹿，爭出噬苹藾。", "乃令高世士，動輒遭狼狽。", "人事既難了，天理尤茫昧。", "聖賢多如此，自古云無奈。"]'),
('29438f54-e82b-4ad6-a73f-acccd570788d','同杜史君飲城南','王安石','宋','宋诗','song-poetry','','[]','山公遊何處，白馬鳴翩翩。',96,'全唐诗/poet.song.31000.json','["山公遊何處，白馬鳴翩翩。", "檀欒十畝碧，五月浮寒烟。", "留客聽其間，風吹江海縣。", "出樽不見日，竹外空青天。", "焚蠟助月出，酒光發金船。", "狂客惜不去，醉翁舞回旋。", "何必吹簫人，玉枝自嬋娟。", "歸路借紅燭，雨星低馬前。"]'),
('f3304f82-779e-4538-885c-0696e47a904c','有感','王安石','宋','宋诗','song-poetry','','[]','憶昔與胡子，戲娛西城幽。',168,'全唐诗/poet.song.31000.json','["憶昔與胡子，戲娛西城幽。", "放斥僕與馬，獨身步田疇。", "牛豎歌我旁，聽之爲久留。", "一接田父語，嘆之勝王侯。", "追逐恨不恣，暮歸輒懷愁。", "顧常輕千乘，只願足一丘。", "子時怪我少，好此寂寞遊。", "笙簧不入耳，又不甘醪羞。", "那知抱孤傷，罷頓不能遒。", "世味已鮮少，但餘野心稠。", "乖離今十年，班髮滿我頭。", "昔興亦略盡，食眠常百憂。", "每逢佳山水，欲往輒復休。", "方壯遂如此，况乃高春秋。"]'),
('205f9245-a26a-4306-8174-2c9fa5a4413f','送孫叔康赴御史府','王安石','宋','宋诗','song-poetry','','[]','古人喜經綸，萬事慚强聒。',120,'全唐诗/poet.song.31000.json','["古人喜經綸，萬事慚强聒。", "時來上青冥，俯仰但一節。", "危言回丘山，聲利盡毫末。", "由來治亂體，宿昔心已達。", "肯隨俗好惡，議論輕自决。", "遺風何寥寥，夢寐待豪傑。", "天書下東南，趣召赴嚴闕。", "長材晦朝倫，高行隠家闥。", "新除酬問望，宿藴行施設。", "念吾非忘形，此理未易說。"]'),
('dd8ca359-3f4c-4819-aca7-dca1744eae73','別馬秘丞','王安石','宋','宋诗','song-poetry','','[]','伯夷惡一世，季也皆鄉人。',96,'全唐诗/poet.song.31000.json','["伯夷惡一世，季也皆鄉人。", "吾嘗論夫子，有似季之倫。", "人情路萬殊，近世頗荆榛。", "唯君遊其間，坦坦得所循。", "意君誠愷悌，慕向從宿昔。", "奈何初相歡，鷁首已云北。", "莓莓郊原青，漠漠風雨黑。", "冠蓋滿津亭，君今去何適。"]'),
('1961d14c-6540-48a8-b8be-33998bfb0aa8','到郡與同官飲','王安石','宋','宋诗','song-poetry','','[]','瀉碧沄沄橫带郭，浮蒼靄靄遥連閣。',64,'全唐诗/poet.song.31000.json','["瀉碧沄沄橫带郭，浮蒼靄靄遥連閣。", "草木猶疑夏鬰葱，風雲已見秋蕭索。", "荒歌野舞同醉醒，水果山肴互酬酢。", "自嫌多病少歡顔，獨負嘉賓此時樂。"]'),
('b3bf52d5-6dca-45d2-95c2-c5c3bf710bf9','自舒州追送朱氏女弟憩獨山館宿木瘤僧舍明日度長安嶺至皖口','王安石','宋','宋诗','song-poetry','','[]','晨霜踐河梁，落日憩亭皋。',120,'全唐诗/poet.song.31000.json','["晨霜踐河梁，落日憩亭皋。", "念彼千里行，惻惻我心勞。", "攬轡上層岡，下臨百仞濠。", "寒流咽欲絕，魚鼈久已逃。", "暮行苦邅迴，細路隠蓬蒿。", "驚麏出馬前，鳥駭亡其曹。", "投僧避夜雨，古檠昏無膏。", "山木鳴四壁，疑身在波濤。", "平明長安嶺，飛雪忽滿袍。", "天低浮雲深，更覺所向高。"]'),
('c1985477-ea7d-4e3b-b264-7175939f6858','招同官遊東園','王安石','宋','宋诗','song-poetry','','[]','青青石上蘗，霜至亦已凋。',72,'全唐诗/poet.song.31000.json','["青青石上蘗，霜至亦已凋。", "冉冉水中蒲，爾生信無聊。", "感此歲云晚，欲歡念誰邀。", "嘉我二三子，爲回東城鑣。", "幽菊尚可泛，取魚繫榆條。", "毋爲百年憂，一日以逍遥。"]'),
('d87b52ea-b218-43ea-950d-3a38181e9cc6','九日隨家人遊東山遂遊東園','王安石','宋','宋诗','song-poetry','','[]','暑往詎幾時，凉歸亦云暫。',48,'全唐诗/poet.song.31000.json','["暑往詎幾時，凉歸亦云暫。", "相隨東山樂，及此身無憾。", "聊回清池柂，更伏荒城檻。", "采采黄金花，持杯爲君泛。"]'),
('429e9a27-6792-474e-bd15-9ee04c62d2e2','秋懷','王安石','宋','宋诗','song-poetry','','[]','城南平野寒多露，窗壁含風秋氣度。',64,'全唐诗/poet.song.31000.json','["城南平野寒多露，窗壁含風秋氣度。", "鄰桑槭槭已欲空，悲蟲啾啾促機杼。", "柴門半掩掃鳥迹，獨抱殘編與神遇。", "韓公既去豈能追，孟子有來還不拒。"]'),
('1f60447c-2d1b-4cc3-9943-5003bed821c4','既別羊王二君與同官會飲于城南因成一篇追寄','王安石','宋','宋诗','song-poetry','','[]','赤車使者白頭翁，當歸入見天門冬。',112,'全唐诗/poet.song.31000.json','["赤車使者白頭翁，當歸入見天門冬。", "與山久別悲匆匆，澤瀉半天河漢空。", "羊王不留行薄晚，酒肉從容追路遠。", "臨流黄昏席未卷，玉壺倒盡黄金盞。", "羅列當辭更繾綣，預知子不空青眼。", "嚴徐長卿誤推挽，老年揮翰天子苑。", "送車陸續隨子返，坐聽城鷄腸宛轉。"]'),
('6431daac-f223-48b6-9813-10a5787e300c','試茗泉','王安石','宋','宋诗','song-poetry','','[]','此泉地何偏，陸羽曾未閱。',48,'全唐诗/poet.song.31000.json','["此泉地何偏，陸羽曾未閱。", "坻沙光散射，竇乳甘潛洩。", "靈山不可見，嘉草何由啜。", "但有夢中人，相隨掬明月。"]'),
('eb3fd329-c225-42b9-93a5-6b3ee2b0a877','躍馬泉','王安石','宋','宋诗','song-poetry','','[]','古水縮蛟螭，憎山欲隳突。',84,'全唐诗/poet.song.31000.json','["古水縮蛟螭，憎山欲隳突。", "山祇來伐之，半嶺跳齧膝。", "玉珂鳴塞空，組練光照日。", "崩騰赴不測，一陷常萬匹。", "神戰異人間，千秋爲儵忽。", "泉旁往來客，夜寄幽人室。", "但聽鳴蕭蕭，何由見神物。"]'),
('b4e1bf71-2b9e-4068-aa59-75d04452044c','白紵山','王安石','宋','宋诗','song-poetry','','[]','白紵衆山頂，江湖所縈带。',96,'全唐诗/poet.song.31000.json','["白紵衆山頂，江湖所縈带。", "浮雲卷晴明，可見九州外。", "肩輿上寒空，置酒故人會。", "峰巒張錦繡，草木吹竽籟。", "登臨信地險，俯仰知天大。", "留歡薄日晚，起視飛鳥背。", "殘年苦局束，往事嗟摧壞。", "歌舞不可求，桓公井空在。"]'),
('acde1616-2916-4346-9ef1-b87099b68f9b','七星硯','王安石','宋','宋诗','song-poetry','','[]','余聞星墮地，往往化爲石。',96,'全唐诗/poet.song.31000.json','["余聞星墮地，往往化爲石。", "石上有七星，此理余莫測。", "持來當白日，光彩不爲匿。", "恍如起鴻蒙，俛仰帝垣側。", "當由偶然似，見取參筆墨。", "豪心蕩珍異，樂以萬金得。", "南工始爲僞，傅合巧無隙。", "亦時疑世人，故自有能識。"]'),
('310a1174-62a2-407e-bcaf-e35a88907a91','九鼎','王安石','宋','宋诗','song-poetry','','[]','禹行掘山走百谷，蛟龍竄藏魑魅伏。',112,'全唐诗/poet.song.31000.json','["禹行掘山走百谷，蛟龍竄藏魑魅伏。", "心誌幽妖尚覬隙，以金鑄鼎空九牧。", "冶雲赤天漲爲黑，韛風餘吹山拔木。", "鼎成聚觀變怪索，夜人行歌鬼晝哭。", "功施元元後無極，三姓衛守相傳屬。", "弱周無人有宜出，沈之九幽拆地軸。", "始皇區區求不得，坐令神奸窺邑屋。"]'),
('db765628-db5a-4587-a71c-ef8d356a0939','九井','王安石','宋','宋诗','song-poetry','','[]','沿崖涉澗三十里，高下犖確無人耕。',160,'全唐诗/poet.song.31000.json','["沿崖涉澗三十里，高下犖確無人耕。", "捫蘿挽蔦到山趾，仰見吹瀉何崢嶸。", "餘聲投林欲風雨，末勢卷土猶溪阬。", "飛蟲凌兢走獸慄，霜雪夏落雷冬鳴。", "野人往往見神物，鱗甲漠漠雲隨行。", "我來立久無所得，空數石上菖蒲生。", "中官繫龍沉玉冊，小吏磔狗澆銀觥。", "地形偶爾藏險怪，天意未必司陰晴。", "山川在理有崩竭，丘壑自古相虛盈。", "誰能保此千世後，天柱不折泉常傾。"]'),
('68e4e19f-3e81-45db-8c37-b2c85db1f4af','寄題衆樂亭','王安石','宋','宋诗','song-poetry','','[]','陵陽遊觀吾所好，恨不即過衆樂亭。',192,'全唐诗/poet.song.31000.json','["陵陽遊觀吾所好，恨不即過衆樂亭。", "嘗聞彷彿入夢寐，吟筆自欲圖丹青。", "千峰秀出百里外，忽於其上崢檐楹。", "朝雲噓岩日暖暖，夜水落澗風泠泠。", "春花窈窕鳥爭舞，夏木蔭鬰猿哀鳴。", "潦收葉落天地爽，海月影到山川明。", "籃輿晨出誰與適，坐與萬物觀虛盈。", "令思民事不忍後，田間笑語催蠶耕。", "吏休歸舍獄訟少，墟落飲酒欲秋成。", "唯愁一日奪令去，出來老稚交逢迎。", "彼民安知方祿仕，徒喜使我寬逋征。", "令知道義士林服，遺愛豈用吾詩評。"]'),
('a91d2ba1-7eb2-4573-add6-7eb064e65e54','書會別亭','王安石','宋','宋诗','song-poetry','','[]','西城路，居人送客西歸處。',60,'全唐诗/poet.song.31000.json','["西城路，居人送客西歸處。", "年年借問去何時，今日扁舟從此去。", "春風吹花落高枝，飛來飛去不自知。", "路上行人亦如此，應有重來此處時。"]'),
('79be576a-d1c5-452b-a0e4-c36496853bbe','題舒州山谷寺石牛洞泉穴','王安石','宋','宋诗','song-poetry','','[]','水泠泠而北出，山靡靡而旁圍。',28,'全唐诗/poet.song.31000.json','["水泠泠而北出，山靡靡而旁圍。", "欲窮源而不得，竟悵望以空歸。"]'),
('ac9ab34e-851f-4492-888a-b199140f4385','泊舟姑蘇','王安石','宋','宋诗','song-poetry','','[]','朝遊盤門東，暮出閶門西。',48,'全唐诗/poet.song.31000.json','["朝遊盤門東，暮出閶門西。", "四顧茫無人，但見白日低。", "荒林带昏煙，上有歸鳥啼。", "物皆得所託，而我無安棲。"]'),
('863a19c2-927b-4a7c-a833-76dd03fe45e0','崑山慧聚寺次孟郊韵','王安石','宋','宋诗','song-poetry','','[]','僧蹊蟠青蒼，莓苔上秋床。',48,'全唐诗/poet.song.31000.json','["僧蹊蟠青蒼，莓苔上秋床。", "露翰饑更清，風蘤遠亦香。", "掃石出古色，洗松納空光。", "久遊不忍還，迫迮冠蓋場。"]'),
('73d22928-763a-4a10-9296-dbcb0be09ef5','如歸亭順風','王安石','宋','宋诗','song-poetry','','[]','春江窈窈來無地，飛帆浩浩窮天際。',64,'全唐诗/poet.song.31000.json','["春江窈窈來無地，飛帆浩浩窮天際。", "朝出吳川夕霅溪，回首喬林吹岸薺。", "柁師高卧自嘯歌，戲彼挽舟行復止。", "人生萬事反衍多，道路後先能幾何。"]'),
('e733fcd9-23c4-4a6b-a6ea-6e87c18bbe03','垂虹亭','王安石','宋','宋诗','song-poetry','','[]','三江五湖口，地與天不隔。',168,'全唐诗/poet.song.31000.json','["三江五湖口，地與天不隔。", "日月所蔽虧，東西渺然白。", "漫漫浸北斗，浩浩浮南極。", "誰投此虹蜺，欲濟兩間阨。", "中流雜蜃氣，欄楯相承翼。", "初疑神所爲，滅沒在頃刻。", "晨興坐其上，傲兀至中昃。", "猶憐變化功，不謂因人役。", "今君持酒漿，談笑顧賓客。", "頗誇九州物，壯麗此無敵。", "熒煌丹砂柱，璀璨黄金壁。", "中家不慮始，助我皆豪殖。", "喟予獨感此，剝爛有終極。", "改作不可無，還當采民力。"]'),
('da805704-0c96-4404-a88a-33d1f17544aa','張氏靜居院','王安石','宋','宋诗','song-poetry','','[]','動者利進爲，靜者樂止居。',264,'全唐诗/poet.song.31000.json','["動者利進爲，靜者樂止居。", "物性有偏得，惟賢時卷舒。", "張侯始出仕，所至多名譽。", "老矣歸偃休，買地斸荒蕪。", "屋成爲令名，名實與時俱。", "南堂棲幽真，晨起瞻像圖。", "北堂畫五禽，游戲養形軀。", "燕有諸賓庭，學有諸子廬。", "問侯年幾何，矯矯八十餘。", "問侯何能爾，心不藏憂愉。", "問侯客何爲，弦歌飲投壺。", "問侯兒何讀，夏商及唐虞。", "嵩山填門戶，洛水繞階除。", "侯於山水間，結駟有通衢。", "我念老退者，古多賢大夫。", "留侯亦養生，乃欲凌空虛。", "閉門不飲酒，豈異山中臞。", "疏傅稍喜客，揮金能自娛。", "不聞喜教子，滿屋青紫朱。", "張侯能兼取，勝事古所無。", "褒稱有樂石，丞相爲之書。", "而我不自量，聞風亦歌呼。"]'),
('d5913658-ad85-4700-9549-bb6deff34064','丙戌五日京師作二首  其一','王安石','宋','宋诗','song-poetry','','[]','北風閣雨去不下，驚沙蒼茫亂昏曉。',32,'全唐诗/poet.song.31000.json','["北風閣雨去不下，驚沙蒼茫亂昏曉。", "傳聞城外八九里，雹大如拳死飛鳥。"]'),
('58c4df4a-66e0-4d82-b05d-ad3c1fa99552','丙戌五日京師作二首  其二','王安石','宋','宋诗','song-poetry','','[]','浮雲離披久不合，太陽獨行乾萬物。',32,'全唐诗/poet.song.31000.json','["浮雲離披久不合，太陽獨行乾萬物。", "誰令昨夜雨霶沱，北風蕭蕭寒到骨。"]'),
('1f73564b-b27f-496a-99c4-0d09f21e3811','答客','王安石','宋','宋诗','song-poetry','','[]','士常疑西伯，何至羑里辱。',48,'全唐诗/poet.song.31000.json','["士常疑西伯，何至羑里辱。", "瞽鰥親父子，尚脫井廩酷。", "昏主雖聖臣，飛禍安可卜。", "致命遂其志，雖窮不爲戮。"]'),
('6fd2042d-d17a-4325-a1c6-e64f87b3016b','次韵唐彥猷華亭十咏 顧林亭','王安石','宋','宋诗','song-poetry','','[]','寥寥湖上亭，不見野王居。',48,'全唐诗/poet.song.31000.json','["寥寥湖上亭，不見野王居。", "平林豈舊物，歲晚空扶疏。", "自古聖賢人，邑國皆丘墟。", "不朽在名德，千秋想其餘。"]'),
('2245da06-c271-4a3e-b082-3bdbd09327cc','次韵唐彥猷華亭十咏 寒穴','王安石','宋','宋诗','song-poetry','','[]','神泉冽冰霜，高穴與雲平。',48,'全唐诗/poet.song.31000.json','["神泉冽冰霜，高穴與雲平。", "空山渟千秋，不出嗚咽聲。", "山風吹更寒，山月相與清。", "北客不到此，如何洗煩酲。"]'),
('bd0f0319-b4f9-4a62-bb15-d2d571fb8727','次韵唐彥猷華亭十咏 吳王獵場','王安石','宋','宋诗','song-poetry','','[]','吳王好射虎，但射不操戈。',48,'全唐诗/poet.song.31000.json','["吳王好射虎，但射不操戈。", "匹馬掠廣場，萬兵助遮羅。", "時平事非昔，此地桑麻多。", "猛獸亦已盡，牛羊在田坡。"]'),
('303531f5-9a32-465b-958e-a686edccd65b','次韵唐彥猷華亭十咏 始皇馳道','王安石','宋','宋诗','song-poetry','','[]','穆王得八駿，萬事得期修。',48,'全唐诗/poet.song.31000.json','["穆王得八駿，萬事得期修。", "茫茫萬載間，復此好遠游。", "車輪與馬跡，此地亦嘗留。", "想當治道時，勞者尸如丘。"]'),
('c977ad16-bb37-4c85-8748-49cc43aad6c0','次韵唐彥猷華亭十咏 柘湖','王安石','宋','宋诗','song-poetry','','[]','柘林著湖山，菱葉蔓湖濱。',48,'全唐诗/poet.song.31000.json','["柘林著湖山，菱葉蔓湖濱。", "秦女亦何事，能爲此湖神。", "年年賽雞豚，漁子自知津。", "幽妖窟險阻，禍福易欺人。"]'),
('718dfd39-ca96-498b-b288-6b7ac91528b4','次韵唐彥猷華亭十咏 陸瑁養魚池','王安石','宋','宋诗','song-poetry','','[]','野人非昔人，亦復水上居。',48,'全唐诗/poet.song.31000.json','["野人非昔人，亦復水上居。", "紛紛水中游，豈是昔時魚。", "吹波浮還沒，競食糟糠餘。", "吞舟不可見，守此歲月除。"]'),
('1be53216-464d-4b0e-94e5-dc3827aa9460','次韵唐彥猷華亭十咏 華亭谷','王安石','宋','宋诗','song-poetry','','[]','巨川非一源，源亦在衆流。',48,'全唐诗/poet.song.31000.json','["巨川非一源，源亦在衆流。", "此谷乃清淺，松江能覆舟。", "蟲魚何所知，上下相沉浮。", "徒嗟大盈北，浩浩無春愁。"]'),
('74af1d4c-0382-4ec7-8ef8-06461bc14732','次韵唐彥猷華亭十咏 陸機宅','王安石','宋','宋诗','song-poetry','','[]','故物一已盡，嗟此歲年深。',48,'全唐诗/poet.song.31000.json','["故物一已盡，嗟此歲年深。", "野桃自著花，荒棘自生鍼。", "芊芊谷水陽，鬰鬰崑山陰。", "俛仰但如昨，遊者不可尋。"]'),
('47b9d7ad-3f54-444d-b124-34de986e5a7f','次韵唐彥猷華亭十咏 崑山','王安石','宋','宋诗','song-poetry','','[]','玉人生此山，山亦傳此名。',48,'全唐诗/poet.song.31000.json','["玉人生此山，山亦傳此名。", "崖風與穴水，清越有餘聲。", "悲哉世所珍，一出受欹傾。", "不如鶴與猿，棲息尚全生。"]'),
('f4b0f32e-7cc5-43f4-b989-7026d5c777c8','次韵唐彥猷華亭十咏 三女崗','王安石','宋','宋诗','song-poetry','','[]','自古世上雄，慷慨擅功名。',48,'全唐诗/poet.song.31000.json','["自古世上雄，慷慨擅功名。", "當時豈有力，能使死者生。", "三女共一丘，此憾亦難平。", "音容若有作，無力傾人城。"]'),
('60ea445e-4d52-4129-aceb-beb7abda8f4d','太白嶺','王安石','宋','宋诗','song-poetry','','[]','太白巃嵷東南馳，衆嶺環合青紛披。',64,'全唐诗/poet.song.31000.json','["太白巃嵷東南馳，衆嶺環合青紛披。", "煙雲厚薄皆可愛，樹石疏密自相宜。", "陽春已歸鳥語樂，溪水不動魚行遲。", "生民何由得處所，與茲魚鳥相諧熙。"]'),
('936d2eb4-76fd-44df-8029-64c4c024e3e7','禿山','王安石','宋','宋诗','song-poetry','','["\u5199\u5c71", "\u5bd3\u8a00", "\u63cf\u5199\u5c71", "\u8bbd\u523a"]','吏役滄海上，瞻山一停舟。',168,'全唐诗/poet.song.31000.json','["吏役滄海上，瞻山一停舟。", "怪此禿誰使，鄉人語其由。", "一狙山上鳴，一狙從之遊。", "相匹乃生子，子衆孫還稠。", "山中草木盛，根實始易求。", "攀挽上極高，屈曲亦窮幽。", "衆狙各豐肥，山乃盡侵牟。", "攘爭取一飽，豈暇議藏收。", "大狙尚自苦，小狙亦已愁。", "稍稍受咋嚙，一毛不得留。", "狙雖巧過人，不善操耡耰。", "所嗜在果穀，得之常似偷。", "嗟此海山中，四顧無所投。", "生生未云已，歲晚將安謀。"]'),
('e43b90b4-53f5-4684-96be-733d1127ec1a','贈曾子固','王安石','宋','宋诗','song-poetry','','[]','曾子文章衆無有，水之江漢星之斗。',64,'全唐诗/poet.song.31000.json','["曾子文章衆無有，水之江漢星之斗。", "挾才乘氣不媚柔，群兒謗傷均一口。", "吾語群兒勿謗傷，豈有曾子終皇皇。", "借令不幸賤且死，後日猶爲班與揚。"]'),
('68a722f9-42de-42b1-b621-bd5e957329fc','鮑公水','王安石','宋','宋诗','song-poetry','','[]','村南鮑公山，山北鮑公水。',116,'全唐诗/poet.song.31000.json','["村南鮑公山，山北鮑公水。", "高穴逗遠源，泠泠落山嘴。", "玉色與飴味，不可他味比。", "竹樹四蒙密，翠藤相披靡。", "漫郎昔少年，幽居得之此。", "臨窺若有遇，愛嘆無時已。", "浮名未汙染，永矢終焉爾。", "奈何中棄入長安，十載風塵化舊顔。", "歡囂滿耳不可洗，此水泠泠空在山。"]'),
('89cd38ec-dcaa-44cf-86f6-bdae5c7f6ca7','寄李士寧先生','王安石','宋','宋诗','song-poetry','','[]','樓臺高聳間晴霞，松檜陰森夾柳斜。',48,'全唐诗/poet.song.31000.json','["樓臺高聳間晴霞，松檜陰森夾柳斜。", "渴愁如箭去年華，陶情滿滿傾榴花。", "自嗟不及門前水，流到先生雲外家。"]'),
('4d902929-8222-4840-a241-766f955019a5','僧德殊家水簾求予咏','王安石','宋','宋诗','song-poetry','','[]','淙淙萬音落石顛，皎皎一派當檐前。',64,'全唐诗/poet.song.31000.json','["淙淙萬音落石顛，皎皎一派當檐前。", "清風高吹鸞鶴唳，白日下照蛟龍涎。", "浮雲粧額自能卷，缺月琢鉤相與縣。", "朱門試問幽人價，翡翠鮫綃不直錢。"]'),
('edd483c6-db97-4dc7-b7ee-28e5fcbcac44','杭州修廣師法喜堂','王安石','宋','宋诗','song-poetry','','[]','浮屠之法與世殊，洗滌萬事求空虛。',128,'全唐诗/poet.song.31000.json','["浮屠之法與世殊，洗滌萬事求空虛。", "師心以此不挂物，一堂收身自有餘。", "堂陰置石雙嵽嵲，石脚立竹青扶疏。", "一來已覺肝膽豁，况乃宴坐窮朝晡。", "憶初救時勇自許，壯大看俗尤崎嶇。", "豐車肥馬載豪傑，少得志願多憂虞。", "始知進退各有理，造次未可分賢愚。", "會將築室返耕釣，相與此處吟山湖。"]'),
('0f30497e-296e-4d13-bcdf-71682b1af203','復至曹娥堰寄剡縣丁元珍','王安石','宋','宋诗','song-poetry','','[]','溪水渾渾來自北，千山抱水清相射。',128,'全唐诗/poet.song.31000.json','["溪水渾渾來自北，千山抱水清相射。", "山深水急無艇子，欲從故人安可得。", "故人昔日此水上，樽酒扁舟慰行役。", "津亭把手坐一笑，我喜滿懷君動色。", "論新講舊惜未足，落日低徊已催客。", "離心自醉不復飲，秋果寒花空滿席。", "今年却坐相逢處，怊悵難求別時迹。", "可憐溪水自南流，安得溪船問消息。"]'),
('2392d679-3286-4e89-8a2a-518b72ded744','答曾子固南豐道中所寄','王安石','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吾子命世豪，術學窮無閒。',210,'全唐诗/poet.song.31000.json','["吾子命世豪，術學窮無閒。", "直意慕聖人，不問閔與顔。", "彼昏何爲者，誣構來{口顔}{口顔}。", "應逮犯秋陽，動爲人所嘆。", "不恤我躬瘁，乃嗟天澤慳。", "令人念公卿，燁燁趨王班。", "泊無憫世意，狙猿而佩環。", "愛子所守卓，憂予不能攀。", "永矢從子遊，合如扉上鐶。", "願言借餘力，迎浦疏潺潺。", "亦有衣上塵，可攀禆泰山。", "大江秋正清，島溆相縈彎。", "四盼浩無主，日暮煙霞斑。", "水竹密以勁，霜楓衰更殷。", "賞託亦云健，行矣非閒關。", "相期東北遊，致館淮之灣。", "無爲襲寧嬴，悠然及溫還。"]'),
('0a1922a4-2c1f-4306-960a-b4f76b1d8990','寄贈胡先生','王安石','宋','宋诗','song-poetry','','[]','先生天下豪傑魁，胸臆廣博天所開。',176,'全唐诗/poet.song.31000.json','["先生天下豪傑魁，胸臆廣博天所開。", "文章事業望孔孟，不復睥睨蔡與崔。", "十年留滯東南州，飽足藜藿安蒿萊。", "獨鳴道德驚此民，民之聞者源源來。", "高冠大带滿門下，奮如百蟄乘春雷。", "惡人沮服善者起，昔時蹻跖今騫回。", "先生不試乃能爾，誠令得志如何哉。", "吾願聖帝營太平，補葺廊廟枝傾頹。", "披旒發纊廣耳目，照徹山谷多遺材。", "先收先生作梁柱，以次構架桷與榱。", "群臣面向帝深拱，仰戴堂陛方崔嵬。"]'),
('3192f25c-6e1d-4e99-970d-da6cbea6485c','得曾子固書因寄','王安石','宋','宋诗','song-poetry','','[]','始吾居揚日，重問每見及。',252,'全唐诗/poet.song.31000.json','["始吾居揚日，重問每見及。", "云將自親側，萬里同講習。", "子行何舒舒，吾望已汲汲。", "窮年夢東南，顔色不可挹。", "仁賢豈欺我，正恐事維縶。", "嚴親抱憂衰，生理頼以給。", "不然航江外，天寒北風急。", "無乃山路惡，僕弱馬行澀。", "孤懷未肯開，歲物忽如蟄。", "朅來高郵住，巷屋頗卑濕。", "蓬蒿稍芟除，茅竹隨補葺。", "苟云禦風氣，尚恐憂雨汁。", "故人莫在眼，屢獨開巾笈。", "忠信蓋未見，吾敢誣茲邑。", "出關誰與語，念子百憂集。", "眺聽聊自放，日暮城頭立。", "徐歸坐當戶，使者操書入。", "時開識子意，如渴得美湆。", "驪駒日就道，玉手行可執。", "舊學待鎸磨，新文得刪拾。", "重登城頭望，喜氣滿原隰。"]'),
('a55cefeb-e21c-43f0-be9e-fb19463a978c','寄虔州江陰二妹','王安石','宋','宋诗','song-poetry','','[]','貢水日夜下，下與章水期。',96,'全唐诗/poet.song.31000.json','["貢水日夜下，下與章水期。", "我行二水間，無日不爾思。", "飄若越鳥北，心常在南枝。", "又如岐首蛇，南北兩欲馳。", "逝者日已遠，百憂詎能追。", "生存苦乖隔，邂逅亦何時。", "女子歸有道，善懷見於詩。", "庶云留汝車，慰我堂上慈。"]'),
('904e5f46-b959-44af-ac79-ba567343ce0f','登越州城樓','王安石','宋','宋诗','song-poetry','','[]','越山長青水長白，越人長家山水國。',64,'全唐诗/poet.song.31000.json','["越山長青水長白，越人長家山水國。", "可憐客子無定宅，一夢三年今復北。", "浮雲縹緲抱城樓，東望不見空回頭。", "人間未有歸耕處，早晚重來此地遊。"]'),
('fb209e44-8c05-4dec-b04d-398ea8775f78','憶昨詩示諸外弟','王安石','宋','宋诗','song-poetry','','[]','憶昨此地相逢時，春入窮谷多芳菲。',384,'全唐诗/poet.song.31000.json','["憶昨此地相逢時，春入窮谷多芳菲。", "短垣囷囷冠翠嶺，躑躅萬樹紅相圍。", "幽花媚草錯雜出，黄蜂白蝶參差飛。", "此時少壯自負恃，意氣與日爭光輝。", "乘閑弄筆戲春色，脫略不省旁人譏。", "坐欲持此博軒冕，肯言孔孟猶寒饑。", "丙子從親走京國，浮塵坌並緇人衣。", "明年親作建昌吏，四月挽船江上磯。", "端居感慨忽自寤，青天閃爍無停暉。", "男兒少壯不樹立，挾此窮老將安歸。", "吟哦圖書謝慶弔，坐室寂寞生伊威。", "材疏命賤不自揣，欲與稷契遐相希。", "旻天一朝畀以禍，先子泯沒予誰依。", "精神流離肝肺絕，眥血被面無時晞。", "母兄呱呱泣相守，三載厭食鍾山薇。", "屬聞降詔起群彥，遂自下國趨王畿。", "刻章琢句獻天子，釣取薄祿歡庭闈。", "身著青衫手持版，奔走卒歲官淮沂。", "淮沂無山四封庳，獨有廟塔尤峨巍。", "時時憑高一悵望，想見江南多翠微。", "歸心動蕩不可抑，霍若猛吹翻旌旂。", "騰書漕府私自列，仁者惻隠從其祈。", "暮春三月亂江水，勁櫓健帆如轉機。", "還家上堂拜祖母，奉手出涕縱橫揮。"]'),
('171c8ea6-f25c-4ad5-acb7-c58d38ec285b','欣會亭','王安石','宋','宋诗','song-poetry','','[]','數家鄰水竹，一塢共雲林。',48,'全唐诗/poet.song.31000.json','["數家鄰水竹，一塢共雲林。", "晚食靜適己，獨謠欣會心。", "移床隨漫興，操策取幽尋。", "未愛神錐汝，猶憐妙斲琴。"]'),
('739e0315-1684-4b5c-b9c1-425cc3fa2a65','東皋','王安石','宋','宋诗','song-poetry','','[]','起伏晴雲徑，縱橫暖水陂。',48,'全唐诗/poet.song.31000.json','["起伏晴雲徑，縱橫暖水陂。", "草長流翠碧，花遠沒黄鸝。", "楚製從人笑，吳吟得自怡。", "東皋興不淺，遊走及芳時。"]'),
('d32faff3-3e14-4ec9-b0d2-c2ee73165b7d','歲晚','王安石','宋','宋诗','song-poetry','','[]','月映林塘澹，風含笑語凉。',48,'全唐诗/poet.song.31000.json','["月映林塘澹，風含笑語凉。", "俯窺憐綠凈，小立佇幽香。", "携幼尋新的，扶衰坐野航。", "延緣久未已，歲晚惜流光。"]'),
('a427447b-187c-4c4d-9e59-e71385b80598','半山春晚即事','王安石','宋','宋诗','song-poetry','','[]','春風取花去，酬我以清陰。',48,'全唐诗/poet.song.31000.json','["春風取花去，酬我以清陰。", "翳翳陂路靜，交交園屋深。", "床敷每小息，杖屨或幽尋。", "惟有北山鳥，經過遺好音。"]'),
('0572daef-ba92-406f-8031-ee6a77cfe086','欹眠','王安石','宋','宋诗','song-poetry','','[]','翠幙卷東岡，欹眠月半床。',48,'全唐诗/poet.song.31000.json','["翠幙卷東岡，欹眠月半床。", "松聲悲永夜，荷氣馥初凉。", "清話非無寄，幽期故不忘。", "扁舟亦在眼，終自懶衣裳。"]'),
('6dac1567-4b7e-46a9-ada1-869d175859be','露坐','王安石','宋','宋诗','song-poetry','','[]','露坐看溝月，飄然風度荷。',48,'全唐诗/poet.song.31000.json','["露坐看溝月，飄然風度荷。", "珠跳散作點，金湧合成波。", "老失芳歲易，靜知良夜多。", "陵秋久不寐，吾樂豈弦歌。"]'),
('6f0d6f82-4fa8-490a-bbce-9119206e27bf','山行','王安石','宋','宋诗','song-poetry','','[]','出寫清淺景，歸穿蒼翠陰。',48,'全唐诗/poet.song.31000.json','["出寫清淺景，歸穿蒼翠陰。", "平頭均楚製，長耳嗣吳吟。", "暮嶺已佳色，寒泉仍好音。", "誰同此真意，倦鳥亦幽尋。"]'),
('01af5e57-4903-427d-b56f-ca8bea9860bd','題雱祠堂','王安石','宋','宋诗','song-poetry','','[]','斯文實有寄，天豈偶生才。',48,'全唐诗/poet.song.31000.json','["斯文實有寄，天豈偶生才。", "一日鳳鳥去，千秋梁木摧。", "煙留衰草恨，風造暮林哀。", "豈謂登臨處，飄然獨往來。"]'),
('8d397eb8-95d8-443a-9071-0d6e456e9b67','定林','王安石','宋','宋诗','song-poetry','','[]','漱甘凉病齒，坐曠息煩襟。',48,'全唐诗/poet.song.31000.json','["漱甘凉病齒，坐曠息煩襟。", "因脫水邊屨，就敷巖上衾。", "但留雲對宿，仍值月相尋。", "真樂非無寄，悲蟲亦好音。"]'),
('619743c1-124b-4acd-a560-d32f630970a9','送張甥赴青州幕','王安石','宋','宋诗','song-poetry','','[]','人情每期費，之子適予心。',48,'全唐诗/poet.song.31000.json','["人情每期費，之子適予心。", "老餞城東陌，悲分歲暮襟。", "少留班露草，遂往隔雲林。", "未覺青丘遠，因風嗣好音。"]'),
('2773dcc0-6213-43ce-b0eb-32dd158ec388','送張宣義之官越幕二首  其一','王安石','宋','宋诗','song-poetry','','[]','會稽遊宦鄉，海物錯句章。',48,'全唐诗/poet.song.31000.json','["會稽遊宦鄉，海物錯句章。", "土潤箭萌美，水甘茶串香。", "今君誠暫屈，他日恐難忘。", "唯有西興渡，靈胥或怒張。"]'),
('df593642-d54f-4b44-91ef-3d640d668a20','送張宣義之官越幕二首  其二','王安石','宋','宋诗','song-poetry','','[]','誰謂貴公子，乃如寒士家。',48,'全唐诗/poet.song.31000.json','["誰謂貴公子，乃如寒士家。", "真宜舉敦樸，已自勝浮華。", "洲荻藏迷子，溪篁擁若耶。", "相望只在眼，音問莫言賒。"]'),
('62e72573-d47c-45c4-959a-341656c36171','送贊善張軒民西歸','王安石','宋','宋诗','song-poetry','','[]','柴荆雀有羅，公子數經過。',48,'全唐诗/poet.song.31000.json','["柴荆雀有羅，公子數經過。", "邂逅相知晚，從容所得多。", "百憂生暮齒，一笑隔滄波。", "早晚西州路，遥聽下坂珂。"]'),
('d5203d17-d2f1-41c9-a918-9c750c085f69','送鄧監簿南歸','王安石','宋','宋诗','song-poetry','','[]','不見驪塘路，茫然四十春。',48,'全唐诗/poet.song.31000.json','["不見驪塘路，茫然四十春。", "長爲異鄉客，每憶故時人。", "水閱公三世，雲浮我一身。", "濠梁送歸處，握手但悲辛。"]'),
('e975f3b9-3d01-4e33-8e0a-864399738997','秋夜二首  其一','王安石','宋','宋诗','song-poetry','','[]','客卧書顛倒，蟲鳴坐寂寥。',48,'全唐诗/poet.song.31000.json','["客卧書顛倒，蟲鳴坐寂寥。", "殘燈生暗暈，重露集寒條。", "真樂閑尤見，深禪靜更超。", "此懷無與晤，擁鼻一長謠。"]'),
('e9ecd9ad-777d-47bc-8bb7-d2aa9bd0a52a','秋夜二首  其二','王安石','宋','宋诗','song-poetry','','[]','幔逗長風細，窗留半月斜。',48,'全唐诗/poet.song.31000.json','["幔逗長風細，窗留半月斜。", "浮煙暝綠草，泫露冷黄花。", "獨曳緣雲策，仍尋度水槎。", "歸時參夜半，鄰犬靜中譁。"]'),
('31c02da1-1422-4e75-b78b-4650d5d8fdc3','即事','王安石','宋','宋诗','song-poetry','','[]','徑暖草如積，山晴花更繁。',48,'全唐诗/poet.song.31000.json','["徑暖草如積，山晴花更繁。", "縱橫一川水，高下數家村。", "靜憩鷄鳴午，荒尋犬吠昏。", "歸來向人說，疑是武陵源。"]'),
('77136279-38ce-45e3-9c8d-7e26ac01afb4','晝寢','王安石','宋','宋诗','song-poetry','','[]','井逕從蕪漫，青藜亦倦扶。',48,'全唐诗/poet.song.31000.json','["井逕從蕪漫，青藜亦倦扶。", "百年唯有且，萬事總無如。", "棄置蕉中鹿，驅除屋上烏。", "獨眠窗日午，往往夢華胥。"]'),
('cea33753-7827-47db-a414-eb9483c8af58','過故居','王安石','宋','宋诗','song-poetry','','[]','泝栰開新屋，扶輿繞故園。',48,'全唐诗/poet.song.31000.json','["泝栰開新屋，扶輿繞故園。", "事遺心獨寄，路翳目空存。", "野果寒林寂，蠻花午簟溫。", "難忘舊時處，欲宿愧桑門。"]'),
('61aaaf07-b7ea-49fe-8ea9-9f40b5dc0b31','雁','王安石','宋','宋诗','song-poetry','','[]','北去還爲客，南來豈是歸。',48,'全唐诗/poet.song.31000.json','["北去還爲客，南來豈是歸。", "倦投空渚泊，饑帖冷雲飛。", "垣柵鷄長暖，溝池鶩自肥。", "憐渠不知此，更墮野人機。"]'),
('fe3663a2-aa54-407b-a414-2fc80e253abf','與道原過西莊遂遊寶乘道原游西庵遂至草堂寶乘寺二首  其一','王安石','宋','宋诗','song-poetry','','[]','桑楊已零落，藻荇亦消沈。',48,'全唐诗/poet.song.31000.json','["桑楊已零落，藻荇亦消沈。", "園宅在人境，歲時傷我心。", "强穿西埭路，共望北山岑。", "欲覓道人語，跨鞍聊一尋。"]'),
('f762a193-6146-497b-8a7e-fda6ad9e3954','與道原過西莊遂遊寶乘道原游西庵遂至草堂寶乘寺二首  其二','王安石','宋','宋诗','song-poetry','','[]','親朋會合少，時序感傷多。',48,'全唐诗/poet.song.31000.json','["親朋會合少，時序感傷多。", "勝踐聊爲樂，清談可當歌。", "微風淡水竹，浄日暖煙蘿。", "興極猶難盡，當如薄暮何。"]'),
('d3bc7fd4-639f-4323-8175-b56676265af9','送陶氏婦兼寄純甫','王安石','宋','宋诗','song-poetry','','[]','雲結川原暗，風連草木萎。',48,'全唐诗/poet.song.31000.json','["雲結川原暗，風連草木萎。", "遥瞻季行役，正對女傷悲。", "夢事中千變，生涯老百罹。", "更慚無道力，臨路涕交頤。"]'),
('e61102df-2d71-4171-8a99-0b59fbb0f0ff','自府中歸寄西庵行詳','王安石','宋','宋诗','song-poetry','','[]','意衰難自力，扶路便思還。',48,'全唐诗/poet.song.31000.json','["意衰難自力，扶路便思還。", "强逐蕭騷水，遥看慘淡山。", "行尋香草遍，歸漾晚雲間。", "西崦分明見，幽人不可攀。"]'),
('3a2b758d-7f56-44d6-bdb8-df96a6f84348','贈上元宰梁之儀承議','王安石','宋','宋诗','song-poetry','','[]','白下有賢宰，能歌如紫芝。',48,'全唐诗/poet.song.31000.json','["白下有賢宰，能歌如紫芝。", "民欺自不忍，縣治本無爲。", "風月誰同賞，江山我亦思。", "粉牆侵醉墨，怊悵綠苔滋。"]'),
('b7c196e4-a33a-48be-9d44-b5077d6d4ef1','贈殊勝院簡道人','王安石','宋','宋诗','song-poetry','','[]','早悟耆山善，今爲洛社豪。',48,'全唐诗/poet.song.31000.json','["早悟耆山善，今爲洛社豪。", "有生常寂寞，所得是風騷。", "露夕吟逾苦，雲收思共高。", "此懷差自適，千社一牛毛。"]'),
('a9acd9a5-5236-44be-b7f9-5f677c3c5b15','懷吳顯道','王安石','宋','宋诗','song-poetry','','[]','南郭紅亭冷，西山白道曛。',48,'全唐诗/poet.song.31000.json','["南郭紅亭冷，西山白道曛。", "江光凌翠氣，洲色亂黄雲。", "歲暮誰邀客，情親故憶君。", "天涯獨惆悵，歸鳥黑紛紛。"]'),
('55eab102-05f2-4f4f-940f-daba4985b795','靜照堂','王安石','宋','宋诗','song-poetry','','[]','任公蹲會稽，海上得招提。',48,'全唐诗/poet.song.31000.json','["任公蹲會稽，海上得招提。", "浄觀堂新搆，幽尋客屢携。", "飛檐出風雨，灑翰落虹蜺。", "投老黄塵陌，東看路恐迷。"]'),
('c0f927db-c27b-4aed-8f40-f8ffeee26c33','重遊草堂  其一','王安石','宋','宋诗','song-poetry','','[]','垣屋荒葛藟，野殿冷檀沈。',48,'全唐诗/poet.song.31000.json','["垣屋荒葛藟，野殿冷檀沈。", "鶴有思顒意，鷹無戀遁心。", "禪房閉深竹，齋鉢度遥岑。", "寂寞黄塵裏，金身倚一尋。"]'),
('3e3ebbea-30eb-4b2f-b495-ad8bb632741d','重遊草堂  其二','王安石','宋','宋诗','song-poetry','','[]','僧殘尚食少，佛古但泥多。',48,'全唐诗/poet.song.31000.json','["僧殘尚食少，佛古但泥多。", "寒守三衣法，饑傳一鉢歌。", "寬閑每迸竹，危朽漫牽蘿。", "怊悵庭前柏，西來意若何。"]'),
('d433da6a-361b-43d8-80f7-3de592d96a6b','重遊草堂  其三','王安石','宋','宋诗','song-poetry','','[]','野寺真蘭若，山僧老病多。',48,'全唐诗/poet.song.31000.json','["野寺真蘭若，山僧老病多。", "疏鍾挾谷響，悲梵入樵歌。", "水映茅篁竹，雲埋蔦女蘿。", "拂塵書所見，因得擬陰何。"]'),
('a7c6c2a8-ca9d-4aac-a07c-cc36f746cbed','題齊安寺山亭','王安石','宋','宋诗','song-poetry','','[]','此山無躑躅，故國有楊梅。',48,'全唐诗/poet.song.31000.json','["此山無躑躅，故國有楊梅。", "悵望心常折，慇懃手自栽。", "暮年逢火改，晴日對花開。", "萬里烏塘路，春風自往來。"]'),
('651a27d5-9cc2-4acc-ae6a-c7c4d9495121','自白門歸望定林有寄','王安石','宋','宋诗','song-poetry','','[]','蹇馿愁石路，余亦倦躋攀。',48,'全唐诗/poet.song.31000.json','["蹇馿愁石路，余亦倦躋攀。", "不見道人久，忽然芳歲殘。", "朝隨雲暫出，暮與鳥爭還。", "杳杳青松壑，知公在兩間。"]'),
('0dc4f4bb-0d42-4e98-a7b7-a84f13acb879','宿定林示無外名務周','王安石','宋','宋诗','song-poetry','','[]','天女穿林至，姮娥度隴來。',48,'全唐诗/poet.song.31000.json','["天女穿林至，姮娥度隴來。", "欲歸今晼晚，相值且徘徊。", "誰謂我忘老，如聞蟲造哀。", "鄰衾亦不寐，共盡白雲杯。"]'),
('22cd7b24-c027-4c08-a687-64088d4ca95f','宿北山示行詳上人','王安石','宋','宋诗','song-poetry','','[]','都城羈旅日，獨許上人賢。',48,'全唐诗/poet.song.31000.json','["都城羈旅日，獨許上人賢。", "誰爲孤峰下，還來宴坐邊。", "是身猶夢幻，何物可攀緣。", "坐對青燈落，松風咽夜泉。"]'),
('012b7035-a21d-4ccb-b095-5f7a220ffcfd','獨飯','王安石','宋','宋诗','song-poetry','','[]','窗明兩不借，榻浄一籧篨。',48,'全唐诗/poet.song.32000.json','["窗明兩不借，榻浄一籧篨。", "栩栩幽人夢，夭夭老者居。", "安能問香積，誰可告華胥。", "獨飯牆陰轉，看雲坐久如。"]'),
('9406bafb-3b9c-4c27-baf2-09e133289aba','草堂','王安石','宋','宋诗','song-poetry','','[]','草堂今寂寞，往事翳山椒。',48,'全唐诗/poet.song.32000.json','["草堂今寂寞，往事翳山椒。", "蕙帳空留鶴，蘿衣終換貂。", "生皆墮天秩，隠或寄公朝。", "疊穎何勞怒，東風汝自摇。"]'),
('c50dd550-1c02-491b-926c-118ee6e6464d','示耿天騭','王安石','宋','宋诗','song-poetry','','[]','挾策能傷性，捐書可盡年。',48,'全唐诗/poet.song.32000.json','["挾策能傷性，捐書可盡年。", "弦歌無舊習，香火有新緣。", "白土長岡路，朱湖小洞天。", "望公時顧我，於此暢幽悁。"]'),
('0818936b-d01a-453c-a49c-72505099db49','光宅','王安石','宋','宋诗','song-poetry','','[]','今知光宅寺，牛首正當門。',48,'全唐诗/poet.song.32000.json','["今知光宅寺，牛首正當門。", "臺殿金碧毀，丘墟桑竹繁。", "蕭蕭新犢卧，冉冉暮鴉翻。", "回首千歲夢，雨花何足言。"]'),
('4fcdb76c-681f-4cb5-aa85-e0a687e2fa0e','示無外','王安石','宋','宋诗','song-poetry','','[]','支頤橫口語，椎髻曲肱眠。',48,'全唐诗/poet.song.32000.json','["支頤橫口語，椎髻曲肱眠。", "莫問誰賓主，安知汝輩年。", "鄰雞生午寂，幽草弄秋妍。", "却憶東窗簟，蠻藤故宛然。"]'),
('4b1da5ed-980e-445a-9760-ebcd5cb73d36','北山暮歸示道人','王安石','宋','宋诗','song-poetry','','[]','千山復萬山，行路有無間。',48,'全唐诗/poet.song.32000.json','["千山復萬山，行路有無間。", "花發蜂遞繞，果垂猿對攀。", "獨尋寒水度，欲趁夕陽還。", "天黑月未上，兒童初掩關。"]'),
('5cac2f90-b88e-4913-be9e-d08d06b45d39','懷古二首  其一','王安石','宋','宋诗','song-poetry','','[]','日密畏前境，淵明欣故園。',48,'全唐诗/poet.song.32000.json','["日密畏前境，淵明欣故園。", "那知飯不賜，所喜菊猶存。", "亦有床座好，但無車馬喧。", "誰爲吾侍者，稚子候柴門。"]'),
('c6ea0bf2-249f-4306-b018-70c277dc22ac','懷古二首  其二','王安石','宋','宋诗','song-poetry','','[]','長者一床室，先生三徑園。',48,'全唐诗/poet.song.32000.json','["長者一床室，先生三徑園。", "非無飯滿鉢，亦有酒盈樽。", "不起華邊坐，常開柳際門。", "漫知談實相，欲辯已忘言。"]'),
('51c6b791-6834-43a9-a41c-3313a8c64926','與寶覺宿精舍','王安石','宋','宋诗','song-poetry','','[]','擾擾復翩翩，秋床燭屢昏。',48,'全唐诗/poet.song.32000.json','["擾擾復翩翩，秋床燭屢昏。", "真爲說萬物，豈止挾三言。", "問義曹溪室，捐書闕里門。", "若知同二妄，目擊道逾存。"]'),
('2c42e413-1544-410c-9ba1-c7afb7317e04','中書偶成','王安石','宋','宋诗','song-poetry','','[]','忽忽余年往，茫茫不自知。',48,'全唐诗/poet.song.32000.json','["忽忽余年往，茫茫不自知。", "慇懃照清淺，邂逅見衰遲。", "輔世無賢業，容身有聖時。", "歸歟今可矣，何以長人爲。"]'),
('e6530672-1079-4847-8c0b-49d21bfb5fe2','華藏寺會故人','王安石','宋','宋诗','song-poetry','','[]','百憂成阻闊，一笑得留連。',48,'全唐诗/poet.song.32000.json','["百憂成阻闊，一笑得留連。", "城郭西風裏，園林落照前。", "共知官似夢，莫負酒如泉。", "興罷重携手，江湖即渺然。"]'),
('2f307d7c-7a3b-419d-af81-7ddd7560d528','求全','王安石','宋','宋诗','song-poetry','','[]','求全傷德義，欲速累功名。',48,'全唐诗/poet.song.32000.json','["求全傷德義，欲速累功名。", "玉要藏而待，苗非揠故生。", "未妨徐出晝，何苦急墮成。", "此道今亡矣，嗟誰可與明。"]'),
('87233c6b-a5e9-430b-a089-31583c1a695f','秋風','王安石','宋','宋诗','song-poetry','','[]','揫歛一何饕，天機亦自勞。',48,'全唐诗/poet.song.32000.json','["揫歛一何饕，天機亦自勞。", "牆隈小翻動，屋角盛呼號。", "漠漠驚沙密，紛紛斷柳高。", "江湖豈在眼，昨夜夢波濤。"]'),
('aa3b86d0-00cc-4270-a832-0499d88a6fe8','次韵昌叔歲暮','王安石','宋','宋诗','song-poetry','','[]','城雲漏日晚，樹凍裹春深。',48,'全唐诗/poet.song.32000.json','["城雲漏日晚，樹凍裹春深。", "糝密魚雖暖，巢危鶴更陰。", "橫風高彍弩，殘溜細鳴琴。", "歲換兒童喜，還傷老大心。"]'),
('37245db6-20c5-459a-95c7-64ede55b1853','次韵酬昌叔羈旅之作','王安石','宋','宋诗','song-poetry','','[]','君方困旅食，予亦誤朝簪。',48,'全唐诗/poet.song.32000.json','["君方困旅食，予亦誤朝簪。", "自索東方米，誰多季子金。", "高門萬馬散，窮巷一燈深。", "客主竟何事，蕭條梁父吟。"]'),
('02dc400f-012a-4f90-8357-47ac3e0ebcf6','次韵唐公三首 東陽道中','王安石','宋','宋诗','song-poetry','','[]','山蔽吳天密，江蟠楚地深。',48,'全唐诗/poet.song.32000.json','["山蔽吳天密，江蟠楚地深。", "浮雲堆白玉，落日瀉黄金。", "渺渺隨行旅，紛紛換歲陰。", "强將詩咏物，收拾濟時心。"]'),
('3f741c80-1726-4a75-83dc-0e12d99fb395','次韵唐公三首 江行','王安石','宋','宋诗','song-poetry','','[]','材非當世用，轂有故人推。',48,'全唐诗/poet.song.32000.json','["材非當世用，轂有故人推。", "使節春冬換，征帆日夜開。", "南遊取干越，東望得州來。", "試盡風波惡，生涯亦可哀。"]'),
('48ead53a-d1c1-41bb-b2b8-4a4dca6d80fb','次韵唐公三首 旅思','王安石','宋','宋诗','song-poetry','','[]','此身南北老，愁見問征途。',48,'全唐诗/poet.song.32000.json','["此身南北老，愁見問征途。", "地大蟠三楚，天低入五湖。", "看雲心共遠，步月影同孤。", "慷慨秋風起，悲歌不爲鱸。"]'),
('00c1c2b6-b9db-4c8a-80a9-83f9c5d792f0','烏塘','王安石','宋','宋诗','song-poetry','','[]','地僻居人少，山稠伏獸多。',48,'全唐诗/poet.song.32000.json','["地僻居人少，山稠伏獸多。", "怒貍朝搏雁，嚵虎夜窺騾。", "籬落生孫竹，門庭上女蘿。", "未應悲寂寞，六載一經過。"]'),
('d6696f31-dff0-443f-a391-977462cb94ab','欲歸','王安石','宋','宋诗','song-poetry','','[]','水漾青天暖，沙吹白日陰。',48,'全唐诗/poet.song.32000.json','["水漾青天暖，沙吹白日陰。", "塞垣春錯莫，行路老侵尋。", "綠稍還幽草，紅應動故林。", "留連一杯酒，滿眼欲歸心。"]'),
('a4bc9341-81a7-4a6f-a547-1fa345199030','發館陶','王安石','宋','宋诗','song-poetry','','[]','促轡數殘更，似聞雞一鳴。',48,'全唐诗/poet.song.32000.json','["促轡數殘更，似聞雞一鳴。", "春風馬上夢，沙路月中行。", "笳鼓遠多思，衣裘寒始輕。", "稍知田父穩，燈火閉柴荆。"]'),
('4e7cb88e-e18d-4ee6-8579-b6df4a4fb6ad','王村','王安石','宋','宋诗','song-poetry','','[]','晻靄王村路，春風北使旗。',48,'全唐诗/poet.song.32000.json','["晻靄王村路，春風北使旗。", "塵催輕騎走，寒咽短簫吹。", "攬轡聯貂帽，投鞭各酒巵。", "紛紛小兒女，何事倚牆窺。"]'),
('b394d411-9dad-4903-9a1c-32aa36c9c197','長垣北','王安石','宋','宋诗','song-poetry','','[]','攬轡長垣北，貂寒不自持。',48,'全唐诗/poet.song.32000.json','["攬轡長垣北，貂寒不自持。", "霜風急鼓吹，煙月暗旌旗。", "騎火流星點，牆桑亞戟枝。", "柴荆掩春夢，誰見我行時。"]'),
('c0429bb7-5563-4948-9f91-ac701cc3c8f2','冬日','王安石','宋','宋诗','song-poetry','','[]','擾擾今非昔，漫漫夜復晨。',48,'全唐诗/poet.song.32000.json','["擾擾今非昔，漫漫夜復晨。", "風沙不貸客，雲日欲迷人。", "散髮愁邊老，開顔醉後春。", "轉思江海上，一洗白綸巾。"]'),
('ff8be57b-2e41-4100-a1b7-2f9c17b6ce22','壬辰寒食','王安石','宋','宋诗','song-poetry','','["\u5bd2\u98df\u8282", "\u601d\u4e61", "\u611f\u4f24"]','客思似楊柳，春風千萬條。',48,'全唐诗/poet.song.32000.json','["客思似楊柳，春風千萬條。", "更傾寒食淚，欲漲冶城潮。", "巾髮雪爭出，鏡顔朱早雕。", "未知軒冕樂，但欲老漁樵。"]'),
('5dca4d92-4dec-4866-b8b9-f03d5a47d0e2','雨中','王安石','宋','宋诗','song-poetry','','[]','尚疑櫻欲吐，已怪菊成漂。',48,'全唐诗/poet.song.32000.json','["尚疑櫻欲吐，已怪菊成漂。", "紫莧凌風怯，青苔挾雨驕。", "長閑故有味，多難自無聊。", "牢落柴荆晚，生涯付一瓢。"]'),
('82541564-96af-427d-a37f-21285538e263','宿雨','王安石','宋','宋诗','song-poetry','','[]','綠攪寒蕪出，紅爭暖樹歸。',48,'全唐诗/poet.song.32000.json','["綠攪寒蕪出，紅爭暖樹歸。", "魚吹塘水動，雁拂塞垣飛。", "宿雨驚沙盡，晴雲晝漏稀。", "却愁春夢短，燈火著征衣。"]'),
('87ab6c01-afa2-4f0c-a0e1-2ebe2b5e918e','乘日','王安石','宋','宋诗','song-poetry','','[]','乘日塞垣入，御風塘路歸。',48,'全唐诗/poet.song.32000.json','["乘日塞垣入，御風塘路歸。", "胡皆躍馬去，雁却背人飛。", "煙水吾鄉似，家書驛使稀。", "匆匆照顔色，恨不洗征衣。"]'),
('8680a7e2-a340-44f4-a1e4-67834338d3c5','秋露','王安石','宋','宋诗','song-poetry','','[]','日月凋何急，荒庭露送秋。',48,'全唐诗/poet.song.32000.json','["日月凋何急，荒庭露送秋。", "初疑宿雨泫，稍怪曉霜稠。", "曠野將馳獵，華堂已御裘。", "空令半夜鶴，抱此一端愁。"]'),
('b15a03a8-78e2-4b8c-9908-b9b15d2fb560','還自河北應客','王安石','宋','宋诗','song-poetry','','[]','愧客問謠俗，舊傳今自如。',48,'全唐诗/poet.song.32000.json','["愧客問謠俗，舊傳今自如。", "材難知驥馬，味美賽河魚。", "塞水移民久，川防動衆初。", "北人雖異論，時議或非疏。"]'),
('fa6d2c7e-6a87-4c11-b7f9-2ceba1ad27cb','將次洺州憩漳上','王安石','宋','宋诗','song-poetry','','[]','漠漠春風裏，茸茸綠未齊。',48,'全唐诗/poet.song.32000.json','["漠漠春風裏，茸茸綠未齊。", "平田鴉散啄，深樹馬迎嘶。", "地入河流曲，天隨日去低。", "高城已在眼，聊復解輕齎。"]'),
('636afbc0-045e-4dcd-a2fa-3931dc1b0f57','和仲庶夜過新開湖憶沖之仲涂共泛','王安石','宋','宋诗','song-poetry','','[]','水遠浮秋色，河空洗夜氛。',48,'全唐诗/poet.song.32000.json','["水遠浮秋色，河空洗夜氛。", "行隨一明月，坐失兩孤雲。", "露髮此時濕，風顔何處醺。", "淹留各有趣，不比漢三君。"]'),
('731b4a0d-ada2-49b4-97a4-4ed8b28dfaf4','送契丹使還次韵答浄因老','王安石','宋','宋诗','song-poetry','','[]','老欲求吾志，時方摭我華。',48,'全唐诗/poet.song.32000.json','["老欲求吾志，時方摭我華。", "强將愁出塞，空得病還家。", "日轉山河暖，風含草木葩。", "勝遊思一往，不敢問三車。"]'),
('40c23f61-120b-4465-b47c-9f643fb6f082','送吳叔開南征','王安石','宋','宋诗','song-poetry','','[]','摻袂不勝情，犀舟擊汰行。',48,'全唐诗/poet.song.32000.json','["摻袂不勝情，犀舟擊汰行。", "倦遊無萬里，惜別有千名。", "春草凄凄綠，江楓湛湛清。", "金陵多麗景，此去屬蘭成。"]'),
('6518ad4c-dfad-4ff5-b5b0-7d9b3678c562','遊棲霞庵約平甫至因寄','王安石','宋','宋诗','song-poetry','','[]','渺渺林間路，蕭蕭物外僧。',48,'全唐诗/poet.song.32000.json','["渺渺林間路，蕭蕭物外僧。", "高陰凉易入，閑貌老難增。", "官事真傷錦，君恩更飲冰。", "求田此山下，終欲忤陳登。"]'),
('0ea55b8a-400e-4e76-8e01-28091f812004','和棲霞寂照庵僧雲渺','王安石','宋','宋诗','song-poetry','','[]','蕭然一世外，所樂有誰同。',48,'全唐诗/poet.song.32000.json','["蕭然一世外，所樂有誰同。", "宴坐能忘老，齋蔬不過中。", "無心爲佛事，有客問家風。", "笑謂西來意，雖空亦不空。"]'),
('5b011d2b-bb11-4a26-b224-9a37902de70a','宜春苑','王安石','宋','宋诗','song-poetry','','[]','宜春舊臺沼，日暮一登臨。',48,'全唐诗/poet.song.32000.json','["宜春舊臺沼，日暮一登臨。", "解带行蒼蘚，移𩌅坐綠陰。", "樹疏啼鳥遠，水靜落花深。", "無復增修事，君王惜費金。"]'),
('0181c2fe-89cf-43be-9f28-d3a2bb03adad','春日','王安石','宋','宋诗','song-poetry','','[]','冉冉春行暮，菲菲物競華。',48,'全唐诗/poet.song.32000.json','["冉冉春行暮，菲菲物競華。", "鶑猶求舊友，雁不背貧家。", "室有賢人酒，門無長者車。", "醉眠聊自適，歸夢到天涯。"]'),
('044554df-7406-413e-b522-a2bc8b63ccb7','癸卯追感正月十五事','王安石','宋','宋诗','song-poetry','','[]','正月端門夜，金輿縹緲中。',48,'全唐诗/poet.song.32000.json','["正月端門夜，金輿縹緲中。", "傳觴三鼓罷，縱觀萬人同。", "警蹕聲如在，嬉遊事已空。", "但令千載後，追咏太平功。"]'),
('a1b3062f-2296-43df-9a2e-d8343c376c46','晚興和沖卿學士','王安石','宋','宋诗','song-poetry','','[]','剡剡風生晚，娟娟月上初。',48,'全唐诗/poet.song.32000.json','["剡剡風生晚，娟娟月上初。", "白沙眠騄驥，清浪浴鱏魚。", "竟欲從君飲，猶便讀我書。", "斜陽不到處，牆角樹扶疏。"]'),
('deb0a1ff-ba66-4927-bf84-ebc3f9580b90','秋興和沖卿','王安石','宋','宋诗','song-poetry','','[]','雲浮朝慘淡，風起夜颼飀。',48,'全唐诗/poet.song.32000.json','["雲浮朝慘淡，風起夜颼飀。", "欲作冰霜地，先迴草樹秋。", "征人倚笛怨，思婦向砧愁。", "爲問隨陽雁，哀鳴豈有求。"]'),
('df2fcfb2-8517-4f8a-8ba0-8cd38ea941bd','次韵沖卿除日立春','王安石','宋','宋诗','song-poetry','','[]','猶殘一日臘，併見兩年春。',48,'全唐诗/poet.song.32000.json','["猶殘一日臘，併見兩年春。", "物以終爲始，人從故得新。", "迎陽朝翦綵，守歲夜傾銀。", "恩賜隨嘉節，無功祗自塵。"]'),
('ebeddc4e-39b1-4fcf-821e-aab1948c5824','題友人郊居水軒','王安石','宋','宋诗','song-poetry','','[]','田中三畝宅，水上一軒開。',48,'全唐诗/poet.song.32000.json','["田中三畝宅，水上一軒開。", "爲有漁樵樂，非無仕進媒。", "槎頭收晚釣，荷葉卷新醅。", "坐說魚腴美，功名挽不來。"]'),
('badf7fca-dd81-4f54-8094-008cd166e806','遊賞心亭寄虔州女弟','王安石','宋','宋诗','song-poetry','','[]','秀發千峰霽，清涵萬里秋。',48,'全唐诗/poet.song.32000.json','["秀發千峰霽，清涵萬里秋。", "滄江天上落，明月鏡中流。", "眼與魂俱斷，身依影獨留。", "爲憐幽興極，不見爾來遊。"]'),
('999804f5-f44d-4089-85ee-97df95fea6ad','江亭晚眺','王安石','宋','宋诗','song-poetry','','[]','日下崦嵫外，秋生沆碭閒。',48,'全唐诗/poet.song.32000.json','["日下崦嵫外，秋生沆碭閒。", "清江無限好，白鳥不勝閑。", "雨過雲收嶺，天空月上灣。", "歸鞍侵調角，回首六朝山。"]'),
('302ddf6b-e419-48f8-b1dc-9afcdb2f1c68','金山寺','王安石','宋','宋诗','song-poetry','','[]','重經高處寺，一與白雲親。',48,'全唐诗/poet.song.32000.json','["重經高處寺，一與白雲親。", "樹木有春意，江山如故人。", "幽軒含氣象，偏影落風塵。", "日暮臨歸去，徘徊欲損神。"]'),
('2c4ffbcd-a648-4dae-bc53-a2aa03e8a029','揖仙閣','王安石','宋','宋诗','song-poetry','','[]','結閣揖仙子，疏塘臨隠扉。',48,'全唐诗/poet.song.32000.json','["結閣揖仙子，疏塘臨隠扉。", "水花紅四出，山竹翠相圍。", "雲度疑軿下，鳬驚恐舄飛。", "蜀薑寧可恃，投釣此忘歸。"]'),
('596ef4bb-585c-405f-8ea2-0f90ae0eb0c8','舟夜即事','王安石','宋','宋诗','song-poetry','','[]','火炬臨遥岸，餘光照客船。',48,'全唐诗/poet.song.32000.json','["火炬臨遥岸，餘光照客船。", "水明魚中餌，沙暖鷺忘眠。", "感概無窮事，遲回欲曉天。", "山泉如有意，枕上送潺湲。"]'),
('69627a73-d095-49e5-9ffb-094b3dc31d7f','何處難忘酒二首  其一','王安石','宋','宋诗','song-poetry','','[]','何處難忘酒，英雄失志秋。',48,'全唐诗/poet.song.32000.json','["何處難忘酒，英雄失志秋。", "廟堂生莽卓，巖谷死伊周。", "賦斂中原困，干戈四海愁。", "此時無一盞，難遣壯圖休。"]'),
('99260792-66de-41d8-8f16-6e81f9dc0722','何處難忘酒二首  其二','王安石','宋','宋诗','song-poetry','','[]','何處難忘酒，君臣會合時。',48,'全唐诗/poet.song.32000.json','["何處難忘酒，君臣會合時。", "深堂拱堯舜，密席坐皋夔。", "和氣襲萬物，歡聲連四夷。", "此時無一盞，真負鹿鳴詩。"]'),
('06bd1a9b-f9d3-4dc5-8c0b-85248e972299','送孫子高','王安石','宋','宋诗','song-poetry','','[]','蕩漾江南客，融怡席上珍。',48,'全唐诗/poet.song.32000.json','["蕩漾江南客，融怡席上珍。", "一樽相別酒，千里獨歸人。", "客路貧堪病，交情遠更親。", "自慚兒女意，失淚滴衣巾。"]'),
('60399f4b-46f1-4575-b989-68fc9a82a390','送董傳','王安石','宋','宋诗','song-poetry','','[]','悠悠隴頭水，日夜向西流。',48,'全唐诗/poet.song.32000.json','["悠悠隴頭水，日夜向西流。", "行路未云已，歸人空復愁。", "文章合用世，顔髮未驚秋。", "一聽秦聲罷，還來上國遊。"]'),
('ba3796b1-9d89-450e-bb13-e23d97ee1b60','寄深州晁同年','王安石','宋','宋诗','song-poetry','','[]','秀色歸荒隴，新聲換氄毛。',48,'全唐诗/poet.song.32000.json','["秀色歸荒隴，新聲換氄毛。", "日催花蕊急，雲避雁行高。", "駐馬旌旗暖，傳觴鼓吹豪。", "班春不知負，短髮爲君搔。"]'),
('aa9a9267-9bcd-43f9-b53a-ed80d80f5b79','白雲然師','王安石','宋','宋诗','song-poetry','','[]','白首一山中，形骸槁木同。',48,'全唐诗/poet.song.32000.json','["白首一山中，形骸槁木同。", "苔爭庵徑路，雲補衲穿空。", "塵土隨車轍，波濤信柂工。", "昏昏老南北，應謝此高風。"]'),
('bd1dfd3d-0e52-4582-82a2-a67f25987fa1','自白土村入北寺二首  其一','王安石','宋','宋诗','song-poetry','','[]','木杪田家出，城陰野逕分。',48,'全唐诗/poet.song.32000.json','["木杪田家出，城陰野逕分。", "溜渠行碧玉，畦稼卧黄雲。", "薄槿烟脂染，深荷水麝焚。", "夕陽人不見，雞鶩自成群。"]'),
('b2821454-5d51-4639-aa8c-6d0db243fb75','自白土村入北寺二首  其二','王安石','宋','宋诗','song-poetry','','[]','雨過百泉出，秋聲連衆山。',48,'全唐诗/poet.song.32000.json','["雨過百泉出，秋聲連衆山。", "獨尋飛鳥外，時渡亂流間。", "坐石偶成歇，看雲相與還。", "會須營一畝，長此聽潺湲。"]'),
('a65c67e3-97cc-4d37-ae3c-cf1aa081ec15','題朱郎中白都莊','王安石','宋','宋诗','song-poetry','','[]','蕭灑桐廬守，滄洲寄一廛。',48,'全唐诗/poet.song.32000.json','["蕭灑桐廬守，滄洲寄一廛。", "山光隔釣岸，江氣雜炊煙。", "藜杖聽鳴艣，籃輿看種田。", "明時須共理，此興在他年。"]'),
('04ef2dba-2a65-4e83-87cb-3a61b1ce4024','史教授獨善堂','王安石','宋','宋诗','song-poetry','','[]','湖海十年舊，林塘三畝餘。',48,'全唐诗/poet.song.32000.json','["湖海十年舊，林塘三畝餘。", "靜非談者隠，貧勝富人居。", "列鼎亦何有，幅巾聊自如。", "猶應不獨善，學子滿階除。"]'),
('10a4fe4c-20ca-4eea-873b-3f60b7a1e17f','寄福公道人','王安石','宋','宋诗','song-poetry','','[]','帝力護禪林，滄洲側布金。',48,'全唐诗/poet.song.32000.json','["帝力護禪林，滄洲側布金。", "樓依水月觀，門接海潮音。", "開士但軟語，遊人多苦吟。", "曾同方丈宿，燈火夜沉沉。"]'),
('8b5860b9-d2e6-4732-aae2-42adf1eadba2','身閑','王安石','宋','宋诗','song-poetry','','[]','身閑宜晚食，歲晏忌晨興。',48,'全唐诗/poet.song.32000.json','["身閑宜晚食，歲晏忌晨興。", "人自嘲便腹，吾方樂曲肱。", "睡蛇雖不去，夢虺已無憑。", "寄語中林客，思禪病未能。"]'),
('fed8e008-30a3-4185-88ff-f5dee7d075b4','還家','王安石','宋','宋诗','song-poetry','','[]','還家豈不樂，生事未應閑。',48,'全唐诗/poet.song.32000.json','["還家豈不樂，生事未應閑。", "朝日已復出，征鞍方更攀。", "傷心百道水，閡目萬重山。", "何以忘羈旅，翛然醉夢間。"]'),
('62162751-358e-42bb-8505-68daf325e1a4','題湯泉壁示諸子有欲閑之意','王安石','宋','宋诗','song-poetry','','[]','吟哦一水上，披寫衆峰間。',48,'全唐诗/poet.song.32000.json','["吟哦一水上，披寫衆峰間。", "偶運非彭澤，留名比峴山。", "君才今卨稷，家行古原顔。", "平世雖多士，安能易地閑。"]'),
('edfe4df4-62c8-4ebc-9fe3-1d4e2f82d7e2','和唐公舍人訪浄因','王安石','宋','宋诗','song-poetry','','[]','西城方外士，傳法自南華。',48,'全唐诗/poet.song.32000.json','["西城方外士，傳法自南華。", "高蹈玩一世，旁通兼數家。", "來遊仁者靜，傳咏正而葩。", "乘興何時再，還能託後車。"]'),
('8f698d0f-c1ef-4d36-bd84-06eb08f0b564','沂溪懷正之','王安石','宋','宋诗','song-poetry','','[]','故人何處所，天角浪漫漫。',48,'全唐诗/poet.song.32000.json','["故人何處所，天角浪漫漫。", "寂寞斷音驛，徘徊愁肺肝。", "世情紛可怪，旅况浩難安。", "願化東南鵠，高飛託羽翰。"]'),
('eef528fd-ee5a-43aa-97f2-d3594b4f6b69','答許秀才','王安石','宋','宋诗','song-poetry','','[]','高陽有才子，負笈求晨饘。',48,'全唐诗/poet.song.32000.json','["高陽有才子，負笈求晨饘。", "所趣少知者，其辭多慨然。", "樵妻竟謝絕，漂母嘗哀憐。", "尚友古之人，于今猶壯年。"]'),
('3afe5c62-2f69-409f-b925-ea239c3d1e29','次韵景仁雪霽','王安石','宋','宋诗','song-poetry','','[]','新聲生屋霤，殘點著垣衣。',48,'全唐诗/poet.song.32000.json','["新聲生屋霤，殘點著垣衣。", "委翳無多在，飄零不更飛。", "坳中餘宿潤，暖處自朝暉。", "稍見青青色，還從柳上歸。"]'),
('1e658aa9-f654-4c5c-8c3b-f11e9e95dbed','次韵范景仁二月五日夜風雪','王安石','宋','宋诗','song-poetry','','[]','何知此邂逅，談笑接清揚。',48,'全唐诗/poet.song.32000.json','["何知此邂逅，談笑接清揚。", "對雪知春淺，回燈惜夜長。", "密雲通炫晃，殘月墮冥茫。", "故有臨邛客，抽毫興未忘。"]'),
('29c1a714-33d0-444f-98de-1c8e2361fd13','次韵沖卿過睢陽','王安石','宋','宋诗','song-poetry','','[]','宮廟此神鄉，留親泊楚艎。',48,'全唐诗/poet.song.32000.json','["宮廟此神鄉，留親泊楚艎。", "天開今壯麗，地積古悲凉。", "不改山河舊，猶餘草木荒。", "還聞足賓客，誰是漢鄒陽。"]'),
('97fbe029-a598-4672-b226-e9e67d0eee21','答沖卿','王安石','宋','宋诗','song-poetry','','[]','風作九衢黄，南窗坐正凉。',48,'全唐诗/poet.song.32000.json','["風作九衢黄，南窗坐正凉。", "破瓜青玉美，浮荈白雲香。", "詩懶猶能强，官閑肯便忘。", "賢愚各有用，尺寸果誰長。"]'),
('b2abeb4e-0cdf-4217-ac26-d0643987ff6e','得書知二弟附陳師道舟上汴','王安石','宋','宋诗','song-poetry','','[]','兒童聞太丘，邂逅兩心投。',48,'全唐诗/poet.song.32000.json','["兒童聞太丘，邂逅兩心投。", "與汝今爲伴，知吾不復憂。", "園桃已解萼，沙水欲驚舟。", "一見南飛雁，江邊肯更留。"]'),
('3a1954f7-7cd4-4cb6-a290-b15bb1291666','初憩和州','王安石','宋','宋诗','song-poetry','','[]','衣足一囊弊，粟餘三釜陳。',48,'全唐诗/poet.song.32000.json','["衣足一囊弊，粟餘三釜陳。", "猶依食貧地，已愧省煩人。", "塵土病催老，風波愁過春。", "詩書今在眼，還欲討經綸。"]'),
('51dd61d7-dc4b-471d-8e54-b54892337b2e','瘧起舍弟尚未已示道原','王安石','宋','宋诗','song-poetry','','[]','側足呻吟地，連甍瘴瘧秋。',48,'全唐诗/poet.song.32000.json','["側足呻吟地，連甍瘴瘧秋。", "窮鄉醫自絀，小市藥難求。", "肝膽疑俱破，筋骸漫獨瘳。", "慚君遠從我，契闊每同憂。"]'),
('cef671b5-fa04-4d0f-8ecf-a7c6c731aa38','送杜十八之廣南','王安石','宋','宋诗','song-poetry','','[]','東南炎海外，尋訪又輸君。',48,'全唐诗/poet.song.32000.json','["東南炎海外，尋訪又輸君。", "過嶺猿啼暖，貪程馬送曛。", "清談消瘴癘，秀句起煙雲。", "及早來鄉薦，朝廷尚右文。"]'),
('78817778-f1d4-424e-9dbf-89a785a4bb69','崑山慧聚寺次張祜韵','王安石','宋','宋诗','song-poetry','','[]','峰嶺互出沒，江湖相吐吞。',48,'全唐诗/poet.song.32000.json','["峰嶺互出沒，江湖相吐吞。", "園林浮海角，臺殿擁山根。", "百里見漁艇，萬家藏水村。", "地偏來客少，幽興秪桑門。"]'),
('359c4035-9384-4dc0-929f-cb360f8c8b32','吳江','王安石','宋','宋诗','song-poetry','','[]','莽莽昔登臨，秋風一散襟。',48,'全唐诗/poet.song.32000.json','["莽莽昔登臨，秋風一散襟。", "地留孤嶼小，天入五湖深。", "柑橘無千里，魚蝦有萬金。", "吾雖輕范蠡，終欲此幽尋。"]'),
('3605c972-ff29-4dd4-8eb5-70a03b21ef5e','江','王安石','宋','宋诗','song-poetry','','[]','靈源開闢有，贏縮但相隨。',48,'全唐诗/poet.song.32000.json','["靈源開闢有，贏縮但相隨。", "逆折山能礙，奔流海與期。", "泥沙拆蚌蛤，雲南暗蛟螭。", "欲問深何許，馮夷秖自知。"]'),
('848a6e70-a5c1-451e-8c53-baa94b20ebdb','江南','王安石','宋','宋诗','song-poetry','','[]','江南春起柂，秋至尚波濤。',48,'全唐诗/poet.song.32000.json','["江南春起柂，秋至尚波濤。", "問舍才能定，呼舟已復操。", "行歌付浩蕩，歸夢得蕭騷。", "冉冉欲何補，紛紛爲此勞。"]'),
('ff8c7efe-38fb-44b1-a881-460f39570cf9','賈生','王安石','宋','宋诗','song-poetry','','[]','漢有洛陽子，少年明是非。',48,'全唐诗/poet.song.32000.json','["漢有洛陽子，少年明是非。", "所論多感概，自信肯依違。", "死者若可作，今人誰與歸。", "應須蹈東海，不但涕沾衣。"]'),
('7b34add3-e222-4455-a9e6-76f2dd907729','還自舅家書所感','王安石','宋','宋诗','song-poetry','','[]','行行過舅居，歸路指親廬。',48,'全唐诗/poet.song.32000.json','["行行過舅居，歸路指親廬。", "日苦樹無頼，天空雲自如。", "黄焦下澤稻，綠碎短樊蔬。", "沮溺非吾意，憫嗟聊駐車。"]'),
('81193af7-7d21-45c3-aeee-29bd122c4632','世事','王安石','宋','宋诗','song-poetry','','[]','世事一何稠，論心日已偷。',48,'全唐诗/poet.song.32000.json','["世事一何稠，論心日已偷。", "尚蒙今士笑，宜見古人羞。", "老圃聊須問，良田亦欲求。", "非關畏黻冕，無責易身修。"]'),
('a87ba162-b3dd-4d8d-b62d-ec2ea1bee6fd','寄純甫','王安石','宋','宋诗','song-poetry','','[]','塞上無花草，飄風急我歸。',48,'全唐诗/poet.song.32000.json','["塞上無花草，飄風急我歸。", "梢林聽澗落，卷土看雲飛。", "想子當紅蕊，思家上翠微。", "江寒亦未已，好好著春衣。"]'),
('ca0d63fb-808e-4b27-8360-7234d1c9b955','招丁元珍','王安石','宋','宋诗','song-poetry','','[]','默默不自得，紛紛何所爲。',48,'全唐诗/poet.song.32000.json','["默默不自得，紛紛何所爲。", "畫墁聊取食，獵較且隨時。", "秋入江湖暗，風生草樹悲。", "黄花一杯酒，思與故人持。"]'),
('bb1b7066-f662-4b08-83df-99512e15e9d9','遊杭州聖果寺','王安石','宋','宋诗','song-poetry','','[]','登高見山水，身在水中央。',48,'全唐诗/poet.song.32000.json','["登高見山水，身在水中央。", "下視樓臺處，空多樹木蒼。", "浮雲連海氣，落日動湖光。", "偶坐吹橫笛，殘聲入富陽。"]'),
('1b03ed07-4f59-490f-9426-6e328cd05f62','京兆杜嬰大醇能讀書其言近莊其爲人曠達而廉清自託於醫無貴賤請之輒往卒也以詩二首傷之  其一','王安石','宋','宋诗','song-poetry','','[]','蕭瑟野衣巾，能忘至老貧。',48,'全唐诗/poet.song.32000.json','["蕭瑟野衣巾，能忘至老貧。", "避囂依市井，蒙垢出埃塵。", "接物工齊物，勞身耻爲身。", "傷心宿昔地，不復見斯人。"]'),
('fea12082-33a6-428c-ad8a-d0e1b73496de','京兆杜嬰大醇能讀書其言近莊其爲人曠達而廉清自託於醫無貴賤請之輒往卒也以詩二首傷之  其二','王安石','宋','宋诗','song-poetry','','[]','叔度醫家子，君平卜肆翁。',48,'全唐诗/poet.song.32000.json','["叔度醫家子，君平卜肆翁。", "蕭條昨日事，彷彿古人風。", "舊宅雨生菌，新阡寒轉蓬。", "存亡誰一問，嗟我亦窮空。"]'),
('687216ab-7d77-469d-96d2-3386c34d1260','江上二首  其一','王安石','宋','宋诗','song-poetry','','[]','潮連風浩蕩，沙引客淹留。',48,'全唐诗/poet.song.32000.json','["潮連風浩蕩，沙引客淹留。", "落日更清坐，空江無近舟。", "共看蒹葦宅，聊即稻粱謀。", "未敢嗟艱食，凶年半九州。"]'),
('125654a2-6493-4f42-8fe2-d94e8316b5c9','江上二首  其二','王安石','宋','宋诗','song-poetry','','[]','書自江邊使，鄉鄰病餓稠。',48,'全唐诗/poet.song.32000.json','["書自江邊使，鄉鄰病餓稠。", "何言萬里客，更作百身憂。", "補敗今誰卹，趨生我自羞。", "西南雙病眼，落日倚扁舟。"]'),
('fc4d0cb2-0865-4035-82fd-45dcd74fdb37','夏夜舟中頗凉因有所感','王安石','宋','宋诗','song-poetry','','[]','扁舟畏朝熱，望夜倚桅檣。',48,'全唐诗/poet.song.32000.json','["扁舟畏朝熱，望夜倚桅檣。", "日共火雲退，風兼水氣凉。", "未秋輕病骨，微曙浣愁腸。", "堅我江湖意，滔滔興不忘。"]'),
('399539bc-8106-448d-a797-9f52d1676121','孤桐','王安石','宋','宋诗','song-poetry','','[]','天質自森森，孤高幾百尋。',48,'全唐诗/poet.song.32000.json','["天質自森森，孤高幾百尋。", "陵霄不屈己，得地本虛心。", "歲老根彌壯，陽驕葉更陰。", "明時思解慍，願斲五絃琴。"]'),
('2c8ce940-c9b0-4196-9464-957d061f0988','遲明','王安石','宋','宋诗','song-poetry','','[]','欹枕浩無情，蘧蘧獨遲明。',48,'全唐诗/poet.song.32000.json','["欹枕浩無情，蘧蘧獨遲明。", "霜繁紅樹老，雲澹素蟾清。", "倦鵲猶三帀，寒鷄未一鳴。", "故山何處所，應有曉猿驚。"]'),
('1ea94455-2c15-4e7c-ba0e-68952f527953','陪友人中秋夕賞月','王安石','宋','宋诗','song-poetry','','[]','海霧看如洗，秋陽望却昏。',48,'全唐诗/poet.song.32000.json','["海霧看如洗，秋陽望却昏。", "光明疑不夜，清瑩欲無坤。", "掃掠風前坐，留連露下尊。", "苦吟應到曉，况有我思存。"]'),
('7168903c-c0f8-4a71-a45b-6af9809c3511','慎縣修路者','王安石','宋','宋诗','song-poetry','','[]','畚築今三歲，康莊始一修。',48,'全唐诗/poet.song.32000.json','["畚築今三歲，康莊始一修。", "何言野人意，能助令君憂。", "勠力非無補，論心豈有求。", "十年空志食，因汝起予羞。"]'),
('4e7e5e5c-d163-4081-846a-c9d76051085e','河勢','王安石','宋','宋诗','song-poetry','','[]','河勢浩難測，禹功傳所聞。',48,'全唐诗/poet.song.32000.json','["河勢浩難測，禹功傳所聞。", "今觀一川破，復以二渠分。", "國論終將塞，民嗟亦已勤。", "無災等難必，從衆在吾君。"]'),
('dd015f50-0ab2-4d9b-8077-12a5a661e11f','送河間晁寺丞','王安石','宋','宋诗','song-poetry','','[]','公孫富文墨，名字世多知。',48,'全唐诗/poet.song.32000.json','["公孫富文墨，名字世多知。", "談笑取高第，弦歌當此時。", "臨河薪石費，近塞繭絲移。", "緩急常愁此，看君有所爲。"]'),
('78474391-500d-4b59-864c-4adc646b4c92','暮春','王安石','宋','宋诗','song-poetry','','[]','春期行晼晚，春意剩芳菲。',48,'全唐诗/poet.song.32000.json','["春期行晼晚，春意剩芳菲。", "曲水應修禊，披香未試衣。", "雨花紅半墮，煙樹碧相依。", "悵望夢中地，王孫底不歸。"]'),
('08397d8b-3079-4ced-97ea-f88319de5c68','遊北山','王安石','宋','宋诗','song-poetry','','[]','攬轡出東城，登臨目暫明。',48,'全唐诗/poet.song.32000.json','["攬轡出東城，登臨目暫明。", "煙雲藏古意，猿鶴弄秋聲。", "客坐苔紋滑，僧眠樾蔭清。", "賞心殊未已，山日下西榮。"]'),
('188046b2-868b-47b7-af89-8228215a8bce','吳正仲謫官得故人寄蟹以詩謝之余次其韵','王安石','宋','宋诗','song-poetry','','[]','越客上荆舠，秋風憶把螯。',48,'全唐诗/poet.song.32000.json','["越客上荆舠，秋風憶把螯。", "故煩分巨跪，持用佐清糟。", "飲量寬滄海，詩鋒捷孟勞。", "甘餐飽觴咏，餘事付鈞陶。"]'),
('2523005d-3cad-417e-b20b-5392f998d058','陳師道宰烏程縣','王安石','宋','宋诗','song-poetry','','[]','嘗聞太丘長，德不負公卿。',48,'全唐诗/poet.song.32000.json','["嘗聞太丘長，德不負公卿。", "墟墓今千載，昆雲亦一城。", "本懷深閉蓄，餘論略施行。", "故自有仁政，能傳家世聲。"]'),
('7de25fa2-5757-497a-aaf2-58a5c8e28be6','冬至','王安石','宋','宋诗','song-poetry','','[]','都城開博路，佳節一陽生。',48,'全唐诗/poet.song.32000.json','["都城開博路，佳節一陽生。", "喜見兒童色，歡傳市井聲。", "幽閑亦聚集，珍麗各携擎。", "却憶他年事，關商閉不行。"]'),
('8e56072c-4c8a-4d71-b759-c6b6615fb677','湯泉','王安石','宋','宋诗','song-poetry','','[]','寒泉詩所咏，獨此沸如烝。',48,'全唐诗/poet.song.32000.json','["寒泉詩所咏，獨此沸如烝。", "一氣無冬夏，諸陽自廢興。", "人游不附火，蟲出亦疑冰。", "更憶驪山下，歊然雪滿塍。"]'),
('ede83c8d-a64c-47d3-927b-cf024b8c3b7e','讀鎮南邸報癸未四月作','王安石','宋','宋诗','song-poetry','','[]','賜詔寬言路，登賢壯陛廉。',48,'全唐诗/poet.song.32000.json','["賜詔寬言路，登賢壯陛廉。", "相期正在治，素定不煩占。", "衆喜夔龍盛，予虞絳灌憸。", "太平詎可致，天意慎猜嫌。"]'),
('42a8338c-4370-4838-9032-e15f18844ce9','擬和御製賞花釣魚','王安石','宋','宋诗','song-poetry','','[]','雲暖蓬萊日，風酣太液春。',72,'全唐诗/poet.song.32000.json','["雲暖蓬萊日，風酣太液春。", "水光承步輦，花氣入鈎陳。", "伏檻留清蹕，傳觴屬從臣。", "霏香連釣餌，落葉亂游鱗。", "鎬飲恩知厚，衢樽賜願均。", "更看追夏諺，先此咏逢辰。"]'),
('ce5deb75-dd6e-4608-ad54-e759d0ad1c4a','和吳沖卿雪霽紫宸朝','王安石','宋','宋诗','song-poetry','','[]','虎士開閶闔，雞人唱九霄。',72,'全唐诗/poet.song.32000.json','["虎士開閶闔，雞人唱九霄。", "雲移銀闕角，日轉玉廊腰。", "箒動川收潦，靴鳴海上潮。", "舞袍沾宿潤，拜笏擁殘飄。", "賜飲人何樂，歸嘶馬亦驕。", "低徊但忘食，吟咏得逍遥。"]'),
('4865d4ed-883a-4d8f-9451-1e88f0ad3b3f','和吳沖卿集禧齋祠','王安石','宋','宋诗','song-poetry','','[]','緘封祝辭密，占寫御名真。',72,'全唐诗/poet.song.32000.json','["緘封祝辭密，占寫御名真。", "帝坐遥臨物，星圖俯映人。", "風含煙外節，月點霧中茵。", "沈藿升煙遠，槐檀取燎新。", "羽衣歸寂寞，金鎪立逡巡。", "却想來時路，還疑隔一塵。"]'),
('d68b1187-8ce4-4e80-8882-c6c05e4e9dd2','送周都官通判湖州','王安石','宋','宋诗','song-poetry','','[]','淥水烏程地，青山顧渚濱。',72,'全唐诗/poet.song.32000.json','["淥水烏程地，青山顧渚濱。", "酒醪猶美好，茶荈正芳新。", "聚泛樽前月，分班焙上春。", "仁風已入俗，樂事始關身。", "橘柚供南貢，楓槐望北宸。", "知君白羽扇，歸日未生塵。"]'),
('6b9565d5-90bf-4ee6-ad52-44d2fd3531ef','雙廟','王安石','宋','宋诗','song-poetry','','[]','兩公天下駿，無地與騰驤。',72,'全唐诗/poet.song.32000.json','["兩公天下駿，無地與騰驤。", "就死得處所，至今猶耿光。", "中原擅兵革，昔日幾侯王。", "此獨身如在，誰令國不亡。", "北風吹樹急，西日照窗凉。", "志士千年淚，泠然落奠觴。"]'),
('b5120845-666e-4382-a9cd-2b012f7ad9b1','和子瞻同王勝之游蔣山','王安石','宋','宋诗','song-poetry','','[]','金陵限南北，形勢豈其然。',120,'全唐诗/poet.song.32000.json','["金陵限南北，形勢豈其然。", "楚役六千里，陳亡三百年。", "江山空幕府，風月自觥船。", "主送悲凉岸，妃埋想故蓮。", "臺傾鳳久去，城踞虎爭偏。", "司馬壖廟域，獨龍層塔顛。", "森疏五願木，蹇淺一人泉。", "棁杖窮諸嶺，籃輿罷半天。", "朱門園淥水，碧瓦第青煙。", "墨客真能賦，留詩野竹娟。"]'),
('cef94a5d-685a-41c7-afb3-4da8da58dc34','送鄆州知府宋諫議','王安石','宋','宋诗','song-poetry','','[]','盛世千齡合，宗工四海瞻。',240,'全唐诗/poet.song.32000.json','["盛世千齡合，宗工四海瞻。", "天心初籲俊，雲翼首離潛。", "德望完圭角，儀形壯陛廉。", "徐鳴蒼玉佩，盡校碧牙籤。", "綸掖清光注，鑾坡茂渥霑。", "文明誠得主，政瘼尚煩砭。", "右府參機務，東塗贊景炎。", "廟謨資石畫，兵略倚珠鈐。", "坐鎮均勞逸，齋居養智恬。", "謳謠喧井邑，惠化穆蒼黔。", "進律朝章舊，疏恩物議僉。", "通班三殿邃，徙部十城兼。", "申甫周之翰，龜蒙魯所詹。", "地靈奎宿照，野沃汶河漸。", "首路龍旗盛，提封虎節嚴。", "賜衣纏紫艾，衛甲綴朱綅。", "海谷移文省，溪堂燕豆添。", "班春回紺幰，問俗卷彤襜。", "舟檝商巖命，熊羆渭水占。", "治裝行入覲，金鼎重調鹽。"]'),
('477e5a00-8d5b-4a46-9ffc-924b63076047','見遠亭上王郎中','王安石','宋','宋诗','song-poetry','','[]','高亭豁可望，朝暮對溪山。',120,'全唐诗/poet.song.32000.json','["高亭豁可望，朝暮對溪山。", "野色軒楹外，霞光几席間。", "樹侵蒼靄沒，鳥背夕陽還。", "草带平沙闊，烟籠別戍閑。", "圃畦荷氣合，田徑燒痕斑。", "樵笛吟晴塢，漁帆出暝灣。", "登臨及芳節，宴喜發朱顔。", "夾砌陳旌旝，褰簾進佩環。", "觀風南國最，應宿紫宸班。", "康樂詩名舊，蕪音詎可攀。"]'),
('cf818387-6e93-41be-8487-403b3604116d','歲晚懷古','王安石','宋','宋诗','song-poetry','','[]','先生歲晚事田園，魯叟遺書廢討論。',64,'全唐诗/poet.song.32000.json','["先生歲晚事田園，魯叟遺書廢討論。", "問訊桑麻憐已長，按行松菊喜猶存。", "農人調笑追尋壑，稚子歡呼出候門。", "遥謝載醪袪惑者，吾今欲辯已忘言。"]'),
('f0101b08-7bc2-4a04-9f70-e4b58438afaf','段約之園亭','王安石','宋','宋诗','song-poetry','','[]','愛公池館得忘機，初日留連至落暉。',64,'全唐诗/poet.song.32000.json','["愛公池館得忘機，初日留連至落暉。", "菱暖紫鱗跳復沒，柳陰黄鳥囀還飛。", "徑無凡草唯生竹，盤有嘉蔬不采薇。", "勝事閬州雖或有，終非吾土豈如歸。"]'),
('866dcc3c-22da-4d32-8f30-9c7080eb52f7','又段氏園亭','王安石','宋','宋诗','song-poetry','','[]','欹眠隨水轉東垣，一點炊煙映水昏。',64,'全唐诗/poet.song.32000.json','["欹眠隨水轉東垣，一點炊煙映水昏。", "漫漫芙蕖難覓路，翛翛楊柳獨知門。", "青山呈露新如染，白鳥嬉游靜不煩。", "朱雀航邊今有此，可能摇蕩武陵源。"]'),
('810c74f4-6ff0-4d31-a7c2-f20a661ab5d5','回橈','王安石','宋','宋诗','song-poetry','','[]','柴荆散策靜凉飈，隠几扁舟白下潮。',64,'全唐诗/poet.song.32000.json','["柴荆散策靜凉飈，隠几扁舟白下潮。", "紫磨月輪升靄靄，帝青雲幕卷寥寥。", "數家鷄犬如相識，一塢山林特見招。", "尚憶木瓜園最好，興殘中路且回橈。"]'),
('e2091f17-f3e4-48bf-84d6-a0c01dfcf76c','酴醿金沙二花合發','王安石','宋','宋诗','song-poetry','','[]','相扶照水弄春柔，發似矜夸歛似羞。',64,'全唐诗/poet.song.32000.json','["相扶照水弄春柔，發似矜夸歛似羞。", "碧合晚雲霞上起，紅爭朝日雪邊流。", "我無丹白知如夢，人有朱鉛見即愁。", "疑此冶容詩所忌，故將樛木比綢繆。"]'),
('f30bccac-f113-462e-9fe9-219e5df18375','次韵公闢正議書公戲語申之以祝助發一笑','王安石','宋','宋诗','song-poetry','','[]','故人辭祿未忘情，語我猶能作扞城。',64,'全唐诗/poet.song.32000.json','["故人辭祿未忘情，語我猶能作扞城。", "身不自遭如貢薛，兒應堪教比韋平。", "老羆豈得長高卧，雛鳳仍聞已閒生。", "把盞祝公公莫拒，緇衣心爲好賢傾。"]'),
('63d448ab-7b34-44d0-bcfa-29e169b841bd','次韵致遠木人洲二首  其一','王安石','宋','宋诗','song-poetry','','[]','迷子山前漲一洲，木人圖志失編收。',64,'全唐诗/poet.song.32000.json','["迷子山前漲一洲，木人圖志失編收。", "年多但有柳生肘，地僻獨無茅蓋頭。", "河側鮑生乾尚立，江邊屈子槁將投。", "未妨他日稱居士，能使君疑福可求。"]'),
('a04f960f-1d8f-4a3c-8eea-056b40afbb34','次韵致遠木人洲二首  其二','王安石','宋','宋诗','song-poetry','','[]','杌爾何年客此洲，飄流誰棄止誰收。',64,'全唐诗/poet.song.32000.json','["杌爾何年客此洲，飄流誰棄止誰收。", "無心使口肝使目，有幹作身根作頭。", "暴露神靈難寄託，禱祠村落幾依投。", "紛紛翦紙真虛負，立槁安知富可求。"]'),
('c7fdbae0-01c1-465a-a265-102ee126d906','次韵酬龔深甫二首  其一','王安石','宋','宋诗','song-poetry','','[]','恩容楚老護松楸，復得一龔從我遊。',64,'全唐诗/poet.song.32000.json','["恩容楚老護松楸，復得一龔從我遊。", "講肄劇談兼祖謝，舞雩高蹈異求由。", "北尋五柞故未憖，東挽三楊仍有樛。", "陟巘降原從此始，但無瑶玉與君舟。"]'),
('5f289357-3cb4-4b3c-8c0d-7f23e0771b80','次韵酬龔深甫二首  其二','王安石','宋','宋诗','song-poetry','','[]','握手東岡雪滿簪，後期惆悵老吳蠶。',64,'全唐诗/poet.song.32000.json','["握手東岡雪滿簪，後期惆悵老吳蠶。", "芳辰一笑真難值，暮齒相思豈久堪。", "他日杜詩傳渭北，幾時周宅對漳南。", "百年邂逅能多少，且可勤來共草菴。"]'),
('ad42125a-9bbb-40c6-ab32-41aacccd53a4','次葉致遠韵','王安石','宋','宋诗','song-poetry','','[]','生涯聊占水中洲，豈即乘桴逐聖丘。',64,'全唐诗/poet.song.32000.json','["生涯聊占水中洲，豈即乘桴逐聖丘。", "身與鳬飛仍雁集，心能茅靡亦波流。", "由來杞梓常先伐，誰謂菰蒲可久留。", "乘興吾廬知未厭，故移脩竹擬延騶。"]'),
('97d47331-1698-4edc-bebe-7a549a59de04','次韵酬朱昌叔五首  其一','王安石','宋','宋诗','song-poetry','','[]','點也自殊由與求，既成春服更何憂。',64,'全唐诗/poet.song.32000.json','["點也自殊由與求，既成春服更何憂。", "拙於人合且天合，靜與道謀非食謀。", "未愛京師傳谷口，但知鄉里勝壺頭。", "嗟予老矣無一事，復得此君相與遊。"]'),
('05c88c92-9067-4be1-9d9b-cc6276167a78','次韵酬朱昌叔五首  其二','王安石','宋','宋诗','song-poetry','','[]','去年音問隔淮州，百謫難知亦我憂。',64,'全唐诗/poet.song.32000.json','["去年音問隔淮州，百謫難知亦我憂。", "前日杯盤共江渚，一歡相屬豈人謀。", "山蟠直瀆輸淮口，水抱長干轉石頭。", "乘興舟輿無不可，春風從此與公遊。"]'),
('b1cb43bb-80aa-419c-9c2b-1cbd291a8d10','次韵酬朱昌叔五首  其三','王安石','宋','宋诗','song-poetry','','[]','烏榜登臨興未休，共言何許更消憂。',64,'全唐诗/poet.song.32000.json','["烏榜登臨興未休，共言何許更消憂。", "聯裾蕭寺尋真覺，方駕孫陵弔仲謀。", "語罷每開歡笑口，詩來仍掉苦吟頭。", "已知軒冕真吾累，且可追隨馬少游。"]'),
('3f1eb1b8-5ef8-4642-b084-46dcca9554ee','次韵酬朱昌叔五首  其四','王安石','宋','宋诗','song-poetry','','[]','白下門東春水流，相看一噱散千憂。',64,'全唐诗/poet.song.32000.json','["白下門東春水流，相看一噱散千憂。", "穿梅入柳曾莫逆，度壍緣岡初不謀。", "世事但如吹劍首，官身難即問刀頭。", "長臨鍛竈真自苦，有興復來從我遊。"]'),
('0d769a5c-86e8-4f2a-bfe2-4bc444e745b3','次韵酬朱昌叔五首  其五','王安石','宋','宋诗','song-poetry','','[]','樂世閑身豈易求，巖居川觀更何憂。',64,'全唐诗/poet.song.32000.json','["樂世閑身豈易求，巖居川觀更何憂。", "放懷自事如初服，買宅相招亦本謀。", "名譽子真矜谷口，事功新息困壺頭。", "知君於此皆無累，長得追隨壙埌遊。"]'),
('a32f40dd-42e8-44f2-b5e1-bbcbba30a1e0','次韵送程給事知越州','王安石','宋','宋诗','song-poetry','','[]','千騎東方占上頭，如何誤到北山遊。',64,'全唐诗/poet.song.32000.json','["千騎東方占上頭，如何誤到北山遊。", "清明若睹蘭亭月，暖熱因忘蕙帳秋。", "投老始知歡可惜，通宵豫以別爲憂。", "西歸定有詩千首，想肯重來賁一丘。"]'),
('7667d9d2-27f5-456a-9d00-e04a77368172','次韵酬徐仲元','王安石','宋','宋诗','song-poetry','','[]','投老逍遥屺與堂，天刑真已脫桁楊。',64,'全唐诗/poet.song.32000.json','["投老逍遥屺與堂，天刑真已脫桁楊。", "緣源靜翳無魚淰，度谷深追有鳥頏。", "每苦交游尋五柳，最嫌尸祝擾庚桑。", "相看不厭唯夫子，風味真如顧建康。"]'),
('0a96fb74-1caf-4ced-9d69-040568f51893','詩奉送覺之奉使東川','王安石','宋','宋诗','song-poetry','','[]','三秋不見每惓惓，握手山林復悵然。',64,'全唐诗/poet.song.32000.json','["三秋不見每惓惓，握手山林復悵然。", "後會敢期黄耉日，相看且度白鷄年。", "畏途石棧王尊馭，榮路金門祖逖鞭。", "一代官儀新藻拂，得瞻宸宇想留連。"]'),
('784f548e-d895-4769-b28b-278461fc1717','次韵奉酬覺之','王安石','宋','宋诗','song-poetry','','[]','久知乘傳入西州，雞黍從容本不謀。',64,'全唐诗/poet.song.32000.json','["久知乘傳入西州，雞黍從容本不謀。", "戶外驚塵尺書至，眼中飛浪片帆收。", "山林病骨煩三顧，湖海離腸欲萬周。", "尚有光華賁岑寂，篋中佳句得長留。"]'),
('6cafc3db-46a2-44c6-a64b-ed1b24070f26','送程公闢得謝歸姑蘇','王安石','宋','宋诗','song-poetry','','[]','東歸行路嘆賢哉，碧落新除寵上才。',64,'全唐诗/poet.song.32000.json','["東歸行路嘆賢哉，碧落新除寵上才。", "白傅林塘傳畫去，吳王花鳥入詩來。", "唱酬自有微之在，談笑應容逸少陪。", "除此兩翁相見外，不知三徑爲誰開。"]'),
('d4205a9a-b090-4424-bbba-d96a2f4c13ae','送項判官','王安石','宋','宋诗','song-poetry','','[]','斷蘆洲渚落楓橋，渡口沙長過午潮。',64,'全唐诗/poet.song.32000.json','["斷蘆洲渚落楓橋，渡口沙長過午潮。", "山鳥自呼泥滑滑，行人相對馬蕭蕭。", "十年長自青衿識，千里來非白璧招。", "握手祝君能强飯，華簪常得從雞翹。"]'),
('93f5543f-36bb-4132-b2e7-9989f20ba7f9','次韵張德甫奉議','王安石','宋','宋诗','song-poetry','','[]','知君非我載醪人，終日相隨免汙茵。',64,'全唐诗/poet.song.32000.json','["知君非我載醪人，終日相隨免汙茵。", "賞盡高山見流水，唱殘白雪值陽春。", "中分香積如來鉢，對現毗耶長者身。", "誰拂定林幽處壁，與君圖寫繼吾真。"]'),
('abc24111-0c44-4b57-9165-2c198730ed45','北山三咏 寶公塔','王安石','宋','宋诗','song-poetry','','[]','道林真骨葬青霄，窣堵千秋未寂寥。',64,'全唐诗/poet.song.32000.json','["道林真骨葬青霄，窣堵千秋未寂寥。", "寶勢旁連大江起，尊形獨受衆山朝。", "雲泉別寺分三徑，香火幽人止一瓢。", "我亦鷲峰同聽法，歲時歌唄豈辭遥。"]'),
('5dfa7778-bab4-4e6f-983c-f9786609a0c6','北山三咏 覺海方丈','王安石','宋','宋诗','song-poetry','','[]','往來城府住山林，諸法翛然但一音。',64,'全唐诗/poet.song.32000.json','["往來城府住山林，諸法翛然但一音。", "不與物違真道廣，每隨緣起自禪深。", "舌根已浄誰能壞，足迹如空我得尋。", "歲晚北窗聊寄傲，蒲萄零落半床陰。"]'),
('7d2d68a0-3302-4796-84a4-a7f957964682','北山三咏 道光泉','王安石','宋','宋诗','song-poetry','','[]','籜龍將雨繞山行，注遠投深靜有聲。',64,'全唐诗/poet.song.32000.json','["籜龍將雨繞山行，注遠投深靜有聲。", "雲涌浴槽朝自暖，虹垂齋鑊午還晴。", "銅瓶各滿幽人意，玉甃因高正士名。", "神力可嗟妨智巧，桔槔零落便苔生。"]'),
('de212090-0ee3-4a3e-adc7-279b45e7ca09','登寶公塔','王安石','宋','宋诗','song-poetry','','[]','倦童疲馬放松門，自把長筇倚石根。',64,'全唐诗/poet.song.32000.json','["倦童疲馬放松門，自把長筇倚石根。", "江月轉空爲白晝，嶺雲分暝與黄昏。", "鼠摇岑寂聲隨起，鴉矯荒寒影對翻。", "當此不知誰客主，道人忘我我忘言。"]'),
('af36fdb5-c2af-4c22-8a47-9c959965b644','重登寶公塔復用前韵二首  其一','王安石','宋','宋诗','song-poetry','','[]','空見方墳涌半霄，難將生死問參寥。',64,'全唐诗/poet.song.32000.json','["空見方墳涌半霄，難將生死問參寥。", "應身東返知何國，瑞像西歸自本朝。", "遺寺有門非輦路，故池無鉢但僧瓢。", "獨龍下視皆陳迹，追數齊梁亦未遥。"]'),
('a808cf5f-2038-44dd-862c-6cb210b94130','重登寶公塔復用前韵二首  其二','王安石','宋','宋诗','song-poetry','','[]','碧玉旋螺恍隔霄，冠山仙冢亦寥寥。',64,'全唐诗/poet.song.32000.json','["碧玉旋螺恍隔霄，冠山仙冢亦寥寥。", "空餘華構延風月，無復靈蹤落市朝。", "帳座追嚴多獻寶，供盤隨施有操瓢。", "他方出沒還如此，與物何心作邇遥。"]'),
('63cbf7f8-b12b-415f-85de-2996469b3d1e','紙暖閤','王安石','宋','宋诗','song-poetry','','[]','聯屏蓋障一尋方，南設鈎簾北置床。',64,'全唐诗/poet.song.32000.json','["聯屏蓋障一尋方，南設鈎簾北置床。", "側座對敷紅絮暖，仰窗分啟碧紗凉。", "氈廬易以梅烝壞，錦幄終於草野妨。", "楚穀越藤真自稱，每糊因得減書囊。"]'),
('803712f8-c16a-4dbc-a626-037c03c5d23f','雨花臺','王安石','宋','宋诗','song-poetry','','[]','盤互長干有絕陘，并包佳麗入江亭。',64,'全唐诗/poet.song.32000.json','["盤互長干有絕陘，并包佳麗入江亭。", "新霜浦溆綿綿凈，薄晚林巒往往青。", "南上欲窮牛渚怪，北尋難忘草堂靈。", "箯輿却走垂楊陌，已戴寒雲一兩星。"]'),
('70cd49c9-c594-45a1-b316-285bf38c4b75','北窗','王安石','宋','宋诗','song-poetry','','[]','病與衰期每强扶，雞壅桔梗亦時須。',64,'全唐诗/poet.song.32000.json','["病與衰期每强扶，雞壅桔梗亦時須。", "空花根蒂難尋摘，夢境煙塵費掃除。", "耆域藥囊真妄有，軒轅經匱或元無。", "北窗枕上春風暖，漫讀毗耶數卷書。"]'),
('d4840303-7aaf-419d-822b-b60d82eb7508','小姑','王安石','宋','宋诗','song-poetry','','[]','小姑未嫁與蘭支，何恨流傳樂府詩。',64,'全唐诗/poet.song.32000.json','["小姑未嫁與蘭支，何恨流傳樂府詩。", "初學水仙騎赤鯉，竟尋山鬼從文貍。", "繽紛雲䙱空棠檝，綽約煙鬟獨桂旗。", "弄玉有祠終或往，飛瓊無夢故難知。"]'),
('650f59e4-e4aa-49c5-8656-a98f4f7de103','榮上人遽欲歸以詩留之','王安石','宋','宋诗','song-poetry','','[]','道人傳業自天台，千里翛然赴感來。',64,'全唐诗/poet.song.32000.json','["道人傳業自天台，千里翛然赴感來。", "梵行毗沙爲外護，法筵靈曜得重開。", "已能爲我迂神足，便可隨方長聖胎。", "肯顧北山如慧約，與公西崦斸莓苔。"]'),
('8fe62d44-ac3a-46ec-aada-c3463250eef3','呈陳和叔','王安石','宋','宋诗','song-poetry','','[]','毀車爲屋僅容身，三歲相要薄主人。',64,'全唐诗/poet.song.32000.json','["毀車爲屋僅容身，三歲相要薄主人。", "晝寓槨磚常至夜，冬沿溝彴復尋春。", "南陔不洎公歸里，蒼墓垂成我喪親。", "後會縱多無此樂，山林投老一傷神。"]'),
('aab7f85a-f14c-4a1b-b907-e5e36a45c761','招呂望之使君','王安石','宋','宋诗','song-poetry','','[]','潮溝東路兩牛鳴，十畝漪漣一草亭。',64,'全唐诗/poet.song.32000.json','["潮溝東路兩牛鳴，十畝漪漣一草亭。", "委質山林如許國，寄懷魚鳥欲忘形。", "紛紛易變浮雲白，落落誰鍾老柏青。", "尚有使君同好惡，想隨秋水肯揚舲。"]'),
('4c17fe02-c66d-427d-9e8d-683b3d8ae79c','公闢枉道見過獲聞新詩因敘嘆仰','王安石','宋','宋诗','song-poetry','','[]','青丘神父能爲政，碧落仙翁好作詩。',64,'全唐诗/poet.song.32000.json','["青丘神父能爲政，碧落仙翁好作詩。", "舊事齊兒應共記，新篇楚老得先知。", "懷磚大峴如迎日，供帳閶門勝去時。", "若與鴟夷鬥百草，錦囊佳麗敵西施。"]'),
('c59e2621-2093-409f-8099-7f4ee7077d0b','全椒張公有詩在北山西庵僧者墁之悵然有感','王安石','宋','宋诗','song-poetry','','[]','十年怊悵躡山阡，終欲持杯滴到泉。',64,'全唐诗/poet.song.32000.json','["十年怊悵躡山阡，終欲持杯滴到泉。", "東路角巾非故約，西州華屋漫脩椽。", "幽明永隔休炊黍，真俗相妨久絕弦。", "遺墨每看疑邂逅，復隨人事散如煙。"]'),
('ebed600a-dd8b-47e0-9f1c-242d9aac625d','嶺雲','王安石','宋','宋诗','song-poetry','','[]','嶺雲合處小盤桓，人得敷衾馬解鞍。',64,'全唐诗/poet.song.32000.json','["嶺雲合處小盤桓，人得敷衾馬解鞍。", "寒莢著天榆歷歷，浄華浮海桂團團。", "交游渙散淵明喜，吏卒蕭條叔夜寬。", "方丈老翁無一髮，更知來不爲皮冠。"]'),
('bfdefc3d-3bb6-417c-b7b8-2049d32efd7f','蓼蟲','王安石','宋','宋诗','song-poetry','','[]','蓼蟲事業無餘習，芻狗文章不更陳。',64,'全唐诗/poet.song.32000.json','["蓼蟲事業無餘習，芻狗文章不更陳。", "隠几自憐居喪我，倨堂誰覺似非人。", "難堪藏室稱中士，祗合箕山作外臣。", "尚有少緣灰未死，欲持新句惱比鄰。"]'),
('a3cbc65f-ecfd-4480-b1e8-fce9aff8828b','莫疑','王安石','宋','宋诗','song-poetry','','[]','莫疑禪伯未知禪，莫笑仙翁不學仙。',64,'全唐诗/poet.song.32000.json','["莫疑禪伯未知禪，莫笑仙翁不學仙。", "靈骨肯傳黄蘗燼，真心自放赤松煙。", "蓮華世界何關汝，楮葉工夫浪費年。", "露鶴聲中江月白，一燈岑寂擁書眠。"]'),
('61ce5968-749e-4a0a-9d9d-eeeb2d022133','示俞秀老','王安石','宋','宋诗','song-poetry','','[]','繚繞山如涌翠波，人家一半在煙蘿。',64,'全唐诗/poet.song.32000.json','["繚繞山如涌翠波，人家一半在煙蘿。", "時豐笑語春聲早，地僻追尋野興多。", "窣堵朱甍開北向，招提素脊隠西阿。", "暮年要與君携手，處處相煩作好歌。"]'),
('bffa20c2-3123-4c60-99a0-09e90f1bb626','外厨遺火示公佐','王安石','宋','宋诗','song-poetry','','[]','刀匕初無欲凊人，如何竈鬼尚嫌嗔。',64,'全唐诗/poet.song.32000.json','["刀匕初無欲凊人，如何竈鬼尚嫌嗔。", "翛翛短褐方煬火，冉冉青煙已被宸。", "邂逅焚巢連鳥雀，倉黄濡幕愧比鄰。", "王陽幸有囊衣在，報賞焦頭亦未貧。"]'),
('f60c54f8-843a-4587-8574-af12b4c63888','讀眉山集次韵雪詩五首  其一','王安石','宋','宋诗','song-poetry','','[]','若木昏昏末有鴉，凍雷深閉阿香車。',64,'全唐诗/poet.song.32000.json','["若木昏昏末有鴉，凍雷深閉阿香車。", "摶雲忽散簁爲屑，翦水如分綴作花。", "擁箒尚憐南北巷，持杯能喜兩三家。", "戲挼弄掬輸兒女，羔袖龍鍾手獨叉。"]'),
('cbfecc29-2eb4-422f-9e69-42658d3b89db','讀眉山集次韵雪詩五首  其二','王安石','宋','宋诗','song-poetry','','[]','神女青腰寶髻鴉，獨藏雲氣委飛車。',64,'全唐诗/poet.song.32000.json','["神女青腰寶髻鴉，獨藏雲氣委飛車。", "夜光往往多聯璧，白小紛紛每散花。", "珠網纚連拘翼座，瑶池淼漫阿環家。", "銀爲宮闕尋常見，豈即諸天守夜叉。"]'),
('12d2ce18-2b25-4126-b367-82da7efca828','讀眉山集次韵雪詩五首  其三','王安石','宋','宋诗','song-poetry','','[]','惠施文字黑如鴉，於此機緘漫五車。',64,'全唐诗/poet.song.32000.json','["惠施文字黑如鴉，於此機緘漫五車。", "皭若易緇終不染，紛然能幻本無花。", "觀空白足寧知處，疑有青腰豈作家。", "慧可忍寒真覺晚，爲誰將手少林叉。"]'),
('b5d0c8d8-d45d-41d8-af5a-94d18f8b64ea','讀眉山集次韵雪詩五首  其四','王安石','宋','宋诗','song-poetry','','[]','寄聲三足阿環鴉，問訊青腰小駐車。',64,'全唐诗/poet.song.32000.json','["寄聲三足阿環鴉，問訊青腰小駐車。", "一一照肌寧有種，紛紛迷眼爲誰花。", "爭妍恐落江妃手，耐冷疑連月姊家。", "長恨玉顔春不久，畫圖時展爲君叉。"]'),
('de679dab-cf17-4c48-9309-5f8b2517af7c','讀眉山集次韵雪詩五首  其五','王安石','宋','宋诗','song-poetry','','[]','戲摇微縞女鬟鴉，試咀流酥已頰車。',64,'全唐诗/poet.song.32000.json','["戲摇微縞女鬟鴉，試咀流酥已頰車。", "歷亂稍埋冰揉粟，消沉時點水圓花。", "豈能舴艋真尋我，且與蝸牛獨卧家。", "欲挑青腰還不敢，直須詩膽付劉叉。"]'),
('dc3fea03-9839-4612-a282-b556b03f8d33','讀眉山集愛其雪詩能用韵復次韵一首','王安石','宋','宋诗','song-poetry','','[]','靚粧嚴飾曜金鴉，比興難工漫百車。',64,'全唐诗/poet.song.32000.json','["靚粧嚴飾曜金鴉，比興難工漫百車。", "水種所傳清有骨，天機能織皦非花。", "嬋娟一色明千里，綽約無心熟萬家。", "長此賞懷甘獨卧，袁安交戟豈須叉。"]'),
('eb66e1fe-0ecd-4575-900c-c58ed844f6f1','八功德水','王安石','宋','宋诗','song-poetry','','[]','雪山馬口出琉璃，聞說諸天與護持。',64,'全唐诗/poet.song.32000.json','["雪山馬口出琉璃，聞說諸天與護持。", "此水遥連八功德，供人真浄四威儀。", "當時迦葉無塵染，何事閿鄉有土思。", "道力起緣非一路，但知瓢飲是生疑。"]'),
('e00b1804-925e-4fe4-a26e-2d73f460ab07','寄題程公闢物華樓','王安石','宋','宋诗','song-poetry','','[]','吳楚東南最上游，江山多在物華樓。',64,'全唐诗/poet.song.32000.json','["吳楚東南最上游，江山多在物華樓。", "遥瞻旌節臨尊俎，獨卧柴荆阻獻酬。", "想有新詩傳素壁，怪無餘墨到滄洲。", "湡浯南望重重綠，章水還能向此流。"]'),
('2a76f754-1684-445e-b762-25066b38750a','酬俞秀老','王安石','宋','宋诗','song-poetry','','[]','灑掃東庵置一床，於君獨覺故情長。',64,'全唐诗/poet.song.32000.json','["灑掃東庵置一床，於君獨覺故情長。", "有言未必輸摩詰，無法何曾泥飲光。", "天壤此身知共弊，江湖他日要相忘。", "猶貪半偈歸思索，却恐提桓妄揣量。"]'),
('69440ab5-b5c6-42b0-855f-06bd6f1e7a97','次韵吳沖卿召赴資政殿聽讀詩義感事','王安石','宋','宋诗','song-poetry','','[]','周南麟趾聖人風，未有騶虞繫召公。',64,'全唐诗/poet.song.32000.json','["周南麟趾聖人風，未有騶虞繫召公。", "雅頌兼陳爲四始，笙歌合奏以三終。", "討論詔使成書上，休澣恩容著籍通。", "牆面豈能知奧義，延陵聽賞自爲聰。"]'),
('1f79a20a-8097-4151-a893-ac7fafd01f00','張侍郎示東府新居詩因而和酬二首  其一','王安石','宋','宋诗','song-poetry','','[]','得賢方慕北山萊，赤白中天二府開。',64,'全唐诗/poet.song.32000.json','["得賢方慕北山萊，赤白中天二府開。", "功謝蕭規慚漢第，恩從隗始詫燕臺。", "曾留上主經過迹，更費高人賦咏才。", "自古落成須善頌，掃除東閣望公來。"]'),
('19cbaa52-ca59-44e3-a6b5-69c28d1a3d1f','張侍郎示東府新居詩因而和酬二首  其二','王安石','宋','宋诗','song-poetry','','[]','榮觀流傳動草萊，中官賜設上尊開。',64,'全唐诗/poet.song.32000.json','["榮觀流傳動草萊，中官賜設上尊開。", "鼓歌䆗窱聽疑夢，肴果聯翩餽有臺。", "斧藻故應宜舊德，棟梁非復稱凡材。", "虛堂欲踵曹參事，試問齊人或肯來。"]'),
('c8ad2b4c-69ec-47e9-a67e-b750565c4f92','次韵沖卿上元從駕至集禧觀偶成','王安石','宋','宋诗','song-poetry','','[]','昭陵持橐從遊人，更見熙寧第四春。',64,'全唐诗/poet.song.32000.json','["昭陵持橐從遊人，更見熙寧第四春。", "寶稱中開移玉座，華燈錯出映朱塵。", "輦前時看新歌舞，仗外還如舊徼巡。", "投老逢時追往事，却含愁思度天津。"]'),
('bbc25e41-6984-48c4-a05f-dea5d4bc8a5c','次韵陪駕觀燈','王安石','宋','宋诗','song-poetry','','[]','並筤含風下玉除，宮商挾奏斐然殊。',64,'全唐诗/poet.song.32000.json','["並筤含風下玉除，宮商挾奏斐然殊。", "福祥周室流爲火，恩澤堯樽散在衢。", "伏枕但能知廣樂，揮毫何以報明珠。", "願留巾篋歸田日，追咏公歡每自娛。"]'),
('80c3a582-78ef-469a-af58-5f371c762d18','和吳相公東府偶成','王安石','宋','宋诗','song-poetry','','[]','承華往歲幸躊躇，風月清談接緒餘。',64,'全唐诗/poet.song.32000.json','["承華往歲幸躊躇，風月清談接緒餘。", "並轡趁朝今已老，連牆得屋喜如初。", "誅茅我夢江皋地，澆薤公思洛水渠。", "歛退故應容拙者，先營環堵祭牢蔬。"]'),
('812b85d6-7656-4ba5-a884-bdd233776c6a','和蔡樞密孟夏旦日西府書事','王安石','宋','宋诗','song-poetry','','[]','宮闕初晴氣象饒，寶車攢轂會東朝。',64,'全唐诗/poet.song.32000.json','["宮闕初晴氣象饒，寶車攢轂會東朝。", "重輪慶自離明發，內壤陰隨解澤消。", "賜篚外廷紛錦繡，燕庖中禁續薪樵。", "聯翩入賀知君意，咫尺威顔不隔霄。"]'),
('e49d47ee-7362-461a-bfd9-a4de9fa2cf95','和蔡副樞賀平戎慶捷','王安石','宋','宋诗','song-poetry','','[]','城郭名王據兩陲，軍前一日送降旗。',64,'全唐诗/poet.song.32000.json','["城郭名王據兩陲，軍前一日送降旗。", "羌兵自此無傳箭，漢甲如今不解纍。", "幕府上功聯舊伐，朝廷稱慶具新儀。", "周家道泰西戎喙，還見詩人咏串夷。"]'),
('2d7eb2f4-11fd-4147-a92d-994a3e1d90b8','次韵奉和蔡樞密南京種山藥法','王安石','宋','宋诗','song-poetry','','[]','區種拋來六七年，春風條蔓想宛延。',64,'全唐诗/poet.song.32000.json','["區種拋來六七年，春風條蔓想宛延。", "難追老圃莓苔徑，空對珍盤玳瑁筵。", "嘉種忽傳河右壤，靈苗更長闕西偏。", "故畦穿斸知何日，南望鍾山一慨然。"]'),
('d166c282-f66d-4e19-bb8d-84ff14fee347','次韵元厚之平戎慶捷','王安石','宋','宋诗','song-poetry','','[]','朝廷今日四夷功，先以招懷後殪戎。',64,'全唐诗/poet.song.32000.json','["朝廷今日四夷功，先以招懷後殪戎。", "胡地馬牛歸隴底，漢人煙火起湟中。", "投戈更講諸儒藝，免胄爭趨上將風。", "文武佐時慚吉甫，宣王征伐自膚公。"]'),
('82fe2abf-4f0b-4c04-98e9-2d70b309da22','謁曾魯公','王安石','宋','宋诗','song-poetry','','[]','翊戴三朝冕有蟬，歸榮今作地行仙。',64,'全唐诗/poet.song.32000.json','["翊戴三朝冕有蟬，歸榮今作地行仙。", "且開京闕蕭何第，未放江湖范蠡船。", "老景已鄰周呂尚，慶門方似漢韋賢。", "一觴豈足爲公壽，願賦長虹吸百川。"]'),
('5860ff53-dc53-44af-aec3-4cef2e516336','駕自啟聖還內','王安石','宋','宋诗','song-poetry','','[]','衣冠原廟漢家儀，羽衛親來此一時。',64,'全唐诗/poet.song.32000.json','["衣冠原廟漢家儀，羽衛親來此一時。", "天子當懷霜露感，都人亦嘆鼓簫悲。", "紛紛瑞氣隨雲漢，漠漠榮光上日旗。", "塵土未驚閶闔閉，綠槐空覆影參差。"]'),
('c8b6a67c-4c73-4e97-833f-0d0d509d6bad','集禧觀池上咏野鵝','王安石','宋','宋诗','song-poetry','','[]','池上野鵝無數好，晴天鏡裏雪毰毸。',64,'全唐诗/poet.song.32000.json','["池上野鵝無數好，晴天鏡裏雪毰毸。", "似憐暄暖鳴相逐，疑戀寬閑去却回。", "京洛塵沙工點汙，江湖矰弋飽驚猜。", "羽毛的的人難近，嗟此謀身或有才。"]'),
('c5519f2f-bd4a-4ea9-b381-b9e68b89d8a4','次韵東廳韓侍郎齋居晚興','王安石','宋','宋诗','song-poetry','','[]','齋禁雖嚴異太常，蕭然高卧意何長。',64,'全唐诗/poet.song.32000.json','["齋禁雖嚴異太常，蕭然高卧意何長。", "煙含欲暝宮庭紫，日映新秋省闥黄。", "壯節易摧行踽踽，華年相背去堂堂。", "追攀坐嘆風塵隔，空聽鈞天夢帝鄉。"]'),
('095772d5-26ce-41e9-951b-b673914e16b8','酬和甫祥源觀醮罷見寄','王安石','宋','宋诗','song-poetry','','[]','竊祿祠官久見容，每持金石薦宸衷。',64,'全唐诗/poet.song.32000.json','["竊祿祠官久見容，每持金石薦宸衷。", "鈞天忽忽清都夢，方丈寥寥弱水風。", "知結勝緣人意外，想尋陳迹馬蹄中。", "新詩起我超然興，更感鍾山蕙帳空。"]'),
('88c3cd53-2a02-4f41-82e5-43ba211d71cc','和御製賞花釣魚二首  其一','王安石','宋','宋诗','song-poetry','','[]','蔭幄晴雲拂曉開，傳呼仙仗九天來。',64,'全唐诗/poet.song.32000.json','["蔭幄晴雲拂曉開，傳呼仙仗九天來。", "披香殿上留朱輦，太液池邊送玉杯。", "宿蕊暖含風浩蕩，戲鱗清映日徘徊。", "宸章獨與春爭麗，恩許賡歌豈易陪。"]'),
('f019103d-51ba-450b-a468-ffc5847af05f','和御製賞花釣魚二首  其二','王安石','宋','宋诗','song-poetry','','[]','靄靄祥雲輦路晴，傳呼萬歲雜春聲。',64,'全唐诗/poet.song.32000.json','["靄靄祥雲輦路晴，傳呼萬歲雜春聲。", "蔽虧玉仗宮花密，映燭金溝御水清。", "珠蕊受風天下暖，錦鱗吹浪日邊明。", "從容樂飲真榮遇，願賦嘉魚頌太平。"]'),
('0831e2b4-7ee1-4447-bb95-7bf20ff900b0','次楊樂道韵六首 後殿朝次偶題','王安石','宋','宋诗','song-poetry','','[]','百年文物士優游，萬國今方似綴旒。',64,'全唐诗/poet.song.32000.json','["百年文物士優游，萬國今方似綴旒。", "發策東堂招儁乂，回輿北苑罷倡優。", "忽隨諸彥登龍尾，尚憶當年應鵠頭。", "獨望清光無補報，更慚虛食太官羞。"]'),
('fa742286-04df-438d-afa2-65b177c35b39','次楊樂道韵六首 御溝','王安石','宋','宋诗','song-poetry','','[]','渺渺金河漲欲平，數支分綠報清明。',64,'全唐诗/poet.song.32000.json','["渺渺金河漲欲平，數支分綠報清明。", "常縈輦路漂花去，更引流杯送酒行。", "靜見金輿穿樹影，清含玉漏過牆聲。", "衰顔一照自多感，迴首江南春水生。"]'),
('7337147e-957a-406e-bc03-11539fcc26f8','次楊樂道韵六首 幕次憶漢上舊居','王安石','宋','宋诗','song-poetry','','[]','漢水泱泱繞鳳林，峴山南路白雲深。',64,'全唐诗/poet.song.32000.json','["漢水泱泱繞鳳林，峴山南路白雲深。", "如何憂國忘家日，尚有求田問舍心。", "直以文章供潤色，未應風月負登臨。", "超然便欲遺榮去，却恐元龍會見侵。"]'),
('04e61913-b67f-4bc2-b58b-610ca91d8f5a','次楊樂道韵六首 後苑詳定書懷','王安石','宋','宋诗','song-poetry','','[]','文墨由來妙禁中，家傳豈獨賦河東。',64,'全唐诗/poet.song.32000.json','["文墨由來妙禁中，家傳豈獨賦河東。", "平生聽想風聲早，數日追隨笑語同。", "御水新如鴨頭綠，宮花更有鶴翎紅。", "看花弄水聊爲樂，不晚朝廷相弱翁。"]'),
('3ed894a7-7048-46d0-9cb0-1f9ba80e8718','次楊樂道韵六首 上巳聞苑中樂聲書事','王安石','宋','宋诗','song-poetry','','[]','苑中誰得從春遊，想見漸臺瓦欲流。',64,'全唐诗/poet.song.32000.json','["苑中誰得從春遊，想見漸臺瓦欲流。", "御水曲隨花影轉，宮雲低繞樂聲留。", "年華未破清明節，日暮初回祓禊舟。", "更覺至尊思慮遠，不應全爲拙倡優。"]'),
('99ca9606-23b7-4273-84f7-489552494a55','次楊樂道韵六首 用樂道舍人韵書十日事呈樂道舍人聖從待制','王安石','宋','宋诗','song-poetry','','[]','東門人物亂如麻，想見新韉照路華。',64,'全唐诗/poet.song.32000.json','["東門人物亂如麻，想見新韉照路華。", "午鼓已傳三刻漏，從官初賜一杯茶。", "匆匆殿下催分首，擾擾宮前聽賣花。", "歸去莫言天上事，但知呼客飲流霞。"]'),
('bad99300-5112-4f9d-af84-608688beff3a','詳定幕次呈聖從樂道','王安石','宋','宋诗','song-poetry','','[]','殿閣掄材覆等差，從臣今日擅文華。',64,'全唐诗/poet.song.32000.json','["殿閣掄材覆等差，從臣今日擅文華。", "楊雄識字無人敵，何遜能詩有世家。", "舊德醉心如美酒，新篇清目勝真茶。", "一觴一咏相從樂，傳說猶堪異日誇。"]'),
('0c3a4b58-71dd-47ef-8c18-a42d48db8181','崇政殿詳定幕次偶題','王安石','宋','宋诗','song-poetry','','[]','嬌雲漠漠護層軒，嫩水濺濺不見源。',64,'全唐诗/poet.song.32000.json','["嬌雲漠漠護層軒，嫩水濺濺不見源。", "禁柳萬條金細撚，宮花一段錦新翻。", "身閑始更知春樂，地廣還同避世喧。", "不恨玉盤冰未賜，清談終日自蠲煩。"]'),
('0443f897-14c6-4cb0-bb63-2f32316c3070','詳定試卷二首  其一','王安石','宋','宋诗','song-poetry','','[]','簾垂咫尺斷經過，把卷空聞笑語多。',64,'全唐诗/poet.song.32000.json','["簾垂咫尺斷經過，把卷空聞笑語多。", "論衆勢難專可否，法嚴人更謹誰何。", "文章直使看無纇，勳業安能保不磨。", "疑有高鴻在寥廓，未應迴首顧張羅。"]'),
('c75e9656-cb45-4b00-875a-2a844f2d3705','詳定試卷二首  其二','王安石','宋','宋诗','song-poetry','','[]','童子常誇作賦工，暮年羞悔有楊雄。',64,'全唐诗/poet.song.32000.json','["童子常誇作賦工，暮年羞悔有楊雄。", "當時賜帛倡優等，今日論才將相中。", "細甚客卿因筆墨，卑於爾雅注魚蟲。", "漢家故事真當改，新咏知君勝弱翁。"]'),
('3ea01b7c-8958-4882-9d42-d1502868f70c','奉酬楊樂道','王安石','宋','宋诗','song-poetry','','[]','邂逅聯裾殿閣春，却愁容易即離群。',64,'全唐诗/poet.song.32000.json','["邂逅聯裾殿閣春，却愁容易即離群。", "相知不必因相識，所得如今過所聞。", "近代聲名出盧駱，前朝筆墨數淵雲。", "與公家世由來事，愧我初無百一分。"]'),
('40d29c0b-e344-45df-98ef-651216008b9e','奉酬聖從待制','王安石','宋','宋诗','song-poetry','','[]','班行想望歲空多，知有龍門未敢過。',64,'全唐诗/poet.song.32000.json','["班行想望歲空多，知有龍門未敢過。", "和近聖人師展季，勇爲君子盜荆軻。", "三刀舊協庭闈夢，五腨今傳里巷歌。", "復道諫書嘗滿篋，不唯詩句似陰何。"]'),
('f39c5415-8ee0-41bd-971a-961905a65d1b','次韵吳仲庶省中畫壁','王安石','宋','宋诗','song-poetry','','[]','畫史雖非顧虎頭，還能滿壁寫滄洲。',64,'全唐诗/poet.song.32000.json','["畫史雖非顧虎頭，還能滿壁寫滄洲。", "九衢京洛風沙地，一片江湖草樹秋。", "行數鯈魚賓共樂，卧看鷗鳥吏方休。", "知君定有扁舟意，却爲丹青肯少留。"]'),
('4254a08c-9f22-4b72-8583-5d549fde3e95','夜讀試卷呈君實待制景仁內翰','王安石','宋','宋诗','song-poetry','','[]','篝燈時見語驚人，更覺揮毫捷有神。',64,'全唐诗/poet.song.32000.json','["篝燈時見語驚人，更覺揮毫捷有神。", "學問比來多可喜，文章非特巧爭新。", "蕉中得鹿初疑夢，牖下窺龍稍眩真。", "邂逅兩賢時所服，坐令孤朽得相因。"]'),
('5bc12223-abd7-4614-9387-a4761d0c32eb','答張奉議','王安石','宋','宋诗','song-poetry','','[]','五馬渡江開國處，一牛吼地作庵人。',64,'全唐诗/poet.song.32000.json','["五馬渡江開國處，一牛吼地作庵人。", "結蟠茅竹纔方丈，穿築溝園未過旬。", "我久欲忘言語道，君今來見句文身。", "思量何物堪酬對，棒喝如今總不親。"]'),
('b1b287f8-ea51-4896-ac65-2dcf2a76d478','次韵和吳仲庶池州齊山畫圖','王安石','宋','宋诗','song-poetry','','[]','省中何忽有崔嵬，六幅生綃坐上開。',64,'全唐诗/poet.song.32000.json','["省中何忽有崔嵬，六幅生綃坐上開。", "指點便知巖石處，登臨新作使君來。", "雅懷重向丹青得，勝勢兼隨翰墨回。", "更想杜郎詩在眼，一江春雪下離堆。"]'),
('e09b5a79-0c90-410b-b651-50fcde0a643d','次韵祖擇之登紫微閣二首  其一','王安石','宋','宋诗','song-poetry','','[]','漠漠秋陰護掖垣，青雲祇在兩楹間。',64,'全唐诗/poet.song.32000.json','["漠漠秋陰護掖垣，青雲祇在兩楹間。", "宮樓唱罷雞人遠，門闕朝歸虎士閑。", "華蓋北瞻夭帝座，蓬萊東想道家山。", "却慚久此隨諸彥，文采初無豹一斑。"]'),
('6a5a9dc2-0391-4968-b665-0be89d8913cc','次韵祖擇之登紫微閣二首  其二','王安石','宋','宋诗','song-poetry','','[]','掖門相對敞銅鐶，䡾䡾飛甍在兩間。',64,'全唐诗/poet.song.32000.json','["掖門相對敞銅鐶，䡾䡾飛甍在兩間。", "潤色平生知地禁，登臨此日愧身閑。", "浮雲倒影移窗隙，落木回飆動屋山。", "忽憶初來秋尚早，紫微花點綠苔斑。"]'),
('6544b75f-b34e-466c-a42d-4bbb717324a1','送沈興宗察院出使湖南','王安石','宋','宋诗','song-poetry','','[]','諫書平日皁囊中，朝路爭看一馬驄。',64,'全唐诗/poet.song.32000.json','["諫書平日皁囊中，朝路爭看一馬驄。", "漢節飽曾衝海霧，楚帆聊復借湖風。", "皇華命使今爲重，直道酬君遠亦同。", "投老承明無補助，得爲湘守即隨公。"]'),
('af7eed99-9f3c-4f2c-ba60-9afa1eb3b72e','春風','王安石','宋','宋诗','song-poetry','','[]','一馬春風北首燕，却疑身得舊山川。',64,'全唐诗/poet.song.32000.json','["一馬春風北首燕，却疑身得舊山川。", "陽浮樹外滄江水，塵漲原頭野火煙。", "日借嫩黄初著柳，雨催新綠稍歸田。", "回頭不見辛夷發，始覺看花是去年。"]'),
('ea20b4fa-504b-4886-a6ab-357863af4d80','永濟道中寄諸舅弟','王安石','宋','宋诗','song-poetry','','[]','燈火匆匆出館陶，回看永濟日初高。',64,'全唐诗/poet.song.32000.json','["燈火匆匆出館陶，回看永濟日初高。", "似聞空舍鳥烏樂，更覺荒陂人馬勞。", "客路光陰真棄置，春風邊塞祇蕭騷。", "辛夷樹下烏塘尾，把手何時得汝曹。"]'),
('d77389cc-b35b-4789-9398-c10be6fc859f','道逢文通北使歸','王安石','宋','宋诗','song-poetry','','[]','朱顔使者錦貂裘，笑語春風入貝州。',64,'全唐诗/poet.song.32000.json','["朱顔使者錦貂裘，笑語春風入貝州。", "欲報京都近消息，傳聲車馬少淹留。", "行人盡道還家樂，騎士能吹出塞愁。", "回首此時空慕羨，驚塵一段向南流。"]'),
('09b710af-aa58-410b-b7a8-7a6fa0da70eb','將次相州','王安石','宋','宋诗','song-poetry','','[]','青山如浪入漳州，銅雀臺西八九丘。',64,'全唐诗/poet.song.32000.json','["青山如浪入漳州，銅雀臺西八九丘。", "螻蟻往還空壟畝，騏驎埋沒幾春秋。", "功名蓋世知誰是，氣力迴天到此休。", "何必地中餘故物，魏公諸子分衣裘。"]'),
('d1da1c53-5e52-4897-bd57-e3af3ed59144','次韵平甫喜唐公自契丹歸','王安石','宋','宋诗','song-poetry','','[]','留犁撓酒得戎心，並袷通歡歲月深。',64,'全唐诗/poet.song.32000.json','["留犁撓酒得戎心，並袷通歡歲月深。", "奉使由來須陸賈，離親何必强曾參。", "燕人候望空甌脫，胡馬追隨出蹛林。", "萬里春風歸正好，亦逢佳客想揮金。"]'),
('3b897432-5819-43c7-87a3-9fd5f284fe4a','尹村道中','王安石','宋','宋诗','song-poetry','','[]','滿眼霜吹宿草根，謾知新歲不逢春。',64,'全唐诗/poet.song.32000.json','["滿眼霜吹宿草根，謾知新歲不逢春。", "却疑青嶂非人世，更覺黄雲是塞塵。", "萬里張侯能奉使，百年曾子肯辭親。", "自憐許國終無用，何事紛紛客此身。"]'),
('edb6c0af-52fb-4396-9ea1-3bbf2f6c8c8c','次韵王勝之咏雪','王安石','宋','宋诗','song-poetry','','[]','萬戶千門車馬稀，行人却返鳥休飛。',64,'全唐诗/poet.song.32000.json','["萬戶千門車馬稀，行人却返鳥休飛。", "玲瓏翦水空中墮，的皪裝春樹上歸。", "素髮聯華驚老大，玉顔爭好羨輕肥。", "朝來已賀豐年瑞，更問田家果是非。"]'),
('c2ed994c-7f2e-4657-8ae4-23d6023ba2c6','次韵酬府推仲通學士雪中見寄','王安石','宋','宋诗','song-poetry','','[]','朝來看雪咏君詩，想見朱衣在赤墀。',64,'全唐诗/poet.song.32000.json','["朝來看雪咏君詩，想見朱衣在赤墀。", "爲問火城將策試，何如雲屋聽窗知。", "曲牆稍覺吹來密，窮巷終憐掃去遲。", "欲訪故人非興盡，自緣無路得傳巵。"]'),
('7c5b1cac-2dda-4fb1-adda-c6e2df6119ef','次韵宋次道憶太平早梅','王安石','宋','宋诗','song-poetry','','[]','大梁春費寶刀催，不似湖陰有早梅。',64,'全唐诗/poet.song.32000.json','["大梁春費寶刀催，不似湖陰有早梅。", "今日盤中看翦綵，當時花下就傳杯。", "紛紛自向江城落，杳杳難隨驛使來。", "知憶舊游還想見，西南枝上月徘徊。"]'),
('6096ad59-c154-4f33-8555-d987980112ef','和曾子翊授舒掾之作','王安石','宋','宋诗','song-poetry','','[]','皖城終歲靜如山，府掾應從到日閑。',64,'全唐诗/poet.song.32000.json','["皖城終歲靜如山，府掾應從到日閑。", "一水碧羅裁繚繞，萬峰蒼玉刻孱顔。", "舊遊筆墨苔今老，浪走塵沙鬢已斑。", "攬轡羨君橋北路，春風枝上鳥關關。"]'),
('a4806c37-db50-4393-934b-7d8e18579639','送劉和父奉使江西','王安石','宋','宋诗','song-poetry','','[]','劉郎今日擁旌麾，傳到江南喜可知。',64,'全唐诗/poet.song.32000.json','["劉郎今日擁旌麾，傳到江南喜可知。", "上冢還須擊羊豕，下車應不問狐狸。", "無人敢效公榮酒，爲我聊尋逸少池。", "亦見嶺頭花爛熳，更將春色寄相思。"]'),
('32d61265-2083-4c3d-8276-af46ed30117f','次韵張子野竹林寺二首  其一','王安石','宋','宋诗','song-poetry','','[]','澗水橫斜石路深，水源窮處有叢林。',64,'全唐诗/poet.song.32000.json','["澗水橫斜石路深，水源窮處有叢林。", "青鴛幾世開蘭若，黄鶴當年瑞卯金。", "敗壁數峰連粉墨，凉煙一穗起檀沈。", "十年親友半零落，回首舊遊成古今。"]'),
('998ffd5d-2ce5-4c0f-9923-4d2256a70efe','次韵張子野竹林寺二首  其二','王安石','宋','宋诗','song-poetry','','[]','京峴城南隠映深，兩牛鳴地得禪林。',64,'全唐诗/poet.song.32000.json','["京峴城南隠映深，兩牛鳴地得禪林。", "風泉隔屋撞哀玉，竹月緣階貼碎金。", "藻井仰窺塵漠漠，青燈對宿夜沈沈。", "扁舟過客十年事，一夢此山愁至今。"]'),
('d514dd3c-c180-462b-9f4e-f75fa069b59e','送吳龍圖知江寧','王安石','宋','宋诗','song-poetry','','[]','才高明主睠方深，屬郡聞風自革心。',64,'全唐诗/poet.song.32000.json','["才高明主睠方深，屬郡聞風自革心。", "閭里不須多按治，山川從此數登臨。", "茅簷坐隔雲千里，柏壟初抽翠一尋。", "東望泫然知有寄，但疑公豈久分襟。"]'),
('b98bc312-df10-4bac-b6dd-60fb4a8763d0','送直講吳殿丞宰鞏縣','王安石','宋','宋诗','song-poetry','','[]','青嵩碧洛曾遊地，墨綬銅章忽在身。',64,'全唐诗/poet.song.32000.json','["青嵩碧洛曾遊地，墨綬銅章忽在身。", "擁馬尚多畿甸雪，隨衣無復禁城塵。", "古來學問須行己，此去風流定慰人。", "更憶少陵詩上語，知君不負鞏梅春。"]'),
('d7d17f04-35c1-4aaa-a25b-7b0387fe8583','送真州吳處厚使君','王安石','宋','宋诗','song-poetry','','[]','江上齋船駐彩橈，鳴笳應滿綠楊橋。',64,'全唐诗/poet.song.32000.json','["江上齋船駐彩橈，鳴笳應滿綠楊橋。", "久爲漢吏知文法，當使淮人服教條。", "拱木延陵瞻故國，叢祠瓜步認前朝。", "登臨莫負山川好，終欲東歸聽楚謠。"]'),
('7308f2b6-e1e3-4560-9404-d977c3b4309e','送李質夫之陝府','王安石','宋','宋诗','song-poetry','','[]','平世求才漫至公，悠悠羈旅士多窮。',64,'全唐诗/poet.song.32000.json','["平世求才漫至公，悠悠羈旅士多窮。", "十年見子尚短褐，千里隨人今北風。", "戶外屨貧虛自滿，樽中酒賤亦常空。", "共嫌欲老無機械，心事還能與我同。"]'),
('4b5c01c5-11ab-4c5f-88e7-c41998cc9e81','題儀真致政孫學士歸來亭','王安石','宋','宋诗','song-poetry','','[]','彭澤陶潛歸去來，素風千歲出塵埃。',64,'全唐诗/poet.song.32000.json','["彭澤陶潛歸去來，素風千歲出塵埃。", "明時儁老心無累，故里高門子有才。", "更作園林負城郭，常留花月映池臺。", "却尋五柳先生傳，柴水區區但可哀。"]'),
('e40531ec-b760-4740-a583-008a25fe141d','次韵吳季野題岳上人澄心亭','王安石','宋','宋诗','song-poetry','','[]','高亭五月尚寒生，回首塵沙自鬰蒸。',64,'全唐诗/poet.song.32000.json','["高亭五月尚寒生，回首塵沙自鬰蒸。", "砌水亂流穿石底，檻雲高出蔽山層。", "躋攀欲絕人間世，締構知從物外僧。", "腸胃坐來清似洗，神奇未怪佛圖澄。"]'),
('f89506f8-c0f1-4291-8a2f-409d565c6557','送彥珍','王安石','宋','宋诗','song-poetry','','[]','挾策窮鄉滿鬢絲，陂田荒盡豈嘗窺。',64,'全唐诗/poet.song.32000.json','["挾策窮鄉滿鬢絲，陂田荒盡豈嘗窺。", "未應谷口終身隠，正合菑川舉國推。", "握手百憂空往事，還家一笑即芳時。", "柘岡定有辛夷發，亦見東風使我知。"]'),
('194ccb79-8b20-42e6-8d16-ed078f29729d','寄張先郎中','王安石','宋','宋诗','song-poetry','','[]','留連山水住多時，年比馮唐未覺衰。',64,'全唐诗/poet.song.32000.json','["留連山水住多時，年比馮唐未覺衰。", "篝火尚能書細字，郵筩還肯寄新詩。", "胡床月下知誰對，蠻榼花前想自隨。", "投老主恩聊欲報，每瞻高躅恨歸遲。"]'),
('b7c4502f-61c9-4374-8d52-003ecb0965bc','汜水寄和甫','王安石','宋','宋诗','song-poetry','','[]','虎牢關下水逶迤，想汝飄然過此時。',64,'全唐诗/poet.song.32000.json','["虎牢關下水逶迤，想汝飄然過此時。", "灑血祇添波浪起，脫身難借羽翰追。", "留連厚祿非朝隠，乖隔殘年更土思。", "已卜冶城三畝地，寄聲知我有歸期。"]'),
('6a6dc69e-94bb-4c1f-adf0-8bac6e8c8fc1','寄黄吉甫','王安石','宋','宋诗','song-poetry','','[]','朱顔去似朔風驚，白髮多於野草生。',64,'全唐诗/poet.song.32000.json','["朱顔去似朔風驚，白髮多於野草生。", "挾策讀書空有得，求田問舍轉無成。", "解鞍烏石岡邊坐，携手辛夷樹下行。", "今日追思真樂事，黄塵深處走雞鳴。"]'),
('49a68be4-f059-4fa8-9f20-e7b3238f8762','次韵平甫村墅春日','王安石','宋','宋诗','song-poetry','','[]','昨日青青尚未齊，忽看春色滿高低。',64,'全唐诗/poet.song.32000.json','["昨日青青尚未齊，忽看春色滿高低。", "陂梅弄影爭先舞，葉鳥藏身自在啼。", "樵蹻踏雲歸舊徑，漁簑背雨向前溪。", "似知我欲逃軒冕，談笑相過各有携。"]'),
('9619939c-f36e-469f-b870-7836985d7ad5','即席次韵微之泛舟','王安石','宋','宋诗','song-poetry','','[]','畫舸幽尋北果園，應將陳迹問桑門。',64,'全唐诗/poet.song.32000.json','["畫舸幽尋北果園，應將陳迹問桑門。", "地隨牆墅行多曲，天著岡巒望易昏。", "故國時平空有木，荒城人少半爲村。", "悠悠興廢皆如此，頼付乾愁酒一樽。"]'),
('b6648bed-d52b-4290-b9de-7f2d7a18b743','示長安君','王安石','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u5144\u59b9", "\u611f\u4f24", "\u91cd\u9022"]','少年離別意非輕，老去相逢亦愴情。',64,'全唐诗/poet.song.32000.json','["少年離別意非輕，老去相逢亦愴情。", "草草杯盤供笑語，昏昏燈火話平生。", "自憐湖海三年隔，又作塵沙萬里行。", "欲問後期何日是，寄書應見雁南征。"]'),
('4595b193-a13a-44bf-be7f-8f07782b8065','和平甫招道光法師','王安石','宋','宋诗','song-poetry','','[]','鍊師投老演真乘，像劫空王爪與肱。',64,'全唐诗/poet.song.32000.json','["鍊師投老演真乘，像劫空王爪與肱。", "於總持門通一路，以光明藏續千燈。", "從容發口酬摩詰，邂逅持心契慧能。", "新句得公還有頼，古人詩字耻無僧。"]'),
('4ab988d1-cb46-4b7f-8954-f48a0fc5543a','和祖仁晚過集禧觀','王安石','宋','宋诗','song-poetry','','[]','妍暖聊隨馬首東，春衫猶未著方空。',64,'全唐诗/poet.song.32000.json','["妍暖聊隨馬首東，春衫猶未著方空。", "煙霞送色歸瑶水，山木分香繞閬風。", "壯髮已輸塵外綠，衰顔漫到酒邊紅。", "日斜歸去人間世，却記前遊似夢中。"]'),
('90529188-4b1f-4fec-9f6b-ac9cd0ffb578','程公闢轉運江西','王安石','宋','宋诗','song-poetry','','[]','江西一節鑄黄金，最慰章濱父老心。',64,'全唐诗/poet.song.32000.json','["江西一節鑄黄金，最慰章濱父老心。", "長孺向來真强予，次公今不異重臨。", "餘風尚有歡謠在，陳迹非無勝事尋。", "豫想新詩能寄我，十年華省故情深。"]'),
('9741524a-479e-46f3-a852-40b2280f2331','次韵微之即席','王安石','宋','宋诗','song-poetry','','[]','釀成吳米野油囊，却愛清談氣味長。',64,'全唐诗/poet.song.32000.json','["釀成吳米野油囊，却愛清談氣味長。", "閑日有僧來北阜，平時無盜出南塘。", "風亭對竹酬孤峭，雪逕尋梅認暗香。", "江水中𤃩應未變，一杯終欲就君嘗。"]'),
('a7c7f026-ed81-4a62-94bd-a0ff95d10f49','和王微之秋浦望齊山感李太白杜牧之','王安石','宋','宋诗','song-poetry','','[]','齊山置酒菊花開，秋浦聞猿江上哀。',64,'全唐诗/poet.song.32000.json','["齊山置酒菊花開，秋浦聞猿江上哀。", "此地流傳空筆墨，昔人埋沒已蒿萊。", "平生志業無高論，末世篇章有逸才。", "尚得使君驅五馬，與尋陳迹久徘徊。"]'),
('245a7d48-4964-4e84-9c43-5c5f34b2caf7','次韵王微之登高齋','王安石','宋','宋诗','song-poetry','','[]','臺殿荒墟辱井堙，豪華不復見臨春。',64,'全唐诗/poet.song.32000.json','["臺殿荒墟辱井堙，豪華不復見臨春。", "北山漠漠雲垂地，南埭悠悠水映人。", "馳道蔽虧松半死，射場埋沒雉多馴。", "登高一曲悲亡國，想繞紅梁落暗塵。"]'),
('e1002fea-893d-4e5f-b4eb-41b7af75053f','和微之重感南唐事','王安石','宋','宋诗','song-poetry','','[]','叔寶傾陳衍弊梁，可嗟曾不見興亡。',64,'全唐诗/poet.song.32000.json','["叔寶傾陳衍弊梁，可嗟曾不見興亡。", "齋祠父子終身費，酣咏君臣舉國荒。", "南狩皖山非故地，北師淮水失名王。", "天移四海歸真主，誰誘昏童肯用良。"]'),
('1ed85cc0-ff87-4849-8622-763ee4c9c0be','李君昆弟訪別長蘆至淮陰追寄','王安石','宋','宋诗','song-poetry','','[]','怒水憑風雪壟高，亂流追我祇魚舠。',64,'全唐诗/poet.song.32000.json','["怒水憑風雪壟高，亂流追我祇魚舠。", "忽看淮月臨寒食，想映江春聽伯勞。", "道義當成麟一角，文章已禿兔千毫。", "後生可畏吾知子，南北何時見兩髦。"]'),
('fab8f67e-a81c-4d69-8d19-a5b659866ab5','貴州虞部使君訪及道舊竊有感惻因成小詩','王安石','宋','宋诗','song-poetry','','[]','韶山秀拔江清寫，氣象還能出搢紳。',64,'全唐诗/poet.song.32000.json','["韶山秀拔江清寫，氣象還能出搢紳。", "當我垂髫初識字，看君揮翰獨驚人。", "郵籤忽報旌麾入，齋閤遥瞻組綬新。", "握手更誰知往事，同時諸彥略成塵。"]'),
('d99e60ae-901e-4ac8-985d-e61a2eda8529','沖卿席上得行字','王安石','宋','宋诗','song-poetry','','[]','二年相值喜同聲，並轡塵沙眼亦明。',64,'全唐诗/poet.song.32000.json','["二年相值喜同聲，並轡塵沙眼亦明。", "新詔各從天上得，殘樽同向月邊傾。", "已嗟後會歡難必，更想前官責尚輕。", "黽勉敢忘君所勗，古人憂樂有違行。"]'),
('ab016c71-4f65-43ca-a5c1-a7e0c1bb88a5','示董伯懿','王安石','宋','宋诗','song-poetry','','[]','穿橋度塹祇閑行，咏石嘲花亦漫成。',64,'全唐诗/poet.song.32000.json','["穿橋度塹祇閑行，咏石嘲花亦漫成。", "嚼蠟已能忘世味，畫脂那更惜時名。", "長干里北寒山紫，白下門西野水明。", "此地一廛須卜築，故人他日訪柴荆。"]'),
('f9363110-8b3f-4054-8df4-04ef66029249','思王逢原三首  其一','王安石','宋','宋诗','song-poetry','','[]','布衣阡陌動成群，卓犖高才獨見君。',64,'全唐诗/poet.song.32000.json','["布衣阡陌動成群，卓犖高才獨見君。", "杞梓豫章蟠絕壑，騏驎騕褭跨浮雲。", "行藏已許終身共，生死那知半路分。", "便恐世間無妙質，鼻端從此罷揮斤。"]'),
('2b3da599-463f-4de8-9a3f-395b5300f5c7','思王逢原三首  其二','王安石','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蓬蒿今日想紛披，冢上秋風又一吹。',64,'全唐诗/poet.song.32000.json','["蓬蒿今日想紛披，冢上秋風又一吹。", "妙質不爲平世得，微言唯有故人知。", "廬山南墮當書案，湓水東來入酒巵。", "陳迹可憐隨手盡，欲歡無復似當時。"]'),
('2e281bee-c850-4787-93c1-8bd414c98951','思王逢原三首  其三','王安石','宋','宋诗','song-poetry','','[]','百年相望濟時功，歲路何知向此窮。',64,'全唐诗/poet.song.32000.json','["百年相望濟時功，歲路何知向此窮。", "鷹隼奮飛凰羽短，騏驎埋沒馬群空。", "中郎舊業無兒付，康子高才有婦同。", "想見江南原上墓，樹枝零落紙錢風。"]'),
('03dc8c32-c31e-4f93-84ad-2c0087ceaf87','和吳御史臨淮感事','王安石','宋','宋诗','song-poetry','','[]','柵鎖城扉曉一開，柂牙車軸轉成雷。',64,'全唐诗/poet.song.32000.json','["柵鎖城扉曉一開，柂牙車軸轉成雷。", "黄塵欲礙龜山出，白浪空分汴水來。", "澄觀有材邀昧陋，霽雲無力報奸回。", "騷人此日追前事，悲氣隨風動管灰。"]'),
('a4f546e4-5f2b-4fc1-ad79-cbacd802d620','和文淑湓浦見寄','王安石','宋','宋诗','song-poetry','','[]','多難漂零歲月賒，空餘文墨舊生涯。',64,'全唐诗/poet.song.32000.json','["多難漂零歲月賒，空餘文墨舊生涯。", "相看楚越常千里，不及朱陳似一家。", "髮爲感傷無翠葆，眼從瞻望有玄花。", "唯詩與我寬愁病，報爾何妨賦棣華。"]'),
('912aadeb-e7e3-4219-aea3-f8b11df8079a','次韵吳季野再見寄','王安石','宋','宋诗','song-poetry','','[]','衣裘南北弊風塵，志趣卑汙已累親。',64,'全唐诗/poet.song.32000.json','["衣裘南北弊風塵，志趣卑汙已累親。", "流俗尚疑身察察，交遊方笑黨頻頻。", "遠同魚樂思濠上，老使鷗驚耻海濱。", "邂逅得君還恨晚，能明吾意久無人。"]'),
('dd4bdcc0-8e58-4986-ba33-ee83a05acef7','次韵平甫贈三靈山人程惟象','王安石','宋','宋诗','song-poetry','','[]','家山松菊半荒蕪，杖策窮年信所如。',64,'全唐诗/poet.song.32000.json','["家山松菊半荒蕪，杖策窮年信所如。", "占見地靈非卜筮，算知人貴自陶漁。", "久諳郭璞言多驗，老比顔含意更疏。", "祇欲勒成方士傳，借君名姓在新書。"]'),
('936d5180-59ed-4327-b46b-732db38265ac','次韵和甫咏雪','王安石','宋','宋诗','song-poetry','','[]','奔走風雲四面來，坐看山壟玉崔嵬。',64,'全唐诗/poet.song.32000.json','["奔走風雲四面來，坐看山壟玉崔嵬。", "平治險穢非無德，潤澤焦枯是有才。", "勢合便疑包地盡，功成終欲放春回。", "寒鄉不念豐年瑞，只憶青天萬里開。"]'),
('1f1f3856-90e2-4fe1-8fe4-9adbf4120d44','次韵張氏女弟咏雪','王安石','宋','宋诗','song-poetry','','[]','天上空多地上稀，初寒風力故應微。',64,'全唐诗/poet.song.32000.json','["天上空多地上稀，初寒風力故應微。", "那能鎮壓黄塵起，强欲侵凌白日飛。", "邑犬橫來矜意氣，窟蟾偷出助光輝。", "都城只有袁安憊，我亦年年幸賜衣。"]'),
('3e76eab4-ab7f-4aea-809f-63f0a2dccaa4','次韵徐仲元咏梅二首  其一','王安石','宋','宋诗','song-poetry','','[]','溪杏山桃欲占新，高梅放蕊尚嬌春。',64,'全唐诗/poet.song.32000.json','["溪杏山桃欲占新，高梅放蕊尚嬌春。", "額黄映日明飛燕，肌粉含風冷太真。", "玉笛悲凉吹易散，冰紈生澀畫難親。", "爭妍喜有君詩在，老我翛然敢效顰。"]'),
('d33c1cb1-21a7-421a-a038-b823e08b644b','次韵徐仲元咏梅二首  其二','王安石','宋','宋诗','song-poetry','','[]','舊挽青條冉冉新，花遲亦度柳前春。',64,'全唐诗/poet.song.32000.json','["舊挽青條冉冉新，花遲亦度柳前春。", "肌冰綽約如姑射，膚雪參差是太真。", "摇落會應傷歲晚，攀翻剩欲寄情親。", "終無驛使傳消息，寂寞知誰笑與顰。"]'),
('9de79a38-e90d-4069-860c-218a1c1917de','詩呈節判陸君','王安石','宋','宋诗','song-poetry','','[]','中郎筆墨妙他年，晚與君遊喜象賢。',64,'全唐诗/poet.song.32000.json','["中郎筆墨妙他年，晚與君遊喜象賢。", "款款故情初未憗，飄飄新句總堪傳。", "英才但未遭文舉，明主寧當棄浩然。", "投贈臨分加組麗，小詩能不强雕鎸。"]'),
('925c9833-7bc7-47e2-9fa4-9ebfc1fd1913','留題曲親盆山','王安石','宋','宋诗','song-poetry','','[]','巧與天成未覺殊，國工施手豈須臾。',64,'全唐诗/poet.song.32000.json','["巧與天成未覺殊，國工施手豈須臾。", "根連滄海蓬萊闊，勢壓黄河砥柱孤。", "坐上煙嵐生紫翠，影中樓閣見青朱。", "爲山觀水皆良喻，誰向君家識所趨。"]'),
('0efc19ed-6151-4cd4-9178-ca24b79e6a12','不到太初兄所居遂已十年以詩攀寄','王安石','宋','宋诗','song-poetry','','[]','一水衣巾翦翠綃，九峰環珮刻青瑶。',64,'全唐诗/poet.song.32000.json','["一水衣巾翦翠綃，九峰環珮刻青瑶。", "生才故有山川氣，卜築兼無市井囂。", "三葉素風門閥在，十年陳迹履綦銷。", "歸榮早晚重携手，莫負幽人久見招。"]'),
('cfb20e05-9da6-450f-95d9-fb0c67aea134','偶成二首  其一','王安石','宋','宋诗','song-poetry','','[]','漸老偏諳世上情，已知吾事獨難行。',64,'全唐诗/poet.song.32000.json','["漸老偏諳世上情，已知吾事獨難行。", "脫身負米將求志，勠力求田豈爲名。", "高論頗隨衰俗廢，壯懷難值故人傾。", "相逢始覺寬愁病，搔首還添白髮生。"]'),
('036cc03e-225f-49d0-8c03-9bf1a15369a0','偶成二首  其二','王安石','宋','宋诗','song-poetry','','[]','懷抱難開醉易醒，曉歌悲壯動秋城。',64,'全唐诗/poet.song.32000.json','["懷抱難開醉易醒，曉歌悲壯動秋城。", "年光斷送朱顔去，世事栽培白髮生。", "三畝未成幽處宅，一身還逐衆人行。", "可憐蝸角能多少，獨與區區觸事爭。"]'),
('9d57d16b-fb10-4c5b-bb03-51201f4e110c','雨過偶書','王安石','宋','宋诗','song-poetry','','[]','霈然甘澤洗塵寰，南畝東郊共慰顔。',64,'全唐诗/poet.song.32000.json','["霈然甘澤洗塵寰，南畝東郊共慰顔。", "地望歲功還物外，天將生意與人間。", "霽分星斗風雷靜，凉入軒窗枕簟閒。", "誰似浮雲知進退，纔成霖雨便歸山。"]'),
('b4aad1b7-f528-4fd3-ae4d-d2ae1825ad2a','季春上旬苑中即事','王安石','宋','宋诗','song-poetry','','[]','輦路行看斗柄東，簾垂殿閣轉春風。',64,'全唐诗/poet.song.32000.json','["輦路行看斗柄東，簾垂殿閣轉春風。", "樹林隠翳燈含霧，河漢欹斜月墜空。", "新蕊漫知紅簌簌，舊山常夢直叢叢。", "賞心樂事須年少，老去應無日再中。"]'),
('cd09a81e-f7bd-40dd-923c-5fd84c4f5ce8','上西垣舍人','王安石','宋','宋诗','song-poetry','','[]','共說才高世所珍，諸賢誰敢望光塵。',64,'全唐诗/poet.song.32000.json','["共說才高世所珍，諸賢誰敢望光塵。", "討論潤色今爲美，學問文章老更醇。", "賦擬相如真復似，詩看子建的應親。", "仍聞悟主言多直，許史家兒往往嗔。"]'),
('c0e59b0a-2100-437c-a5e1-1da826e538ae','退朝','王安石','宋','宋诗','song-poetry','','[]','門外鳴騶送響頻，披衣强起赴鷄人。',64,'全唐诗/poet.song.32000.json','["門外鳴騶送響頻，披衣强起赴鷄人。", "火城夜闇雲藏闕，玉座朝寒雪被宸。", "邂逅欲成雙白鬢，蕭條難得兩朱輪。", "猶憐退食親朋在，相與吟哦未厭貧。"]'),
('d372c642-fa10-4d5b-ac73-42300a19eab1','與微之同賦梅花得香字三首  其一','王安石','宋','宋诗','song-poetry','','[]','漢宮嬌額半塗黄，粉色凌寒透薄粧。',64,'全唐诗/poet.song.32000.json','["漢宮嬌額半塗黄，粉色凌寒透薄粧。", "好借月魂來映燭，恐隨春夢去飛揚。", "風亭把盞酬孤艷，雪徑回輿認暗香。", "不爲調羹應結子，直須留此占年芳。"]'),
('785ce441-2538-4747-96aa-2ebb1a8e63ef','與微之同賦梅花得香字三首  其二','王安石','宋','宋诗','song-poetry','','[]','結子非貪鼎鼐嘗，偶先紅杏占年芳。',64,'全唐诗/poet.song.32000.json','["結子非貪鼎鼐嘗，偶先紅杏占年芳。", "從教臘雪埋藏得，却怕春風漏洩香。", "不御鉛華知國色，祇裁雲縷想仙裝。", "少陵爲爾牽詩興，可是無心賦海棠。"]'),
('46e2032e-7e60-47ec-9c5b-8b8fee09ce83','與微之同賦梅花得香字三首  其三','王安石','宋','宋诗','song-poetry','','[]','淺淺池塘短短牆，年年爲爾惜流芳。',64,'全唐诗/poet.song.32000.json','["淺淺池塘短短牆，年年爲爾惜流芳。", "向人自有無言意，傾國天教抵死香。", "鬚裊黄金危欲墮，蒂團紅蠟巧能裝。", "嬋娟一種如冰雪，依倚春風笑野棠。"]'),
('d5ee6369-3577-42a1-ab5c-292895e7a516','和晚菊','王安石','宋','宋诗','song-poetry','','[]','不得黄花九日吹，空看野葉翠葳蕤。',64,'全唐诗/poet.song.32000.json','["不得黄花九日吹，空看野葉翠葳蕤。", "淵明酩酊知何處，子美蕭條向此時。", "委翳似甘終草莽，栽培空欲傍藩籬。", "可憐蜂蝶飄零後，始有閑人把一枝。"]'),
('561be8bb-947d-4a3d-9ef3-62692408e4f6','景福殿前柏','王安石','宋','宋诗','song-poetry','','[]','香葉由來耐歲寒，幾經真賞駐鳴鑾。',64,'全唐诗/poet.song.32000.json','["香葉由來耐歲寒，幾經真賞駐鳴鑾。", "根通御水龍應蟄，枝觸宮雲鶴更盤。", "怪石誤蒙三品號，老松先得大夫官。", "知君勁節無榮慕，寵辱紛紛一等看。"]'),
('615a8088-c58d-4880-a18a-5b2eb07174fa','四月果','王安石','宋','宋诗','song-poetry','','[]','一春强半勒花風，幾日園林幾樹紅。',64,'全唐诗/poet.song.32000.json','["一春强半勒花風，幾日園林幾樹紅。", "汲汲追攀常恨晚，紛紛吹洗忽成空。", "行看果下蒼苔地，已作人間白髮翁。", "豈惜解鞍留夜飲，此身醒醉與誰同。"]'),
('740d87fd-b57b-440a-bb8c-020648319895','牆西樹','王安石','宋','宋诗','song-poetry','','[]','牆西高樹結陰稠，步屣窮年向此留。',64,'全唐诗/poet.song.32000.json','["牆西高樹結陰稠，步屣窮年向此留。", "白日屢移催我老，清風一至使人愁。", "紛紛暝鳥驚還合，渺渺凉蟬咽欲休。", "回首舊林歸未得，看看知復幾春秋。"]'),
('0d425a6b-a2d9-4211-9b84-4168e791200f','度麾嶺寄莘老','王安石','宋','宋诗','song-poetry','','[]','區區隨傳換冬春，夜半懸崖託此身。',64,'全唐诗/poet.song.32000.json','["區區隨傳換冬春，夜半懸崖託此身。", "豈慕王尊能許國，直緣毛義欲私親。", "施爲已壞生平學，夢想猶歸寂寞濱。", "風月一歌勞者事，能明吾意可無人。"]'),
('0d5a29f8-8786-4b81-b424-ca6007f660f8','狄梁公陶淵明俱爲彭澤令至今有廟在焉刁景純作詩見示繼以一篇','王安石','宋','宋诗','song-poetry','','[]','梁公壯節就夔魖，陶令清身託酒徒。',64,'全唐诗/poet.song.32000.json','["梁公壯節就夔魖，陶令清身託酒徒。", "政在房陵成底事，年稱甲子亦何須。", "江山彭澤空遺像，歲月柴桑失故區。", "末俗此風猶不競，詩翁嘆息未應無。"]'),
('36455798-f622-4288-b531-ae2a73d3c89d','寄沈鄱陽','王安石','宋','宋诗','song-poetry','','[]','離家當日尚炎風，叱馭歸時九月窮。',64,'全唐诗/poet.song.32000.json','["離家當日尚炎風，叱馭歸時九月窮。", "朝渡藤溪霜落後，夜過麾嶺月明中。", "山川道路良多阻，風俗謠言苦未通。", "唯有鄱君人共愛，流傳名譽滿江東。"]'),
('49396474-2a80-4072-99d5-7ca43eac1070','送裴如晦宰吳江','王安石','宋','宋诗','song-poetry','','[]','青髮朱顔各少年，幅巾談笑兩歡然。',64,'全唐诗/poet.song.32000.json','["青髮朱顔各少年，幅巾談笑兩歡然。", "柴桑別後餘三徑，天祿歸來盡一廛。", "邂逅都門誰載酒，蕭條江縣去鳴弦。", "猶疑甫里英靈在，到日憑君爲艤船。"]'),
('69a4f29d-c95b-45da-960a-5d54ddbd4438','次韵樂道送花','王安石','宋','宋诗','song-poetry','','[]','沁水名園好物華，露盤分送子雲家。',64,'全唐诗/poet.song.32000.json','["沁水名園好物華，露盤分送子雲家。", "新粧欲應何人面，彩筆知書幾葉花。", "曾和郢中歌白雪，亦陪天上飲流霞。", "春風已得同心賞，更擬携詩載酒誇。"]'),
('c4b317a3-157c-44a8-b1a1-bed708c8303f','籌思亭','王安石','宋','宋诗','song-poetry','','[]','昔人何計亦何思，許國憂民適此時。',64,'全唐诗/poet.song.32000.json','["昔人何計亦何思，許國憂民適此時。", "寓興中園爲遠趣，託名華榜有新詩。", "數株碧柳蒼苔地，一丈紅蕖淥水池。", "坐聽楚謠知歲美，想銜杯酒問花期。"]'),
('cb599f85-7d15-4cdd-bb5d-0bdfcc521acf','愁臺','王安石','宋','宋诗','song-poetry','','[]','頹垣斷壍有平沙，老木荒榛八九家。',64,'全唐诗/poet.song.32000.json','["頹垣斷壍有平沙，老木荒榛八九家。", "河勢東南吹地坼，天形西北倚城斜。", "傾壺語罷還登眺，岸幘詩成却嘆嗟。", "萬事因循今白髮，一年容易即黄花。"]'),
('410a93d3-0611-445a-ba49-cc84ba1aae31','和正叔懷其兄草堂','王安石','宋','宋诗','song-poetry','','[]','茆堂竹樹水之濱，耕稼逍遥似子真。',64,'全唐诗/poet.song.32000.json','["茆堂竹樹水之濱，耕稼逍遥似子真。", "小吏一身今倦宦，先生三畝獨安貧。", "欲拋縣印辭黄綬，來伴山冠戴白綸。", "祇恐明時收士急，不容家有兩閑人。"]'),
('37176d6c-b785-4338-8d27-377e6aace9ef','鄭子憲西齋','王安石','宋','宋诗','song-poetry','','[]','漫搆軒窗意亦深，滔滔浮俗倦登臨。',64,'全唐诗/poet.song.32000.json','["漫搆軒窗意亦深，滔滔浮俗倦登臨。", "詩書千載經綸志，松竹四時蕭灑心。", "曉枕不容春夢到，夜燈唯許月華侵。", "行看富貴酬勤苦，車馬重來拾翠陰。"]'),
('5cd7909b-6480-40b6-9090-a1dd58d18be2','寄題思軒','王安石','宋','宋诗','song-poetry','','[]','名郎此地昔徘徊，天誘良孫接踵來。',64,'全唐诗/poet.song.32000.json','["名郎此地昔徘徊，天誘良孫接踵來。", "萬屋尚歌餘澤在，一軒還向舊堂開。", "右軍筆墨空殘沼，內史文章祇廢臺。", "邑子從今誇勝事，豈論王謝世稱才。"]'),
('30e48503-9dce-4725-ad1c-782f3cd03b5b','陳君式大夫恭軒','王安石','宋','宋诗','song-poetry','','[]','恭軒靜對北堂深，新斸檀欒一畝陰。',64,'全唐诗/poet.song.32000.json','["恭軒靜對北堂深，新斸檀欒一畝陰。", "膝下往來前日事，眼中封植去年心。", "每懷樽斝沾餘瀝，獨喜弦歌有嗣音。", "肯搆會須門閥大，世資何用滿籝金。"]'),
('c32c9b85-d2d8-44ad-994d-c750af697a1f','寄黄吉甫','王安石','宋','宋诗','song-poetry','','[]','學兼文武在吾曹，別後應看虎豹韜。',64,'全唐诗/poet.song.32000.json','["學兼文武在吾曹，別後應看虎豹韜。", "欲問廟堂誰鎮撫，尚傳邊塞敢驚騷。", "旌旗急引飛黄下，烽火遥連太白高。", "聞說荆人亦憔悴，家家還願獻春醪。"]'),
('3562cdf5-52fb-45f6-8217-9bd03accec13','高魏留','王安石','宋','宋诗','song-poetry','','[]','魏留十七助防邊，埋沒鹽州十八年。',64,'全唐诗/poet.song.32000.json','["魏留十七助防邊，埋沒鹽州十八年。", "衣屨窮空委胡婦，糗糧辛苦待山田。", "關河舊路頻回首，腹背他時兩受鞭。", "邂逅得歸耶戰死，母隨人去亦蕭然。"]'),
('590ce261-6637-45cf-9be9-15e0502b76ad','丁年','王安石','宋','宋诗','song-poetry','','[]','丁年結客盛遊從，宛洛氈車處處逢。',64,'全唐诗/poet.song.32000.json','["丁年結客盛遊從，宛洛氈車處處逢。", "吟盡物華愁筆老，醉消春色愛醅濃。", "壚間寂寞相如病，鍛處荒凉叔夜慵。", "早晚青雲須自致，立談平取徹侯封。"]'),
('95364be6-4698-4d98-95cd-12d31cd1f852','送王詹叔利州路運判','王安石','宋','宋诗','song-poetry','','[]','王孫舊讀五車書，手把山陽太守符。',64,'全唐诗/poet.song.32000.json','["王孫舊讀五車書，手把山陽太守符。", "未駕朱轓辭輦轂，却分金節佐均輸。", "人才自古常難得，時論如君豈久孤。", "去去便看歸奏計，莫嗟行路有崎嶇。"]'),
('03e10d43-a371-404c-aac9-140d24e2506f','送周仲章使君','王安石','宋','宋诗','song-poetry','','[]','看君東下霅溪船，迴首紛紛已五年。',64,'全唐诗/poet.song.32000.json','["看君東下霅溪船，迴首紛紛已五年。", "簪筆少留吾所望，剖符輕去此何緣。", "高麾行路穿秦樹，駿馬歸時著蜀鞭。", "子墨文章應滿篋，承明宣室正詳延。"]'),
('bb5621a6-431b-4f61-b5c0-3dcc8c9a82fa','送王蒙州','王安石','宋','宋诗','song-poetry','','[]','請郡東南促去程，拍堤江水照紅旌。',64,'全唐诗/poet.song.32000.json','["請郡東南促去程，拍堤江水照紅旌。", "仁聲已逐春風到，使節猶占夜斗行。", "箭落皁鵰毚兔避，句傳炎海鱷魚驚。", "麒麟不是人間物，漢詔先應召賈生。"]'),
('410413db-4184-4e3d-bae3-213eb3d42d93','送龐簽判','王安石','宋','宋诗','song-poetry','','[]','北都兩去不辭勤，仕路論材况出群。',64,'全唐诗/poet.song.32000.json','["北都兩去不辭勤，仕路論材况出群。", "一相開藩嘗負弩，三年通籍更從軍。", "清談猶得當時事，遺愛應從此日聞。", "我憶荆溪山最樂，看君摩翮上青雲。"]'),
('98415bea-51bc-4423-9fd8-97116808ff60','送潘景純','王安石','宋','宋诗','song-poetry','','[]','東都曾以一當千，場屋聲名十五年。',64,'全唐诗/poet.song.32000.json','["東都曾以一當千，場屋聲名十五年。", "晚賜綠衣隨宦牒，始操丹筆事戎旃。", "明時正欲精蒐選，榮路何當力薦延。", "頼有史君能好士，方看一鶚在秋天。"]'),
('3927d668-df4f-4c63-909d-b02b9256d028','送僧無惑歸鄱陽','王安石','宋','宋诗','song-poetry','','[]','晚扶衰憊寄人間，應接紛紛祇强顔。',64,'全唐诗/poet.song.32000.json','["晚扶衰憊寄人間，應接紛紛祇强顔。", "挂席每諳東匯水，採芝多夢舊遊山。", "故人獨往今爲樂，何日相隨我亦閑。", "歸見江東諸父老，爲言飛鳥會知還。"]'),
('94450e5e-c77b-4ee8-96cd-217519637ac8','送遜師歸舒州','王安石','宋','宋诗','song-poetry','','[]','山川相對一悲翁，往事紛紛夢寐中。',64,'全唐诗/poet.song.32000.json','["山川相對一悲翁，往事紛紛夢寐中。", "邂逅故人恩意在，低徊今日笑言同。", "看吹陌上楊花滿，忽憶巖前蕙帳空。", "亦見桐鄉諸父老，爲傳衰颯病春風。"]'),
('8fcd342b-925c-4c22-a033-adb3d6c8388a','寄育王大覺禪師','王安石','宋','宋诗','song-poetry','','[]','單已安那示入禪，草堂難望故依然。',64,'全唐诗/poet.song.32000.json','["單已安那示入禪，草堂難望故依然。", "山今歲暮終岑寂，人更天寒最靜便。", "隠迹亦知甘自足，憑心豈吝慰相憐。", "所聞不到荆門耳，人老禾新又一年。"]'),
('ae57bd38-d9dd-4077-97dc-e20cb00afb1d','寄無爲軍張居士','王安石','宋','宋诗','song-poetry','','[]','南陽居士月城翁，曾習禪那問色空。',64,'全唐诗/poet.song.32000.json','["南陽居士月城翁，曾習禪那問色空。", "卓犖想超文字外，低徊却寄語言中。", "真心妙道終無二，末學殊方自不同。", "此理世間多未悟，因君往往嘆西風。"]'),
('21f596b8-b394-4d23-b962-4fbece274315','次韵酬鄧子儀二首  其一','王安石','宋','宋诗','song-poetry','','[]','青溪相值各青春，老去臨流輒損神。',64,'全唐诗/poet.song.32000.json','["青溪相值各青春，老去臨流輒損神。", "事事只隨波浪去，年年空得鬢毛新。", "論心未忍遺橫目，干世還憂近逆鱗。", "嘉句感君邀我厚，自嗟才不異常人。"]'),
('a9f2db44-eb35-4528-bbb6-df6aef3e5a3d','次韵酬鄧子儀二首  其二','王安石','宋','宋诗','song-poetry','','[]','金陵邂逅府東偏，手得新蒲每共編。',64,'全唐诗/poet.song.32000.json','["金陵邂逅府東偏，手得新蒲每共編。", "采石偶耕垂百日，青溪並釣亦三年。", "君才有用方求祿，我志無成稍問田。", "一笑欲論心迹事，白頭相就且欹眠。"]'),
('819c089a-1d69-4a5a-9fe8-bf191ecc2c04','送李璋','王安石','宋','宋诗','song-poetry','','[]','湖海聲名二十年，尚隨鄉賦已華顛。',64,'全唐诗/poet.song.32000.json','["湖海聲名二十年，尚隨鄉賦已華顛。", "却歸甫里無三徑，擬傍胥山就一廛。", "朱轂風塵休悵望，青鞋雲水且留連。", "故人亦見如相問，爲道方尋木雁篇。"]'),
('3046e6bc-a49d-46f2-8a13-818e8554834f','送章宏','王安石','宋','宋诗','song-poetry','','[]','道合由來不易謀，豈無和氏識荆璆。',64,'全唐诗/poet.song.32000.json','["道合由來不易謀，豈無和氏識荆璆。", "一川濁水浮文鷁，千里輕帆落武丘。", "身退豈嫌吾道進，學成方悟衆人求。", "西風乞得東南守，杖策還能訪我不。"]'),
('55cf5ff3-0e80-4704-816e-8d8f649b5f89','別葛使君','王安石','宋','宋诗','song-poetry','','[]','邑屋爲儒知善政，市門多粟見豐年。',64,'全唐诗/poet.song.32000.json','["邑屋爲儒知善政，市門多粟見豐年。", "追攀更覺相逢晚，談笑難忘欲別前。", "客幙雅遊皆置榻，令堂清坐亦鳴弦。", "輕舟後夜滄江北，迴首春城空黯然。"]'),
('2e553b52-de32-44ff-92b3-cae8621d882c','送王龍圖守荆南','王安石','宋','宋诗','song-poetry','','[]','壯志高才偃一藩，更嗟賢路此時難。',64,'全唐诗/poet.song.32000.json','["壯志高才偃一藩，更嗟賢路此時難。", "長幡欲動何妨屈，老驥能行豈易閑。", "沙市放船寒月白，渚宮留御古苔斑。", "知公未厭還隨詔，歸看功名重太山。"]'),
('820537c4-0c0a-4419-b1fd-33de736af74e','次韵酬宋中散二首  其一','王安石','宋','宋诗','song-poetry','','[]','初見彤庭賜履雙，便參東閣寄南邦。',64,'全唐诗/poet.song.32000.json','["初見彤庭賜履雙，便參東閣寄南邦。", "時聞正論除疑網，每讀高辭折慢幢。", "陳迹欲尋無復日，舊恩思報有如江。", "風流今見佳公子，投老心旌一片降。"]'),
('c154b60e-7485-4544-b600-15e3f094d5f1','次韵酬宋中散二首  其二','王安石','宋','宋诗','song-poetry','','[]','超然京洛諒難雙，處在家庭譽在邦。',64,'全唐诗/poet.song.32000.json','["超然京洛諒難雙，處在家庭譽在邦。", "道義門中窺戶牖，風騷壇上見麾幢。", "素書款款誰憐杜，彩筆遒遒獨勝江。", "信美賢公有才子，篤誠真復類尨降。"]'),
('e18265b5-7438-460e-b34d-60a67e485e38','和宋太博服除還朝簡諸朋舊','王安石','宋','宋诗','song-poetry','','[]','呼門初起外廷臣，秀氣稜稜動搢紳。',64,'全唐诗/poet.song.32000.json','["呼門初起外廷臣，秀氣稜稜動搢紳。", "談論坐來能慰我，篇章傳出亦驚人。", "生芻一束他年闕，伐木相求此地新。", "便欲與君同樂處，窮通餘事不關身。"]'),
('cfa97ab0-5dff-4117-a283-0a8eeb3efe0d','次韵酬宋玘六首  其一','王安石','宋','宋诗','song-poetry','','[]','洗雨吹風一月春，山紅漫漫綠紛紛。',64,'全唐诗/poet.song.32000.json','["洗雨吹風一月春，山紅漫漫綠紛紛。", "褰裳遠野誰從我，散策空陂忽見君。", "青眼坐傾新歲酒，白頭追誦少年文。", "因嗟涉世終無補，久使高材雍上聞。"]'),
('45bb7cf5-9229-45a8-b614-566b7a05869f','次韵酬宋玘六首  其二','王安石','宋','宋诗','song-poetry','','[]','東風渺渺客天涯，病眼先春已見花。',64,'全唐诗/poet.song.32000.json','["東風渺渺客天涯，病眼先春已見花。", "遠欲報君羞强聒，老知隨俗厭雄誇。", "窮通往事真如夢，得失秋毫豈更嗟。", "邂逅故人唯有醉，醉中衣幘任欹斜。"]'),
('2cb54358-0e33-4af4-a9a7-218a3e022852','次韵酬宋玘六首  其三','王安石','宋','宋诗','song-poetry','','[]','城中燈火照青春，遠引吾方避糾紛。',64,'全唐诗/poet.song.32000.json','["城中燈火照青春，遠引吾方避糾紛。", "遊衍水邊追野馬，嘯歌林下應山君。", "愁尋徑草無求仲，喜對檐花有廣文。", "邂逅一樽聊酩酊，聲名身後豈須聞。"]'),
('ce556061-e9f0-49a0-bd04-7147ec896b1e','次韵酬宋玘六首  其四','王安石','宋','宋诗','song-poetry','','[]','遠迹荒郊謝儁豪，春風誰與駐干旄。',64,'全唐诗/poet.song.32000.json','["遠迹荒郊謝儁豪，春風誰與駐干旄。", "故交重趼恩何厚，新句連篇韵更高。", "美似狂酲初噉蔗，快如衰病得觀濤。", "久知壞冶成天巧，豈與人間共一陶。"]'),
('742ceafb-3abb-4c2f-9ebb-7c26ae9ec259','次韵酬宋玘六首  其五','王安石','宋','宋诗','song-poetry','','[]','無能私願祇求田，時物安能學計然。',64,'全唐诗/poet.song.32000.json','["無能私願祇求田，時物安能學計然。", "鑿井未成歌擊壤，射熊猶得夢鈞天。", "遥思故國歸來日，留滯新恩已去年。", "携手與君遊最樂，春風波上水濺濺。"]'),
('5c24cbc5-f3e3-4138-931a-a87c2379492b','次韵酬宋玘六首  其六','王安石','宋','宋诗','song-poetry','','[]','山陂疇昔從吾親，諸父先生各佩紛。',64,'全唐诗/poet.song.32000.json','["山陂疇昔從吾親，諸父先生各佩紛。", "零落長年誰語此，遲回故地却逢君。", "衣冠偶坐論經術，襁褓當時刺繡文。", "更怪高材終未遇，有司何日選方聞。"]'),
('5b6b8b11-361f-4701-9eb8-68a38f3f894d','寄吳正仲却蒙馬行之都官梅聖俞太博和寄依韵酬之','王安石','宋','宋诗','song-poetry','','[]','山水玄暉去後空，騷人還向此間窮。',64,'全唐诗/poet.song.32000.json','["山水玄暉去後空，騷人還向此間窮。", "小詩聊與論孤憤，大句安知辱兩雄。", "秦甲久愁荆劍利，趙兵今窘漢旗紅。", "背城不敢收餘燼，馬首翩翩只欲東。"]'),
('770dfe93-a8ed-48ae-865e-db2fa9620c66','寄平甫','王安石','宋','宋诗','song-poetry','','[]','少時爲學豈身謀，欲老低徊各自羞。',64,'全唐诗/poet.song.32000.json','["少時爲學豈身謀，欲老低徊各自羞。", "乘馬從徒真擾擾，求田問舍轉悠悠。", "弦歌舊國平生樂，鞍馬新年幾日留。", "坐想摇鞭楊柳路，春風先我入皇州。"]'),
('7df3849c-cd1a-42ab-91fa-e8fad58961d2','次韵舍弟常州官舍應客','王安石','宋','宋诗','song-poetry','','[]','霜雪紛紛上鬢毛，憂時自悔目空蒿。',64,'全唐诗/poet.song.32000.json','["霜雪紛紛上鬢毛，憂時自悔目空蒿。", "桑麻祇欲求三畝，勢利誰能算一毫。", "此地舊傳公子札，吾心真慕伯成高。", "飄然更有乘桴興，萬里寒江正復艚。"]'),
('c0421e7a-4c86-4fab-b24b-3f734902c255','舟還江南阻風有懷伯兄','王安石','宋','宋诗','song-poetry','','[]','幾時重接汝南評，兩槳留連不計程。',64,'全唐诗/poet.song.32000.json','["幾時重接汝南評，兩槳留連不計程。", "白浪黏天無限斷，玄雲垂野少晴明。", "平皋望望欲何向，薄宦嗟嗟空此行。", "會有開樽相勸日，鶺鴒隨處共飛鳴。"]'),
('59551677-df35-4109-a92d-aeac5f6b0a2a','同陳伯通錢材翁遊山二君有詩因次元韵','王安石','宋','宋诗','song-poetry','','[]','秋來閑興每登臨，因叩精藍望碧岑。',64,'全唐诗/poet.song.32000.json','["秋來閑興每登臨，因叩精藍望碧岑。", "强策羸驂尋水石，忽驚幽鳥下煙林。", "同時覽物悲歡異，自古忘名趣向深。", "安得湖山歸我手，靜看雲意學無心。"]'),
('646a164c-3881-428d-b937-5cc632b045ed','夢張劍州','王安石','宋','宋诗','song-poetry','','[]','萬里憐君蜀道歸，相逢似喜語還悲。',64,'全唐诗/poet.song.32000.json','["萬里憐君蜀道歸，相逢似喜語還悲。", "江淮別業依前處，日月新阡卜幾時。", "自說曲阿猶未穩，即尋湓水去猶疑。", "茫然却是陳橋夢，昨日春風馬上思。"]'),
('27e5ab26-4fe8-4a9a-8288-70464bd3ccb7','酬慕容員外','王安石','宋','宋诗','song-poetry','','[]','初駕王門學者師，晚漂湖海衆人悲。',64,'全唐诗/poet.song.32000.json','["初駕王門學者師，晚漂湖海衆人悲。", "吹毛未識腰間劍，刺股猶藏袖裏錐。", "衛霍功名還有命，蘇張才氣久非時。", "江尤亦見應須飲，莫放窮愁入兩眉。"]'),
('953d4859-9d49-4904-b3b9-bc511b7237c7','次韵張唐公馬上','王安石','宋','宋诗','song-poetry','','[]','揭節初悲力不任，賜身終愧謬恩臨。',64,'全唐诗/poet.song.32000.json','["揭節初悲力不任，賜身終愧謬恩臨。", "病來氣弱歸宜早，偷取官多責恐深。", "膏澤未施空謗怨，瘡痍猶在豈謳吟。", "黄昏信馬江城路，欲訪何人話此心。"]'),
('157873d0-ce65-433f-8e6c-8926ae5a0b58','和王司封會同年','王安石','宋','宋诗','song-poetry','','[]','收科天陛頃同時，回首相歡事亦稀。',64,'全唐诗/poet.song.32000.json','["收科天陛頃同時，回首相歡事亦稀。", "追講舊遊犀麈脫，交酬新唱彩箋飛。", "直須傾倒樽中酒，休惜淋浪坐上衣。", "日暮主翁留客轄，會稽聊滯買臣歸。"]'),
('06453d33-d401-4389-aa57-f773d7175c3a','次韵酬子玉同年','王安石','宋','宋诗','song-poetry','','[]','盛德無心漠北窺，蕃胡亦恐勢方羸。',64,'全唐诗/poet.song.32000.json','["盛德無心漠北窺，蕃胡亦恐勢方羸。", "塞垣高壘深溝地，幕府輕裘緩带時。", "趙將時皆思李牧，楚音身自感鍾儀。", "慚君許我論邊鎖，俎豆平生却少知。"]'),
('cc3342cc-ff9b-459c-9be7-31d703cfc150','和舍弟舟上示沈道源','王安石','宋','宋诗','song-poetry','','[]','還裝欲盡喜舟輕，更喜嘉賓伴此行。',64,'全唐诗/poet.song.32000.json','["還裝欲盡喜舟輕，更喜嘉賓伴此行。", "野飲不忘魚可釣，旅羹何惜雁能鳴。", "西山壯馬先歸牧，南穴殘梟欲就烹。", "憂國自多廊廟宰，與君詩酒盡交情。"]'),
('c693722f-4a8c-4119-9ee6-d5189081473d','過山即事','王安石','宋','宋诗','song-poetry','','[]','却過茲山已九年，江湖身世只飄然。',64,'全唐诗/poet.song.32000.json','["却過茲山已九年，江湖身世只飄然。", "曲城丘墓心空折，鹽步庭闈眼欲穿。", "慘慘野雲生隴底，蕭蕭饑馬立風前。", "轉多愁思摧華髮，早晚輕舟上秀川。"]'),
('e5f5a58c-0253-42de-bcce-8270cff5f720','酬裴如晦','王安石','宋','宋诗','song-poetry','','[]','二年羈旅越人吟，乞得東南病更侵。',64,'全唐诗/poet.song.32000.json','["二年羈旅越人吟，乞得東南病更侵。", "殤子未安莊氏義，壽親還慰魯侯心。", "鮮鮮細菊霜前蕊，漠漠疏桐日下陰。", "濁酒一杯秋滿眼，可憐同意不同斟。"]'),
('052cea32-37da-4e97-b09b-0dcd7fe06721','酬鄭閎中','王安石','宋','宋诗','song-poetry','','[]','蕭條行路欲華顛，迴首山林尚渺然。',64,'全唐诗/poet.song.32000.json','["蕭條行路欲華顛，迴首山林尚渺然。", "三釜祇知爲養急，五漿非敢在人先。", "文章滿世吾誰慕，行義如君衆所傳。", "宜有至言來助我，可能空寄好詩篇。"]'),
('47b24d44-1a38-4fe5-bc34-62c316cb1a8e','寄余溫卿','王安石','宋','宋诗','song-poetry','','[]','雲散風流不自禁，天涯無路盍朋簪。',64,'全唐诗/poet.song.32000.json','["雲散風流不自禁，天涯無路盍朋簪。", "空馳上國青泥信，誰和南山白石音。", "平日離愁寬带眼，訖春歸思滿琴心。", "終回一命翩翩駕，獨過嵇山鍛樹陰。"]'),
('fae1ec52-5d48-4ae2-bc28-b45844b236f1','寄郎侍郎','王安石','宋','宋诗','song-poetry','','[]','兩朝人物嘆賢豪，凜凜清風晚見褒。',64,'全唐诗/poet.song.32000.json','["兩朝人物嘆賢豪，凜凜清風晚見褒。", "江漢但歸滄海闊，丘陵難學太山高。", "放懷詩酒機先息，迴首功名世自勞。", "久願作公樽俎客，恨無三畝斲蓬蒿。"]'),
('da848764-125e-42b6-869a-f5d2a93e8f93','送道光法師住持靈巖','王安石','宋','宋诗','song-poetry','','[]','靈巖開闢自何年，草木神奇鳥獸仙。',64,'全唐诗/poet.song.32000.json','["靈巖開闢自何年，草木神奇鳥獸仙。", "一路紫苔通窅窱，千崖青靄落潺湲。", "山祇嘯聚荒禪室，象衆低摧想法筵。", "雪足莫辭重趼往，東人香火有因緣。"]'),
('cd554d3d-ac9b-45ea-a984-05e1ce735831','奉酬永叔見贈','王安石','宋','宋诗','song-poetry','','[]','欲傳道義心猶在，强學文章力已窮。',64,'全唐诗/poet.song.32000.json','["欲傳道義心猶在，强學文章力已窮。", "他日若能窺孟子，終身何敢望韓公。", "摳衣最出諸生後，倒屣嘗傾廣座中。", "祇恐虛名因此得，嘉篇爲貺豈宜蒙。"]'),
('0cb2aa03-7d9a-4549-9d50-395f44fb9b4c','送陳舜俞制科東歸','王安石','宋','宋诗','song-poetry','','[]','諸賢發策未央宮，獨得菑川一老翁。',64,'全唐诗/poet.song.32000.json','["諸賢發策未央宮，獨得菑川一老翁。", "曲學暮年終漢相，高談平日漫周公。", "君今壯歲收科第，我欲它時看事功。", "聞說慨然真有意，贈行聊似古人風。"]'),
('812240c6-73f9-4147-a6c0-696c4cc5b857','送何正臣主簿','王安石','宋','宋诗','song-poetry','','[]','何郎冰雪照青春，應敵皆言筆有神。',64,'全唐诗/poet.song.32000.json','["何郎冰雪照青春，應敵皆言筆有神。", "魯國儒人何獨少，元君畫史故應真。", "百年冠蓋風雲會，萬里山川日月新。", "可但諸公能品藻，會須天子擢平津。"]'),
('863bcfad-a9d1-49d6-ad05-b3bfc6e84fa9','與舍弟華藏院此君亭咏竹','王安石','宋','宋诗','song-poetry','','[]','一逕森然四座凉，殘陰餘韵去何長。',64,'全唐诗/poet.song.32000.json','["一逕森然四座凉，殘陰餘韵去何長。", "人憐直節生來瘦，自許高材老更剛。", "會與蒿藜同雨露，終隨松柏到冰霜。", "煩君惜取根株在，欲乞伶倫學鳳凰。"]'),
('fb2557ed-626b-481d-84b6-d61e063dfd78','上元戲呈貢父','王安石','宋','宋诗','song-poetry','','[]','車馬紛紛白晝同，萬家燈火暖春風。',64,'全唐诗/poet.song.32000.json','["車馬紛紛白晝同，萬家燈火暖春風。", "別開閶闔壺天外，特起蓬萊陸海中。", "盡取繁華供俠少，祇分牢落與衰翁。", "不知太乙遊何處，定把青藜獨照公。"]'),
('ec0f13c8-0f4e-42cb-b610-4ccef657e74c','次韵楊樂道述懷之作','王安石','宋','宋诗','song-poetry','','[]','素心非不慕前修，自怪因循欲白頭。',64,'全唐诗/poet.song.32000.json','["素心非不慕前修，自怪因循欲白頭。", "獵較趣時終瑣瑣，畫墁營職信悠悠。", "濠梁最憶知魚樂，牢策翻慚爲彘謀。", "尚有故人能慰我，詩成珠玉每相投。"]'),
('07a7abb0-0677-4d69-8afc-8863269358cd','和楊樂道見寄','王安石','宋','宋诗','song-poetry','','[]','宅带園林五畝餘，蕭條還似茂陵居。',64,'全唐诗/poet.song.32000.json','["宅带園林五畝餘，蕭條還似茂陵居。", "殺青滿架書新繕，生白當窗室久虛。", "孤學自難窺奧密，重言猶得慰空疏。", "相思每欲投詩社，只待春蒲葉又書。"]'),
('fd4d74cb-a225-4ff3-8f63-fe8cdb3640a9','寄吳沖卿二首  其一','王安石','宋','宋诗','song-poetry','','[]','平生身事略相同，三歲連牆左廏中。',64,'全唐诗/poet.song.32000.json','["平生身事略相同，三歲連牆左廏中。", "更得謬恩分省舍，又將衰鬢作鄰翁。", "聯翩久傍官槐綠，契闊今看楚蓼紅。", "不欲與君爲遠別，沙臺吹帽約秋風。"]'),
('d48af3df-673e-4dc0-b1ee-3e9064c433d2','寄吳沖卿二首  其二','王安石','宋','宋诗','song-poetry','','[]','塞垣花氣欲飛浮，眼底紛紛綠漸抽。',64,'全唐诗/poet.song.32000.json','["塞垣花氣欲飛浮，眼底紛紛綠漸抽。", "悠遠山川嗟我老，急難兄弟想君愁。", "舊知白日諸曹滿，試問紅燈幾客留。", "時節只應無意思，亦如行路判春休。"]'),
('f797f995-e4a8-4186-bd68-70dce3c6fa34','酬沖卿見別','王安石','宋','宋诗','song-poetry','','[]','同官同齒復同科，朋友婚姻分最多。',64,'全唐诗/poet.song.32000.json','["同官同齒復同科，朋友婚姻分最多。", "兩地塵沙今齟齬，二年風月共婆娑。", "朝倫孰與君材似，使指將如我病何。", "升黜會應從此異，願偷閑暇數經過。"]'),
('496df998-6409-4151-ad6a-19f51200374c','次御河寄城北會上諸友','王安石','宋','宋诗','song-poetry','','[]','客路花時祇攪心，行逢御水半晴陰。',64,'全唐诗/poet.song.32000.json','["客路花時祇攪心，行逢御水半晴陰。", "背城野色雲邊盡，隔屋春聲樹外深。", "香草已堪回步履，午風聊復散衣襟。", "憶君載酒相追處，紅萼青跗定滿林。"]'),
('daa2cbb5-57f7-4806-b32e-419fc8749b9e','寄友人三首  其一','王安石','宋','宋诗','song-poetry','','[]','萬里書歸說我愁，知君不忘北城幽。',64,'全唐诗/poet.song.32000.json','["萬里書歸說我愁，知君不忘北城幽。", "一篇封禪才難學，三畝蓬蒿勢易求。", "欲與山僧論地券，願爲鄰舍事田疇。", "應須急作南征計，漠北風沙不可留。"]'),
('249ce177-6150-43c5-867f-6033df1127d0','寄友人三首  其二','王安石','宋','宋诗','song-poetry','','[]','水邊幽樹憶同攀，曾約移居向此間。',64,'全唐诗/poet.song.32000.json','["水邊幽樹憶同攀，曾約移居向此間。", "欲語林塘迷舊徑，却隨車馬入他山。", "飛花著地容難冶，鳴鳥窺人意轉閑。", "物色可歌春不返，相思空復慘朱顔。"]'),
('d3383c21-f334-4243-baef-c7b8f0e76b92','寄友人三首  其三','王安石','宋','宋诗','song-poetry','','[]','一別三年各一方，此身漂蕩只殊鄉。',64,'全唐诗/poet.song.32000.json','["一別三年各一方，此身漂蕩只殊鄉。", "看沙更覺蓬萊淺，數日空驚霹靂忙。", "渺渺水波低赤岸，濛濛雲氣淡扶桑。", "登臨舊興無多在，但有浮槎意未忘。"]'),
('da27255d-b7ca-4694-8d78-6c48b23e751d','寄張襄州','王安石','宋','宋诗','song-poetry','','[]','襄陽州望古來雄，耆舊相傳有素風。',64,'全唐诗/poet.song.32000.json','["襄陽州望古來雄，耆舊相傳有素風。", "四葉表閭唐尹氏，一門逃世漢龐公。", "故家遺俗應多在，美景良辰定不空。", "遥憶習池寒夜月，幾人談笑伴詩翁。"]'),
('1ba444f2-15de-4e7d-8f31-acec8c86ab1c','次韵昌叔懷灊樓讀書之樂','王安石','宋','宋诗','song-poetry','','[]','志食長年不得休，一巢無地拙於鳩。',64,'全唐诗/poet.song.32000.json','["志食長年不得休，一巢無地拙於鳩。", "聊爲薄宦容身者，能免高人笑我不。", "道德文章吾事落，塵埃波浪此生浮。", "看君別後行藏意，回顧灊樓祇自羞。"]'),
('56845be8-d491-4bf4-8394-bc02236cffc5','酬浄因長老樓上翫月見懷有疑君魂夢在清都之句','王安石','宋','宋诗','song-poetry','','[]','道人心與世無求，隠几蕭然在此樓。',64,'全唐诗/poet.song.32000.json','["道人心與世無求，隠几蕭然在此樓。", "坐對高梧傾曉月，看翻清露洗新秋。", "登臨更欲邀元亮，披寫還能擬惠休。", "顧我不知天上樂，虛疑昨夜夢仙遊。"]'),
('596a33db-8d64-4de9-b42d-cf43afcbfcb3','寄張諤招張安國金陵法曹','王安石','宋','宋诗','song-poetry','','[]','我老願爲臧丈人，君今少壯豈長貧。',64,'全唐诗/poet.song.32000.json','["我老願爲臧丈人，君今少壯豈長貧。", "好須自致青冥上，可且相從寂寞濱。", "深谷黄鸝嬌引子，曲碕翠碧巧藏身。", "尋幽觸靜還成興，何必區區九陌塵。"]'),
('0fea721b-6c4c-41d1-b1f8-99d5f6044a28','欲往浄因寄涇州韓持國','王安石','宋','宋诗','song-poetry','','[]','紫荆山下物華新，只與都城共一春。',64,'全唐诗/poet.song.32000.json','["紫荆山下物華新，只與都城共一春。", "令節想君携綠酒，故情憐我踏黄塵。", "泔魚已悔他年事，搏虎方收末路身。", "欲寄微言書不盡，試尋僧閣望西人。"]'),
('270e2ef8-d404-479d-a35d-ce0c22312ead','送別韓虞部','王安石','宋','宋诗','song-poetry','','[]','客舍街南初著巾，與君兄弟即相親。',64,'全唐诗/poet.song.32000.json','["客舍街南初著巾，與君兄弟即相親。", "當年豈意兩家子，今日更爲同社人。", "京洛風塵嗟阻闊，江湖杯酒惜逡巡。", "歸帆嶺北茫茫水，把手何時寂寞濱。"]'),
('ff1c120f-158c-401b-a9a6-86c88bdefe51','懷舒州山水呈昌叔','王安石','宋','宋诗','song-poetry','','[]','山下飛鳴黄栗留，溪邊飲啄白符鳩。',64,'全唐诗/poet.song.32000.json','["山下飛鳴黄栗留，溪邊飲啄白符鳩。", "不知此地從君處，亦有他人繼我不。", "塵土生涯休盪滌，風波時事只飄浮。", "相看髮禿無歸計，一夢東南即自羞。"]'),
('110cc50c-b3ea-4057-92ec-2940c2c8e96f','呈柳子玉同年','王安石','宋','宋诗','song-poetry','','[]','三年不上鄴王臺，鴻雁歸時又北來。',64,'全唐诗/poet.song.32000.json','["三年不上鄴王臺，鴻雁歸時又北來。", "水底舊波吹歲換，柳梢新葉卷春回。", "塵沙漠漠凋雙鬢，簫鼓匆匆把一杯。", "勞事欲歌無與和，衰顔思見故人開。"]'),
('04a490ef-77a1-47c2-b6be-8a77803a07b4','次韵陸定遠以謫往來求詩','王安石','宋','宋诗','song-poetry','','[]','牢落何由共一樽，相望空復嘆芝焚。',64,'全唐诗/poet.song.32000.json','["牢落何由共一樽，相望空復嘆芝焚。", "濟時尚負生平學，慰我應多別後文。", "可但風流追甫白，由來家世出機雲。", "行吟强欲偷新格，自笑安能到萬分。"]'),
('ba21ef65-12a2-43cb-87c1-dafb47418c8a','李璋下第','王安石','宋','宋诗','song-poetry','','[]','浩蕩宮門白日開，君王高拱試群材。',64,'全唐诗/poet.song.32000.json','["浩蕩宮門白日開，君王高拱試群材。", "學如吾子何憂失，命屬天公不可猜。", "意氣未宜輕感慨，文章尤忌數悲哀。", "男兒獨患無名爾，將相誰云有種哉。"]'),
('ae1dd328-46dc-47df-af4e-d379fb44c415','送楊驥秀才歸鄱陽','王安石','宋','宋诗','song-poetry','','[]','客舍風塵弊綵衣，悲吟重見雁南飛。',64,'全唐诗/poet.song.32000.json','["客舍風塵弊綵衣，悲吟重見雁南飛。", "荆山和氏方三獻，太學何生且一歸。", "曠野已寒諳獨宿，長年多難惜分違。", "巾箱所得皆幽懿，亦見鄉人爲發揮。"]'),
('83c93eed-99f3-4763-87f6-c8aab9334c8d','平山堂','王安石','宋','宋诗','song-poetry','','[]','城北橫岡走翠虬，一堂高視兩三州。',64,'全唐诗/poet.song.32000.json','["城北橫岡走翠虬，一堂高視兩三州。", "淮岑日對朱欄出，江岫雲齊碧瓦浮。", "墟落耕桑公愷悌，杯觴談笑客風流。", "不知峴首登臨處，壯觀當時有此不。"]'),
('bf850292-bbdd-43ba-b925-f59863975ae8','示德逢','王安石','宋','宋诗','song-poetry','','[]','先生貧敝古人風，{糹丐}想柴桑在眼中。',67,'全唐诗/poet.song.32000.json','["先生貧敝古人風，{糹丐}想柴桑在眼中。", "憐愍雞豚非孟子，勤勞禾黍信周公。", "深藏組麗三千牘，靜占寬閑五百弓。", "處世但令心自可，相知何藉一劉龔。"]'),
('1211bb78-3d19-4f0b-93e3-f47f2dac9565','示四妹','王安石','宋','宋诗','song-poetry','','[]','孟光求婿得梁鴻，廡下相隨不諱窮。',64,'全唐诗/poet.song.32000.json','["孟光求婿得梁鴻，廡下相隨不諱窮。", "卓犖才名今日事，蕭條門巷古人風。", "五噫尚與時多忤，一笑兼忘我屢空。", "六月塵沙不相貸，泫然搔首又西東。"]'),
('ef327540-7b99-46c7-986a-e71c1ec23b22','寄酬曹伯玉因以招之','王安石','宋','宋诗','song-poetry','','[]','寒鴉對立西風樹，幽草環生白露庭。',64,'全唐诗/poet.song.32000.json','["寒鴉對立西風樹，幽草環生白露庭。", "清坐苦無公事擾，高談時有故人經。", "思君異日投朱紱，過我何時載淥醽。", "及此江湖氣蕭爽，最宜相值倒吾瓶。"]'),
('944932f4-72bd-4ec5-af82-6779284376f4','次韵奉酬李質夫','王安石','宋','宋诗','song-poetry','','[]','逸少池邊有舊山，幾年征淚染衣斑。',64,'全唐诗/poet.song.32000.json','["逸少池邊有舊山，幾年征淚染衣斑。", "駑駘自飽方爭路，騕褭長饑不在閑。", "雪漲江南歸浩蕩，煙埋河朔去間關。", "勞歌一聽皆愁思，况我心非木石頑。"]'),
('ff9b73ee-b8c0-41ce-884d-0690823d80aa','寄袁州曹伯玉使君','王安石','宋','宋诗','song-poetry','','[]','宜春城郭繞樓臺，想見登臨把一杯。',64,'全唐诗/poet.song.32000.json','["宜春城郭繞樓臺，想見登臨把一杯。", "濕濕嶺雲生竹箘，冥冥江雨熟楊梅。", "政成定入邦人咏，詩就還隨驛使來。", "錯莫風沙愁病眼，不知何日爲君開。"]'),
('c351ab99-d5c1-4541-97e7-e7128b14f186','邢太保有鶴折翼以詩傷之客有記翎經冥三韵而忘其詩者因作四韵','王安石','宋','宋诗','song-poetry','','[]','不爲摧傷改性靈，靜中猶見好儀形。',64,'全唐诗/poet.song.32000.json','["不爲摧傷改性靈，靜中猶見好儀形。", "每憐今日長垂翅，却悔當時誤翦翎。", "醫得舊創猶有法，相知多難豈無經。", "稻粱且向人間覓，莫羨摶風起北冥。"]'),
('6f9844eb-e6ea-4eaf-ba8f-918509e7c4b0','寄致政吳虞部','王安石','宋','宋诗','song-poetry','','[]','白鷗生意在滄波，不爲風塵有網羅。',64,'全唐诗/poet.song.32000.json','["白鷗生意在滄波，不爲風塵有網羅。", "年抵馮唐初未半，才方疏廣豈能多。", "孤清楚國知誰繼，遺愛郴人想共歌。", "嗟我欲歸真未晚，雪舟乘興會相過。"]'),
('073a41c5-9a6c-4d0d-887d-5fcf66a6a3b2','再至京口寄漕使曹郎中','王安石','宋','宋诗','song-poetry','','[]','漂流曾落此江邊，憶與詩翁賦浩然。',64,'全唐诗/poet.song.32000.json','["漂流曾落此江邊，憶與詩翁賦浩然。", "鄉國去身猶萬里，驛亭分首已三年。", "北城紅出高枝靚，南浦青回老樹圓。", "還似昔時風露好，只疑談笑在君前。"]'),
('5f721a5e-08b3-41dd-ba86-9dd66b7dc1b4','次韵平甫金山會宿寄親友','王安石','宋','宋诗','song-poetry','','[]','天末海門橫北固，煙中沙岸似西興。',64,'全唐诗/poet.song.32000.json','["天末海門橫北固，煙中沙岸似西興。", "已無船舫猶聞笛，遠有樓臺祗見燈。", "山月入松金破碎，江風吹水雪崩騰。", "飄然欲作乘桴計，一到扶桑恨未能。"]'),
('cc19cf8f-7c67-44b3-b607-67348c4df0fd','送何聖從龍圖','王安石','宋','宋诗','song-poetry','','[]','射策曾稱蜀郡雄，朝廷重得漢司空。',64,'全唐诗/poet.song.32000.json','["射策曾稱蜀郡雄，朝廷重得漢司空。", "應留賜席丹塗地，誤責飛芻紫塞功。", "三徑欲歸無舊業，百城先至有清風。", "潞山直與天爲黨，回首孫高想見公。"]'),
('d8b926a6-5685-4076-833d-328831d8ae8d','送趙學士陝西提刑','王安石','宋','宋诗','song-poetry','','[]','遥知彼俗經兵後，應望名公走馬來。',64,'全唐诗/poet.song.32000.json','["遥知彼俗經兵後，應望名公走馬來。", "陛下柬求今日始，胸中包畜此時開。", "山西豪傑歸囊牘，渭北風光入酒杯。", "堪笑陋儒昏鄙甚，略無謀術贊行臺。"]'),
('04d13db4-0306-47ec-9235-1403c99c984c','丙申八月作','王安石','宋','宋诗','song-poetry','','[]','秋風摧剝利如刀，漠漠昏煙玩日高。',64,'全唐诗/poet.song.32000.json','["秋風摧剝利如刀，漠漠昏煙玩日高。", "眼看南山露崖窾，心隨東水轉波濤。", "歸期正自憑蓍蔡，生理應須問酒醪。", "還有詩書能慰我，不多霜雪上顛毛。"]'),
('b23e9b0e-4304-4ca6-b67c-cdcdab99788b','登西樓','王安石','宋','宋诗','song-poetry','','[]','樓影侵雲百尺斜，行人樓上憶天涯。',64,'全唐诗/poet.song.32000.json','["樓影侵雲百尺斜，行人樓上憶天涯。", "情多自悔登臨數，目極應驚悵望賒。", "一曲平蕪連古樹，半分殘日带明霞。", "潘郎何用悲秋色，祇此傷春髮已華。"]'),
('2dbbd8e6-7bbf-4b55-9665-1cf08c1673ee','即事','王安石','宋','宋诗','song-poetry','','[]','河流南苑岸西斜，風有晶光露有華。',64,'全唐诗/poet.song.32000.json','["河流南苑岸西斜，風有晶光露有華。", "門柳故人陶令宅，井桐前日總持家。", "嘉招欲覆杯中淥，麗唱仍添錦上花。", "便作武陵樽俎客，川源應未少紅霞。"]'),
('71ad3dfe-bac8-4f1d-9b7c-0001b1ea7932','酬吳仲庶小園之句','王安石','宋','宋诗','song-poetry','','[]','舊年臺榭掃流塵，職閉朱門歲又新。',64,'全唐诗/poet.song.32000.json','["舊年臺榭掃流塵，職閉朱門歲又新。", "花影隙中看裊裊，車音牆外去轔轔。", "相逢豈少佳公子，一醉何妨薄主人。", "祇向東風邀載酒，定知無奈帝城春。"]'),
('234909ff-a7c0-49b6-b161-808146b4d5f7','始與韓玉汝相近居遂相與遊今居復相近而兩家子唱和詩相屬因有此作','王安石','宋','宋诗','song-poetry','','[]','羈旅兒童得近鄰，相知邂逅即情親。',64,'全唐诗/poet.song.32000.json','["羈旅兒童得近鄰，相知邂逅即情親。", "當時豈意兩家子，此地更爲同社人。", "勳業彈冠知白首，文章投筆讓青春。", "萬金雖愧君多産，比我淵明亦未貧。"]'),
('ba4528ff-a63d-47eb-826d-88040ee9bb50','春寒','王安石','宋','宋诗','song-poetry','','[]','春風滿地月如霜，拂曉鍾聲到景陽。',64,'全唐诗/poet.song.32000.json','["春風滿地月如霜，拂曉鍾聲到景陽。", "花底裌衣朝宿衛，柳邊新火起嚴粧。", "冰殘玉甃泉初動，水澀銅壺漏更長。", "從此暄妍知幾日，便應鶗鴂損年芳。"]'),
('537aae75-6c1b-43bb-9fed-9cdf34182ecc','次韵再遊城西李園','王安石','宋','宋诗','song-poetry','','[]','京師花木類多奇，常恨春歸人未歸。',64,'全唐诗/poet.song.32000.json','["京師花木類多奇，常恨春歸人未歸。", "車馬喧喧走塵土，園林處處鎖芳菲。", "殘紅已落香猶在，羈客多傷涕自揮。", "我亦悠悠無事者，約君聯騎訪郊圻。"]'),
('25dab787-9dcb-4f8e-9a95-e59c647bef8f','予求守江陰未得酬昌叔憶江陰見及之作','王安石','宋','宋诗','song-poetry','','[]','黄田港北水如天，萬里風檣看賈船。',64,'全唐诗/poet.song.32000.json','["黄田港北水如天，萬里風檣看賈船。", "海外珠犀常入市，人間魚蟹不論錢。", "高亭笑語如昨日，末路塵沙非少年。", "强乞一官終未得，祇君同病肯相憐。"]'),
('d78c8a10-49d2-4795-ba05-6bcd4df5b725','送蘇屯田廣西轉運','王安石','宋','宋诗','song-poetry','','[]','置將從來欲善師，百城蹉跌起毫釐。',64,'全唐诗/poet.song.32000.json','["置將從來欲善師，百城蹉跌起毫釐。", "驅除久費兵符出，按撫紛煩使節移。", "恩澤易行窮苦後，功名常見急難時。", "孺文此日風流在，直筆他年豈愧辭。"]'),
('f0714e6d-ef2e-46dd-990f-2464437b34c9','酬淮南提刑邵不疑學士','王安石','宋','宋诗','song-poetry','','[]','曾咏常州送主人，豈知身得兩朱輪。',64,'全唐诗/poet.song.32000.json','["曾咏常州送主人，豈知身得兩朱輪。", "田疇汎濫川方壅，厨傳蕭條市亦貧。", "以我薄材思拊傴，頼君餘教得因循。", "詢求故有風謠在，不獨鑱詩尚未泯。"]'),
('d3f54b03-1baa-4894-87e3-8545e47b4c36','酬王太祝','王安石','宋','宋诗','song-poetry','','[]','一馬常隨世事馳，豈論江徼與河湄。',64,'全唐诗/poet.song.32000.json','["一馬常隨世事馳，豈論江徼與河湄。", "已成白髮潘常侍，更似青衫杜拾遺。", "勳業儻來知有命，文章聊欲見無期。", "喜君材俊能從我，力學何妨和子思。"]'),
('09a29930-904d-461c-9831-b2e70621b6e8','出城訪無黨因宿齋館','王安石','宋','宋诗','song-poetry','','[]','關外尋君信馬蹄，漫成詩句任天倪。',64,'全唐诗/poet.song.32000.json','["關外尋君信馬蹄，漫成詩句任天倪。", "花枝到眼春相照，山色侵衣晚自迷。", "今日笑談還喜共，經年勞逸固難齊。", "生涯零落歸心懶，多謝慇懃杜宇啼。"]'),
('ff85805e-6836-4ec1-85ee-b775d7fdeb46','寄張氏女弟','王安石','宋','宋诗','song-poetry','','[]','十年江海別常輕，豈料今隨寡嫂行。',64,'全唐诗/poet.song.32000.json','["十年江海別常輕，豈料今隨寡嫂行。", "心折向誰論宿昔，魂來空復夢平生。", "音容想像猶如昨，歲月蕭條忽已更。", "知汝此悲還似我，欲爲西望涕先橫。"]'),
('42b65e4e-2be9-4e9a-85c3-fe7f7319c99f','奉寄子思以代別','王安石','宋','宋诗','song-poetry','','[]','南北蹉跎成兩翁，悲歡邂逅笑言同。',64,'全唐诗/poet.song.32000.json','["南北蹉跎成兩翁，悲歡邂逅笑言同。", "全家欲出嶺雲外，匹馬肯尋山雨中。", "趨府折腰嗟踽踽，聽泉分手惜匆匆。", "寄聲但有加餐飯，才業如君豈久窮。"]'),
('5e5bedd3-9f63-41ce-aecb-fa70a974cae2','次韵劉著作過茆山今平甫往遊因寄','王安石','宋','宋诗','song-poetry','','[]','華陽仙伯有茆卿，官府今傳在赤城。',64,'全唐诗/poet.song.32000.json','["華陽仙伯有茆卿，官府今傳在赤城。", "三鶴不歸猶地勝，二君能到亦心清。", "詩中慷慨悲陳迹，篇末慇懃奬後生。", "遥想青雲知可附，坐看閭巷得名聲。"]'),
('8838b889-bece-48c8-9d7d-4ecfbb6f41ab','次韵十四叔賜詩留別','王安石','宋','宋诗','song-poetry','','[]','窮冬追路出西津，得侍茫然兩見春。',64,'全唐诗/poet.song.32000.json','["窮冬追路出西津，得侍茫然兩見春。", "發冊久嗟淹國士，起家初命慰鄉人。", "行辭北闕樓臺麗，歸佐南州縣邑新。", "班草數行衣上淚，何時杖屨却相親。"]'),
('098fc745-3bd7-4e0b-977a-d844e9b8e15e','次韵耿天騭大風','王安石','宋','宋诗','song-poetry','','[]','雲埋月缺暈寒灰，飈發齊如巨象豗。',64,'全唐诗/poet.song.32000.json','["雲埋月缺暈寒灰，飈發齊如巨象豗。", "縱勇萬川冰柱立，紛披千障土囊開。", "魯門未怪爰居至，鄭圃何妨禦寇來。", "終夜不眠誰與共，坐忘唯有一顔回。"]'),
('46926a1b-f446-4572-971c-2d8dbadfb082','法喜寺','王安石','宋','宋诗','song-poetry','','[]','門前白道自縈回，門下青莎間綠苔。',64,'全唐诗/poet.song.32000.json','["門前白道自縈回，門下青莎間綠苔。", "雜樹繞花鶑引去，壞簷無幕雁歸來。", "寂寥誰共樽前酒，牢落空留案上杯。", "我憶故鄉誠不淺，可憐鶗鴂重相催。"]'),
('e2c5bedc-5f23-4735-ad75-0a6ed1028e46','長干寺','王安石','宋','宋诗','song-poetry','','[]','梵館清閑側布金，小塘回曲翠文深。',64,'全唐诗/poet.song.32000.json','["梵館清閑側布金，小塘回曲翠文深。", "柳條不動千絲直，荷葉相依萬蓋陰。", "漠漠岑雲相上下，翩翩沙鳥自浮沈。", "羈人樂此忘歸思，忍向西風學越吟。"]'),
('c66a5286-d527-4412-ab07-b70c454bfff2','落星寺','王安石','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','崒雲臺殿起崔嵬，萬里長江一酒杯。',64,'全唐诗/poet.song.32000.json','["崒雲臺殿起崔嵬，萬里長江一酒杯。", "坐見山川吞日月，杳無車馬送塵埃。", "雁飛雲路聲低過，客近天門夢易迴。", "勝概唯詩可收拾，不才羞作等閑來。"]'),
('5173505b-1373-4f8f-8397-cf8ce6970cf5','清風閣','王安石','宋','宋诗','song-poetry','','[]','飛甍孤起下州牆，勝勢崢嶸壓四方。',64,'全唐诗/poet.song.32000.json','["飛甍孤起下州牆，勝勢崢嶸壓四方。", "遠引江山來控带，平看鷹隼去飛翔。", "高蟬感耳何妨靜，赤日焦心不廢凉。", "况是使君無一事，日陪賓從此傾觴。"]'),
('156e2bc5-aedb-4f4c-bf43-99aad9210d10','留題微之廨中清輝閣','王安石','宋','宋诗','song-poetry','','[]','故人名字在瀛洲，邂逅低徊向此留。',64,'全唐诗/poet.song.32000.json','["故人名字在瀛洲，邂逅低徊向此留。", "鷗鳥一雙隨坐嘯，荷花十丈對冥搜。", "水涵樽俎清如洗，山染衣巾翠欲流。", "宣室應疑鬼神事，知君能復幾來遊。"]'),
('76a94bb8-d5e8-4b86-a4a0-bb74f0fe2fb4','次韵和甫春日金陵登臺','王安石','宋','宋诗','song-poetry','','[]','鍾山漠漠水洄洄，西有陵雲百尺臺。',64,'全唐诗/poet.song.32000.json','["鍾山漠漠水洄洄，西有陵雲百尺臺。", "萬物已隨和氣動，一樽聊與故人來。", "天邊幽鳥鳴相和，地上晴煙掃不開。", "愁眼看春長恐盡，直須去取六龍回。"]'),
('e89733c2-9de6-470a-8fa4-e07cc8cf8cfd','慶老堂','王安石','宋','宋诗','song-poetry','','[]','板輿去國宦三年，華屋歸來地一偏。',64,'全唐诗/poet.song.32000.json','["板輿去國宦三年，華屋歸來地一偏。", "種竹常疑出冬筍，開池故合涌寒泉。", "身閑楚老猶能戲，道勝鄒人不更遷。", "嗟我强顔無所及，想君爲樂更焦然。"]'),
('8d5c14b8-b239-44be-b40a-30894ce690b9','寄陳宣叔','王安石','宋','宋诗','song-poetry','','[]','扁舟欲動更徘徊，一笑相看病眼開。',64,'全唐诗/poet.song.32000.json','["扁舟欲動更徘徊，一笑相看病眼開。", "事忤貴人今見節，政行豪縣衆稱材。", "忽驚歲月侵雙鬢，却喜山川共一杯。", "落日亂流江北去，離心猶與水東迴。"]'),
('7b993de7-75a5-45a6-b522-e574ae94ef6d','寄張劍州并示女弟','王安石','宋','宋诗','song-poetry','','[]','劍閣天梯萬里寒，春風此日白衣冠。',64,'全唐诗/poet.song.32000.json','["劍閣天梯萬里寒，春風此日白衣冠。", "烏辭反哺顛毛黑，鳥引思歸口血丹。", "行路想君今眚瘦，相逢添我老悲酸。", "浮雲渺渺吹西去，每到原頭勒馬看。"]'),
('88b654ab-cc35-4d75-9254-82f2d23c4ca4','元珍以詩送綠石硯所謂玉堂新樣者','王安石','宋','宋诗','song-poetry','','[]','玉堂新樣世爭傳，况以蠻溪綠石鎸。',64,'全唐诗/poet.song.32000.json','["玉堂新樣世爭傳，况以蠻溪綠石鎸。", "嗟我長來無異物，愧君持贈有佳篇。", "久埋瘴霧看猶濕，一取春波洗更鮮。", "還與故人袍色似，論心於此亦同堅。"]'),
('eb4a08c4-0863-4de0-9a7f-276f0e047575','和微之林亭','王安石','宋','宋诗','song-poetry','','[]','爲有檀欒占雒陽，憶歸杖策此徜徉。',64,'全唐诗/poet.song.32000.json','["爲有檀欒占雒陽，憶歸杖策此徜徉。", "觀魚得意還知樂，入鳥忘機肯亂行。", "未敢許君輕去國，不應如我漫爲郎。", "中園日涉非無趣，保此千鍾慰北堂。"]'),
('4fc500a3-a173-402a-af29-c354d999d742','酬微之梅暑新句','王安石','宋','宋诗','song-poetry','','[]','江梅落盡雨昏昏，去馬來牛漫不分。',64,'全唐诗/poet.song.32000.json','["江梅落盡雨昏昏，去馬來牛漫不分。", "當此沈陰無白日，豈知炎旱有彤雲。", "琴絃欲緩何妨促，畫蠹微生故可熏。", "回首凉秋知未遠，會須重曝阮郎褌。"]'),
('011535a4-bb53-4bb3-9428-98bdc25923a9','平甫與寶覺遊金山思大覺并見寄及相見得詩次韵二首  其一','王安石','宋','宋诗','song-poetry','','[]','寵參時宰道人琳，氣蓋諸公弟季心。',64,'全唐诗/poet.song.32000.json','["寵參時宰道人琳，氣蓋諸公弟季心。", "勝踐肯論山在險，冥搜欲與海爭深。", "摇摇北下隨帆影，踽踽東來想足音。", "握手更知禪伯遠，隔雲靈鷲碧千尋。"]'),
('c44e9840-38da-4a73-a7b5-96dc474c762d','平甫與寶覺遊金山思大覺并見寄及相見得詩次韵二首  其二','王安石','宋','宋诗','song-poetry','','[]','漳南開士好叢林，慧劍何年出水心。',64,'全唐诗/poet.song.32000.json','["漳南開士好叢林，慧劍何年出水心。", "獨往便應諸漏盡，相逢未免故情深。", "檻窺山鳥有真意，窗聽海潮非世音。", "一笑上方人事外，不知衰境兩侵尋。"]'),
('60135431-d5ad-4f40-a02c-1579c48d37d4','金陵懷古四首  其一','王安石','宋','宋诗','song-poetry','','[]','霸祖孤身取二江，子孫多以百城降。',64,'全唐诗/poet.song.32000.json','["霸祖孤身取二江，子孫多以百城降。", "豪華盡出成功後，逸樂安知與禍雙。", "東府舊基留佛剎，後庭餘唱落船窗。", "黍離麥秀從來事，且置興亡近酒缸。"]'),
('5914ce2a-822d-453f-8c44-c990dc13a94b','金陵懷古四首  其二','王安石','宋','宋诗','song-poetry','','[]','天兵南下此橋江，敵國當時指顧降。',192,'全唐诗/poet.song.32000.json','["天兵南下此橋江，敵國當時指顧降。", "山水雄豪空復在，君王神武自難雙。", "留連落日頻回首，想像餘墟獨倚窗。", "却怪夏陽纔一葦，漢家何事費罌缸。", "地勢東回萬里江，雲間天闕古來雙。", "兵纏四海英雄得，聖出中原次第降。", "山水寂寥埋王氣，風烟蕭颯滿僧窗。", "廢陵壞冢空冠劍，誰復沾纓酹一缸。", "憶昨天兵下蜀江，將軍談笑士爭降。", "黄旗已盡年三百，紫氣空收劍一雙。", "破堞自生新草木，廢宮誰識舊軒窗。", "不須搔首尋遺事，且倒花前白玉缸。"]'),
('31997fa0-f15f-4d5e-9636-b1ab118dfb9b','次韵舍弟遇子固憶少述','王安石','宋','宋诗','song-poetry','','[]','歸計何時就一廛，寒城回首意茫然。',64,'全唐诗/poet.song.32000.json','["歸計何時就一廛，寒城回首意茫然。", "野林細錯黄金日，溪岸寬圍碧玉天。", "飛兔已聞追騕褭，太阿猶恨失龍泉。", "遥知更憶河濱友，從事能忘我獨賢。"]'),
('03285f45-717f-46f9-b7c1-1249df6c22cd','次韵昌叔咏塵','王安石','宋','宋诗','song-poetry','','[]','塵土輕颺不自持，紛紛生物更相吹。',64,'全唐诗/poet.song.32000.json','["塵土輕颺不自持，紛紛生物更相吹。", "翻成地上高烟霧，散在人間要路岐。", "一世競馳甘睬目，幾家清坐得軒眉。", "超然祇有江湖上，還見波濤恐我時。"]'),
('4c000d40-cbf8-45f5-9598-8374fe385da5','石竹花','王安石','宋','宋诗','song-poetry','','[]','退公詩酒樂華年，欲取幽芳近綺筵。',64,'全唐诗/poet.song.32000.json','["退公詩酒樂華年，欲取幽芳近綺筵。", "種玉亂抽青節瘦，刻繒輕染絳花圓。", "風霜不放飄零早，雨露應從愛惜偏。", "已向美人衣上並，更留佳客賦嬋娟。"]'),
('23f29aa7-c2a3-4e32-adfd-70558a0b7a1f','古松','王安石','宋','宋诗','song-poetry','','[]','森森直幹百餘尋，高入青冥不附林。',64,'全唐诗/poet.song.32000.json','["森森直幹百餘尋，高入青冥不附林。", "萬壑風生成夜響，千山月照掛秋陰。", "豈因糞壤栽培力，自得乾坤造化心。", "廊廟乏材應見取，世無良匠勿相侵。"]'),
('4bc7e337-90fa-4fea-b5c0-92aefe24c4df','玉晨大檜鶴廟古松最爲佳樹','王安石','宋','宋诗','song-poetry','','[]','壇廟千年草不生，幽真曾此蔭餘清。',64,'全唐诗/poet.song.32000.json','["壇廟千年草不生，幽真曾此蔭餘清。", "月枝地上流雲影，風葉天邊過雨聲。", "材大賢於人有用，節高仙與世無情。", "秦山陂下今迷處，苦里宮中漫得名。"]'),
('dc605173-39e5-495f-ba0c-a87d482f293d','次韵董伯懿松聲','王安石','宋','宋诗','song-poetry','','[]','天機自動豈關情，能作人間物外聲。',64,'全唐诗/poet.song.32000.json','["天機自動豈關情，能作人間物外聲。", "暝聒一堂無客夢，曉悲千嶂有猿驚。", "廟中奏瑟沈三嘆，堂下吹簫失九成。", "俚耳紛紛多鄭衛，直須聞此始心清。"]'),
('fa9e3e64-54a3-4d26-b175-0ea9c8d5b46a','次韵答平甫','王安石','宋','宋诗','song-poetry','','[]','高蟬抱殻悲聲切，新鳥爭巢誶語忙。',64,'全唐诗/poet.song.32000.json','["高蟬抱殻悲聲切，新鳥爭巢誶語忙。", "長樹老陰欺夏日，晚花幽艷敵春陽。", "雲歸山去當檐靜，風過溪來滿坐凉。", "物物此時皆可賦，悔予千里不相將。"]'),
('7b8a09e4-4fd5-4f78-bb42-5003d860930a','次韵質夫兄使君同年','王安石','宋','宋诗','song-poetry','','[]','樓堞相望一日程，春風吹急似摇旌。',64,'全唐诗/poet.song.32000.json','["樓堞相望一日程，春風吹急似摇旌。", "莫言樂國無愁夢，頼把新詩有故情。", "客舍五漿非所願，私田三徑會須成。", "青雲自致歸公等，如我何緣得此聲。"]'),
('a2ca5cba-0111-4074-b00d-c2f1d22a0f0f','金明池','王安石','宋','宋诗','song-poetry','','[]','宜秋西望碧參差，憶看鄉人禊飲時。',64,'全唐诗/poet.song.32000.json','["宜秋西望碧參差，憶看鄉人禊飲時。", "斜倚水開花有思，緩隨風轉柳如癡。", "青天白日春常好，綠髮朱顔老自悲。", "跋馬未堪塵滿眼，夕陽偷理釣魚絲。"]'),
('51388e35-603a-4b53-b59a-a193b8f25262','葛溪驛','王安石','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u7f81\u65c5", "\u601d\u4e61", "\u5199\u666f"]','缺月昏昏漏未央，一燈明滅照秋床。',64,'全唐诗/poet.song.32000.json','["缺月昏昏漏未央，一燈明滅照秋床。", "病身最覺風露早，歸夢不知山水長。", "坐感歲時歌慷慨，起看天地色凄凉。", "鳴蟬更亂行人耳，正抱疏桐葉半黄。"]'),
('5818e428-babf-4e57-b3f3-dbebf9b80328','泛舟青溪入水門登高齋奉呈叔康','王安石','宋','宋诗','song-poetry','','[]','簿領紛紛惜此時，起携佳客散沈迷。',64,'全唐诗/poet.song.32000.json','["簿領紛紛惜此時，起携佳客散沈迷。", "十圍但見諸營柳，九曲難尋故國溪。", "牽埭欲隨流水遠，放船終礙畫橋低。", "子猷清興何曾盡，想憶高齋更一躋。"]'),
('f42cc560-0366-44f4-9424-64960e0de802','爲裴使君賦擬峴臺','王安石','宋','宋诗','song-poetry','','[]','君作新臺擬峴山，羊公千載得追攀。',64,'全唐诗/poet.song.32000.json','["君作新臺擬峴山，羊公千載得追攀。", "歌鍾殷地登臨處，花木移春指顧間。", "城似大堤來宛宛，溪如清漢落潺潺。", "時平不比征吳日，緩带尤宜向此閑。"]'),
('c0a04253-e144-48e2-b1b3-0c3db748e9f9','送李才元校理知邛州','王安石','宋','宋诗','song-poetry','','[]','朝廷孝治稱今日，鄉郡榮歸及壯時。',64,'全唐诗/poet.song.32000.json','["朝廷孝治稱今日，鄉郡榮歸及壯時。", "關吏相呼迎印綬，里兒爭出望旄麾。", "北堂已足誇三釜，南畝當今識兩歧。", "獨我尚留真有命，天於人欲本無私。"]'),
('b84e15c6-9438-4ade-9f10-80ace6514add','送張頡仲舉知奉新','王安石','宋','宋诗','song-poetry','','[]','故人爲邑士多稱，繇賦寬賒獄訟平。',64,'全唐诗/poet.song.32000.json','["故人爲邑士多稱，繇賦寬賒獄訟平。", "老吏閉門無重糈，荒山開隴有新粳。", "方揮玉麈日邊坐，又結銅章天外行。", "此去料君歸不久，挾材如此即名卿。"]'),
('a6bd5b20-199e-4b3f-8788-30eb88536bc8','張劍州至劍一日以親憂罷','王安石','宋','宋诗','song-poetry','','[]','客舍飛塵尚滿韉，却尋東路想茫然。',64,'全唐诗/poet.song.32000.json','["客舍飛塵尚滿韉，却尋東路想茫然。", "白頭反哺秦烏側，流血思歸蜀鳥前。", "今日相逢知悵望，幾時能到與留連。", "行看萬里雲西去，倚馬春風不忍鞭。"]'),
('2ca51b08-f2d8-41c6-b848-bf291299d55a','次韵子履遠寄之作','王安石','宋','宋诗','song-poetry','','[]','飄然逐客出都門，士論應悲玉石焚。',64,'全唐诗/poet.song.32000.json','["飄然逐客出都門，士論應悲玉石焚。", "高位紛紛誰得志，窮途往往始能文。", "柴桑今日思元亮，天祿何時召子雲。", "直使聲名傳後世，窮通何必較功勳。"]'),
('f70840c9-f959-4934-af1a-76756cf76236','送李太保知儀州','王安石','宋','宋诗','song-poetry','','[]','北平上谷當時守，氣略人推李廣優。',64,'全唐诗/poet.song.32000.json','["北平上谷當時守，氣略人推李廣優。", "還見子孫持漢節，欲臨關塞撫羌酋。", "雲邊鼓吹應先喜，日下旌旗更少留。", "五字亦君家世事，一吟何以稱來求。"]'),
('9c7caf8b-9485-4cb6-9913-c947599e44a8','送西京簽判王著作','王安石','宋','宋诗','song-poetry','','[]','兒曹曾上洛城頭，尚記清波繞驛流。',64,'全唐诗/poet.song.32000.json','["兒曹曾上洛城頭，尚記清波繞驛流。", "却想山川常在夢，可憐顔髮已驚秋。", "辟書今日看君去，著籍長年嘆我留。", "三十六峰應好在，寄聲多謝欲來遊。"]'),
('928fab65-5b68-4667-b28a-61debb205e65','送劉貢父赴秦州清水','王安石','宋','宋诗','song-poetry','','[]','劉郎高論坐噓枯，幕府調胹用緒餘。',64,'全唐诗/poet.song.32000.json','["劉郎高論坐噓枯，幕府調胹用緒餘。", "筆下能當萬人敵，腹中嘗記五車書。", "聞多望士登天祿，知有名臣薦子虛。", "且復弦歌窮塞上，祇應非晚召相如。"]'),
('724f9fc6-1b80-41c0-bdab-4fdd73607721','送純甫如江南','王安石','宋','宋诗','song-poetry','','[]','青溪看汝始蹁躚，兄弟追隨各少年。',64,'全唐诗/poet.song.32000.json','["青溪看汝始蹁躚，兄弟追隨各少年。", "壯爾有行今納婦，老吾無用亦求田。", "初來淮北心常折，却望江南眼更穿。", "此去還知苦相憶，歸時快馬亦須鞭。"]'),
('ff6e5b28-be4a-4ddb-807e-5670bc760308','送郊社朱兄除郎東歸','王安石','宋','宋诗','song-poetry','','[]','手持官牒出神皋，迎客遥知賀酒醪。',64,'全唐诗/poet.song.32000.json','["手持官牒出神皋，迎客遥知賀酒醪。", "照映里門非白屋，欺凌春草有青袍。", "宦遊雖晚何妨久，餓顯從來不必高。", "孝友父兄家法在，想能清白遺兒曹。"]'),
('e0179e58-02c6-4936-8b0a-662bb984e09a','送沈康知常州','王安石','宋','宋诗','song-poetry','','[]','作客蘭陵迹已陳，爲傳謠俗記州民。',64,'全唐诗/poet.song.32000.json','["作客蘭陵迹已陳，爲傳謠俗記州民。", "溝塍半廢田疇薄，厨傳相仍市井貧。", "常恐勞人輕白屋，忽逢佳士得朱輪。", "慇懃話此還惆悵，最憶荆溪兩岸春。"]'),
('2fffe45c-5841-4f2d-8760-4e9961c6b17e','安豐張令修芍陂','王安石','宋','宋诗','song-poetry','','[]','桐鄉振廩得周旋，芍水修陂道路傳。',64,'全唐诗/poet.song.32000.json','["桐鄉振廩得周旋，芍水修陂道路傳。", "日想僝功追往事，心知爲政似當年。", "魴魚鱍鱍歸城市，秔稻紛紛載酒船。", "楚相祠堂仍好在，勝遊思爲子留篇。"]'),
('c5043722-0104-43ed-897e-da168ca6a862','送復之屯田赴成都','王安石','宋','宋诗','song-poetry','','[]','槃礴西南江與岷，石犀金馬世稱神。',64,'全唐诗/poet.song.32000.json','["槃礴西南江與岷，石犀金馬世稱神。", "桑麻接畛餘無地，錦繡連城別有春。", "結綬相隨通籍久，推車此去辟書新。", "知君不爲山川險，便忘吾家叱馭人。"]'),
('1e8b7279-7aad-4cf5-984a-1c780488e359','送經臣富順寺丞','王安石','宋','宋诗','song-poetry','','[]','故人爲縣楚江邊，海角猶聞政事傳。',64,'全唐诗/poet.song.32000.json','["故人爲縣楚江邊，海角猶聞政事傳。", "萬井已安如赤子，一麾今去上青天。", "應開醉眼酴醿下，莫起歸心杜宇前。", "報主代親俱有地，幾人忠孝似君全。"]'),
('08071889-5e08-4c57-8489-8a9e5f257097','送張卿致仕','王安石','宋','宋诗','song-poetry','','[]','子房籌策漢時功，身退超然慕赤松。',64,'全唐诗/poet.song.32000.json','["子房籌策漢時功，身退超然慕赤松。", "餘烈尚能開後世，高材今復繼前蹤。", "執鞭始負平生願，操几何知此地逢。", "竊食一官慚未艾，緒言方頼賜從容。"]'),
('8150680e-cfba-4ca5-96a5-ce9b83d83c9d','送梅龍圖','王安石','宋','宋诗','song-poetry','','[]','子真家世子雲鄉，風力才華豈易當。',64,'全唐诗/poet.song.32000.json','["子真家世子雲鄉，風力才華豈易當。", "回首古人多隠約，致身今日獨輝光。", "謨明久合分三府，治劇聊須試一方。", "從此政成何所報，百城無事祇耕桑。"]'),
('31aab5a9-d78f-420a-a849-80aa1b1bf7f1','送李秘校南歸','王安石','宋','宋诗','song-poetry','','[]','四十青衫更旅人，悠悠饑馬傍沙塵。',64,'全唐诗/poet.song.32000.json','["四十青衫更旅人，悠悠饑馬傍沙塵。", "久留上國言空富，却走南州食轉貧。", "自作詩書能見志，應知時命不關身。", "江湖勝事從今數，肯但悲歌寂寞濱。"]'),
('c4e2d54b-f021-442a-87f8-f00b4c6a6bb7','送蕭山錢著作','王安石','宋','宋诗','song-poetry','','[]','才高諸彥故無嫌，兄弟同時舉孝廉。',64,'全唐诗/poet.song.32000.json','["才高諸彥故無嫌，兄弟同時舉孝廉。", "東觀外除方墨綬，西州相見已蒼髯。", "靈胥引水清穿市，神禹分山翠入簾。", "好去弦歌聊自慰，郡人誰敢慢陶潛。"]'),
('688b08a0-8c9e-47f0-9c74-7f8a3d4cd78a','送靈仙裴太博','王安石','宋','宋诗','song-poetry','','[]','一官留隠太常中，生事蕭然信所窮。',64,'全唐诗/poet.song.32000.json','["一官留隠太常中，生事蕭然信所窮。", "有力尚期當世用，無求今見古人風。", "邅迴舊學皆殘藁，邂逅相看各老翁。", "他日卜居何處好，溪山還欲與君同。"]'),
('d98e9ee4-a7a5-4a47-839a-7d383c7c769a','送趙燮之蜀永康簿','王安石','宋','宋诗','song-poetry','','[]','蜀山萬里一青袍，石棧天梯箠轡高。',64,'全唐诗/poet.song.32000.json','["蜀山萬里一青袍，石棧天梯箠轡高。", "多學似君寧易得，小官於此亦徒勞。", "行追西路聊班草，坐憶南州欲夢刀。", "他日寄聲能問我，應從錦水至江皋。"]'),
('8344e16e-acc9-45d9-aa10-a37ebc99967f','酬吳季野見寄','王安石','宋','宋诗','song-poetry','','[]','漫披陳蠹學經綸，捧檄生平祗爲親。',64,'全唐诗/poet.song.32000.json','["漫披陳蠹學經綸，捧檄生平祗爲親。", "聞道不先從事早，課功無狀取官頻。", "豈堪置足青冥上，終欲回身寂寞濱。", "俯仰謬恩方自歉，慚君將比洛陽人。"]'),
('9663a713-1716-4a66-abbd-f0e7cdd57a46','和平甫寄陳正叔','王安石','宋','宋诗','song-poetry','','[]','强行南仕莫辭勤，聞說田園已曠耘。',64,'全唐诗/poet.song.32000.json','["强行南仕莫辭勤，聞說田園已曠耘。", "縱使一區猶有宅，可能三月尚無君。", "且同元亮傾樽酒，更與靈均續舊文。", "此道廢興吾命在，世間滕口任云云。"]'),
('a8b7113e-74b1-416a-9884-b7e344e962c8','送王大卿致政歸江陵','王安石','宋','宋诗','song-poetry','','[]','九卿初命亞三司，朝吏相瞻得老師。',64,'全唐诗/poet.song.32000.json','["九卿初命亞三司，朝吏相瞻得老師。", "南闕便還新印綬，東舟只載舊書詩。", "漢庭餞客無佳句，越水歸裝有富貲。", "回首千年見疏范，共疑今事勝當時。"]'),
('ed61a289-b02b-400d-b965-794af3dcb0b8','送叔康侍御','王安石','宋','宋诗','song-poetry','','[]','詔取名郎入憲臺，此時方急濟時才。',64,'全唐诗/poet.song.32000.json','["詔取名郎入憲臺，此時方急濟時才。", "聖聰應已虛心待，奸黨寧無側目猜。", "白筆豈知權可畏，皁囊還請上親開。", "佇聞讜論能醫國，飛報頻隨驛騎來。"]'),
('c6052b7c-b128-4538-9deb-0bc6a7f92ba0','寄朱昌叔','王安石','宋','宋诗','song-poetry','','[]','清江漫漫繞城流，尚憶城邊繫小舟。',64,'全唐诗/poet.song.32000.json','["清江漫漫繞城流，尚憶城邊繫小舟。", "射虎未能隨李廣，割雞空欲戲言游。", "雲埋塞路驚塵合，霜入春風滿鬢愁。", "此日君書苦難得，謾多鴻雁起南洲。"]'),
('0cec4fca-65f9-4484-90f7-d38799801dbd','九日登東山寄昌叔','王安石','宋','宋诗','song-poetry','','[]','城上啼烏破寂寥，思君何處坐岧嶢。',64,'全唐诗/poet.song.32000.json','["城上啼烏破寂寥，思君何處坐岧嶢。", "應須綠酒酬黄菊，何必紅裙弄紫簫。", "落木雲連秋水渡，亂山煙入夕陽橋。", "淵明久負東籬醉，猶分低心事折腰。"]'),
('fa18272a-6b83-4186-96a3-a11fe4a9e792','到舒州次韵答平甫','王安石','宋','宋诗','song-poetry','','[]','夜別江船曉解驂，秋城氣象亦潭潭。',64,'全唐诗/poet.song.32000.json','["夜別江船曉解驂，秋城氣象亦潭潭。", "山從樹外青爭出，水向沙邊綠半涵。", "行問嗇夫多不記，坐論公瑾少能談。", "只愁地僻無賓客，舊學從誰得指南。"]'),
('1885c6d7-5f68-4530-b46e-b8774c570d28','舒州七月十一日雨','王安石','宋','宋诗','song-poetry','','[]','行看野氣來方勇，卧聽秋聲落竟慳。',64,'全唐诗/poet.song.32000.json','["行看野氣來方勇，卧聽秋聲落竟慳。", "淅瀝未生羅豆水，蒼茫空失皖公山。", "火耕又見無遺種，肉食何妨有厚顔。", "巫祝萬端曾不救，只疑天賜雨工閑。"]'),
('c386c0ba-408f-4706-926f-12d14c3bd51c','次韵答丁端州','王安石','宋','宋诗','song-poetry','','[]','莫嗟荒僻又離群，且喜風謠嶺北聞。',64,'全唐诗/poet.song.32000.json','["莫嗟荒僻又離群，且喜風謠嶺北聞。", "銅柱雖然蠻徼接，竹符還是漢家分。", "春書來逐衡陽雁，秋騎歸看隴首雲。", "相見會知南望苦，病骸今似沈休文。"]'),
('ce4ad1ea-8f1d-4a42-9dc9-2fe078c464d9','答劉季孫','王安石','宋','宋诗','song-poetry','','[]','偶著儒冠敢陋今，自憐多負少時心。',64,'全唐诗/poet.song.32000.json','["偶著儒冠敢陋今，自憐多負少時心。", "輊軒已任人前後，揭厲安知世淺深。", "挾策有思悲慷慨，負薪無力病侵淫。", "愧君綠綺虛投贈，更覺貧家報乏金。"]'),
('be96520d-014d-424d-90a1-1aa6e83a5ae8','次韵酬王太祝','王安石','宋','宋诗','song-poetry','','[]','塵土波瀾不自期，飄然身與願相違。',64,'全唐诗/poet.song.32000.json','["塵土波瀾不自期，飄然身與願相違。", "衰根要路知難植，病羽長年欲退飛。", "高論已嗟能聽少，力行還恨賦材微。", "慚君俊少今知我，一見心如客得歸。"]'),
('fef6c09f-dc83-439e-adce-f34191fa3488','寄吳成之','王安石','宋','宋诗','song-poetry','','[]','綠髮溪山笑語中，豈知翻手兩成翁。',64,'全唐诗/poet.song.32000.json','["綠髮溪山笑語中，豈知翻手兩成翁。", "辛夷屋角摶香雪，躑躅岡頭挽醉紅。", "想見舊山茅徑在，追隨今日板輿空。", "渭陽車馬嗟何及，榮祿方當與子同。"]'),
('af849108-eb76-4b0b-bc22-55940f00fd41','寄曾子固','王安石','宋','宋诗','song-poetry','','[]','斗粟猶慚報禮輕，敢嗟吾道獨難行。',64,'全唐诗/poet.song.32000.json','["斗粟猶慚報禮輕，敢嗟吾道獨難行。", "脫身負米將求志，戮力乘田豈爲名。", "高論幾爲衰俗廢，壯懷難值故人傾。", "荒城回首山川隔，更覺秋風白髮生。"]'),
('997ef224-b39b-4ef7-86aa-92c8b875182f','至開元僧舍上方次韵舍弟二月一日之作','王安石','宋','宋诗','song-poetry','','[]','溪谷濺濺嫩水通，野田高下綠蒙茸。',64,'全唐诗/poet.song.32000.json','["溪谷濺濺嫩水通，野田高下綠蒙茸。", "和風滿樹笙簧雜，霽雪兼山粉黛重。", "萬里有家歸尚隔，一廛無地去何從。", "傷春故欲西南望，迴首荒城已暮鍾。"]'),
('94ed5c6a-903f-403e-a6a8-132d36641caa','寄王回深甫','王安石','宋','宋诗','song-poetry','','[]','少年倏忽不再得，後日歡娛能幾何。',64,'全唐诗/poet.song.32000.json','["少年倏忽不再得，後日歡娛能幾何。", "顧我面顔衰更早，憐君身世病還多。", "窗間暗淡月含霧，船底飄颻風送波。", "一寸古心俱未試，相思中夜起悲歌。"]'),
('311ccf70-8547-4cb9-852c-859b57890935','次韵答彥珍','王安石','宋','宋诗','song-poetry','','[]','手得封題手自開，一篇美玉綴玫瑰。',64,'全唐诗/poet.song.32000.json','["手得封題手自開，一篇美玉綴玫瑰。", "衆知圓媚難論報，自顧窮愁敢角才。", "君卧南陽惟畎畝，我行西路亦風埃。", "相逢不必嗟勞事，尚欲賡歌咏起哉。"]'),
('22d75ef4-4eb3-45af-9dc8-42088c001129','寄闕下諸父兄兼示平甫兄弟','王安石','宋','宋诗','song-poetry','','[]','父兄爲學衆人知，小弟文章亦自奇。',64,'全唐诗/poet.song.32000.json','["父兄爲學衆人知，小弟文章亦自奇。", "家勢到今宜有後，士才如此豈無時。", "久聞陽羨溪山好，頗與淵明性分宜。", "但願一門皆貴仕，時將車馬過茆茨。"]'),
('538433b0-43f4-4da8-b391-8cbc73c3ade4','鍾山西庵白蓮亭','王安石','宋','宋诗','song-poetry','','[]','山亭新破一方苔，白帝留花滿四隈。',64,'全唐诗/poet.song.32000.json','["山亭新破一方苔，白帝留花滿四隈。", "野艷輕明非傅粉，秋光清淺不憑材。", "鄉窮自作幽人伴，歲晚誰爲靜女媒。", "可笑遠公池上客，却因松菊賦歸來。"]'),
('5f587f0d-54fe-46b1-bb1a-8c34dac87d39','贈長寧僧首','王安石','宋','宋诗','song-poetry','','[]','秀骨厖眉倦往還，自然清譽落人間。',64,'全唐诗/poet.song.32000.json','["秀骨厖眉倦往還，自然清譽落人間。", "閑中用意歸詩筆，靜外安身比太山。", "欲倩野雲朝送客，更邀江月夜臨關。", "嗟予蹤迹飄塵土，一對孤峰幾厚顔。"]'),
('8c16a02b-d0df-4218-ae16-13b9fe352be2','次韵舍弟賞心亭即事二首','王安石','宋','宋诗','song-poetry','','[]','檻折檐傾野水傍，臺城佳氣已消亡。',128,'全唐诗/poet.song.32000.json','["檻折檐傾野水傍，臺城佳氣已消亡。", "難披榛莽尋千古，獨倚青冥望八荒。", "坐覺塵沙昏遠眼，忽看風雨破驕陽。", "扁舟此日東南興，欲盡江流萬里長。", "霸氣消磨不復存，舊朝臺殿祇空村。", "孤城倚薄青天近，細雨侵凌白日昏。", "稍覺野雲成晚霽，却疑山月是朝暾。", "此時江海無窮興，醒客忘言醉客喧。"]'),
('9e45a6e4-05d3-4cc3-b58b-c18833325241','次韵陳學士小園即事','王安石','宋','宋诗','song-poetry','','[]','牆屋雖無好鳥鳴，池塘亦未有蛙聲。',64,'全唐诗/poet.song.32000.json','["牆屋雖無好鳥鳴，池塘亦未有蛙聲。", "樹含宿雨紅初入，草倚朝陽綠更生。", "萬物天機何得喪，百年心事不將迎。", "與君杖策聊觀化，搔首春風眼尚明。"]'),
('d381e2af-1254-4145-8705-cc9c8f5c4b52','寄友人','王安石','宋','宋诗','song-poetry','','[]','飄然羈旅尚無涯，一望西南百嘆嗟。',64,'全唐诗/poet.song.32000.json','["飄然羈旅尚無涯，一望西南百嘆嗟。", "江擁涕洟流入海，風吹魂夢去還家。", "平生積慘應銷骨，今日殊鄉又見花。", "安得此身如草樹，根株相守盡年華。"]'),
('8cb5f9bd-cbdb-44ab-933c-4d32f9c5354c','登大茅山','王安石','宋','宋诗','song-poetry','','[]','一峰高出衆山顛，疑隔塵沙道里千。',64,'全唐诗/poet.song.32000.json','["一峰高出衆山顛，疑隔塵沙道里千。", "俯視煙雲來不極，仰攀蘿蔦去無前。", "人間已換嘉平帝，地下誰通句曲天。", "陳迹是非今草莽，紛紛流俗尚師仙。"]'),
('ac34e7bc-027d-4624-934e-dbedad6fd5dc','登中茅山','王安石','宋','宋诗','song-poetry','','[]','翛然杖屨出塵囂，雞犬無聲到泬寥。',64,'全唐诗/poet.song.32000.json','["翛然杖屨出塵囂，雞犬無聲到泬寥。", "欲見五芝莖葉老，尚攀三鶴羽翰遥。", "容溪路轉迷橫彴，仙几風來得墮樵。", "興罷日斜歸亦懶，更磨碑蘚認前朝。"]'),
('176e6b37-ae1c-4d6d-be98-4fb4cb35a7b1','登小茅山','王安石','宋','宋诗','song-poetry','','[]','捫蘿路到半天窮，下視淮洲杳靄中。',64,'全唐诗/poet.song.32000.json','["捫蘿路到半天窮，下視淮洲杳靄中。", "物外真游來几席，人間榮願付苓通。", "白雲坐處龍池杳，明月歸時鶴馭空。", "回首三君誰更似，子房家世有高風。"]'),
('d2c54008-92eb-40d3-bdd1-9482580569d1','送張仲容赴杭州孫公辟','王安石','宋','宋诗','song-poetry','','[]','萬屋相誇漆與丹，笑歌長在綺紈間。',64,'全唐诗/poet.song.32000.json','["萬屋相誇漆與丹，笑歌長在綺紈間。", "綵船春戲城邊水，畫燭秋尋寺外山。", "憶我屢隨遊客入，喜君今赴辟書還。", "遥知曼倩威行久，赤筆應從到日閑。"]'),
('adf35b60-e60a-45df-a7f2-09c2e49b3fc7','贈李士寧道人','王安石','宋','宋诗','song-poetry','','[]','季主逡巡居卜肆，彌明邂逅作詩翁。',64,'全唐诗/poet.song.32000.json','["季主逡巡居卜肆，彌明邂逅作詩翁。", "曾令宋賈嘆車上，更使劉侯驚坐中。", "杳杳人傳多異事，冥冥誰識此高風。", "行歌過我非無謂，唯恨貧家酒盞空。"]'),
('315f3bd1-ea0d-4c9c-93e0-2d22c1b9616e','次韵春日即事','王安石','宋','宋诗','song-poetry','','[]','人間尚有薄寒侵，和氣先薰草樹心。',64,'全唐诗/poet.song.32000.json','["人間尚有薄寒侵，和氣先薰草樹心。", "丹白自分齊破蕾，青黄相向欲交陰。", "潺潺嫩水生幽谷，漠漠輕煙動遠林。", "病得一官隨太守，班春無助愧周任。"]'),
('f86af98a-41a2-406c-bae9-e825c69d2556','次韵答陳正叔二首  其一','王安石','宋','宋诗','song-poetry','','[]','青衫憔悴北歸來，髮有霜根面有埃。',64,'全唐诗/poet.song.32000.json','["青衫憔悴北歸來，髮有霜根面有埃。", "群吠我方憎猘子，一鳴誰更識龍媒。", "功名落落求難值，日月沄沄去不回。", "勝事與身何等近，酒樽詩卷數須開。"]'),
('31a70b7d-856f-4d88-bfd7-ffc474d78421','次韵答陳正叔二首  其二','王安石','宋','宋诗','song-poetry','','[]','田宅荒凉去復來，詩書顔髮兩塵埃。',64,'全唐诗/poet.song.32000.json','["田宅荒凉去復來，詩書顔髮兩塵埃。", "忘機自許鷗相狎，得禍誰期鶴見媒。", "此道未行身有待，古人不見首空回。", "何當水石他年住，更把韋編靜處開。"]'),
('d8d2d1b0-15d6-4749-a6dc-dfdcfbf46537','送崔左藏之廣東','王安石','宋','宋诗','song-poetry','','[]','怪石巉巉上泬寥，昔人於此奏簫韶。',64,'全唐诗/poet.song.32000.json','["怪石巉巉上泬寥，昔人於此奏簫韶。", "水清但有嘉魚出，風暖何曾毒草摇。", "今日淹留君按節，當時嬉戲我垂髫。", "因尋舊政詢遺老，爲作新詩變俚謠。"]'),
('58b100d3-0e1a-49a1-86f7-d080143a36cf','苦雨','王安石','宋','宋诗','song-poetry','','[]','靈場奔走尚無功，去馬來車道不通。',64,'全唐诗/poet.song.32000.json','["靈場奔走尚無功，去馬來車道不通。", "風助亂雲陰更密，水爭高岸氣尤雄。", "平時溝洫今多廢，下戶京囷久已空。", "肉食自嗟何所報，古人憂國願年豐。"]'),
('095fe360-d5f1-4502-8750-68190b38dced','江上','王安石','宋','宋诗','song-poetry','','[]','村落家家有濁醪，青旗招客解袛裯。',64,'全唐诗/poet.song.32000.json','["村落家家有濁醪，青旗招客解袛裯。", "春風似補林塘破，野水遥連草樹高。", "寄食舟車隨處弊，行歌天地此身勞。", "遲回自負平生意，豈是明時惜一毛。"]'),
('d763de97-4f36-47a9-9018-6d34a379bf80','午枕','王安石','宋','宋诗','song-poetry','','[]','百年春夢去悠悠，不復吹簫向此留。',64,'全唐诗/poet.song.32000.json','["百年春夢去悠悠，不復吹簫向此留。", "野草自花還自落，鳴禽相乳亦相酬。", "舊蹊埋沒開新徑，朱戶欹斜見畫樓。", "欲把一杯無伴侶，眼看興廢使人愁。"]'),
('f4f897cb-8b69-4d10-96c0-6b064ea50191','寄石鼓寺陳伯庸','王安石','宋','宋诗','song-poetry','','[]','鯨海無風白日閑，天門當面險難攀。',64,'全唐诗/poet.song.32000.json','["鯨海無風白日閑，天門當面險難攀。", "塵埃掉臂離長陌，琴酒和雲入舊山。", "仁義未饒軒冕貴，功名莫信鬼神慳。", "郭東一點英雄氣，時伴君心夜斗間。"]'),
('2035bb87-15b0-4741-a93c-71749ea72b37','送熊伯通','王安石','宋','宋诗','song-poetry','','[]','歲暮欣逢蓋共傾，川塗南北豈忘情。',64,'全唐诗/poet.song.32000.json','["歲暮欣逢蓋共傾，川塗南北豈忘情。", "事經官路心應折，地入家山眼更明。", "江上月華空自照，梅邊春意恰相迎。", "關河不鎖真消息，野客猶能聽治聲。"]'),
('92f433a9-7d94-4004-8135-99ac27e357f0','送王覃','王安石','宋','宋诗','song-poetry','','[]','分走人間十五年，塵沙吹鬢各蒼然。',64,'全唐诗/poet.song.32000.json','["分走人間十五年，塵沙吹鬢各蒼然。", "山林渺渺長回首，兒女紛紛忽滿前。", "知子有才思奮發，嗟余無地與迴旋。", "相看一作秦吳別，身世何時兩息肩。"]'),
('ffdf2100-df5c-409d-af28-35b5ca0627e9','送明州王大卿','王安石','宋','宋诗','song-poetry','','[]','大曆才臣有此州，昆雲今駕鹿轓游。',64,'全唐诗/poet.song.32000.json','["大曆才臣有此州，昆雲今駕鹿轓游。", "從來所至邦人喜，真復能分聖主憂。", "千里封疆何足治，一時名跡故應留。", "屬城舊吏雖疲懶，尚可揮毫敵李舟。"]'),
('9ebd292e-bb4a-4d6d-a318-0464b18d2d5e','姑胥郭','王安石','宋','宋诗','song-poetry','','[]','誤褫雲巾別故山，抵吳由越兩間關。',64,'全唐诗/poet.song.32000.json','["誤褫雲巾別故山，抵吳由越兩間關。", "千家漁火秋風市，一葉歸舟暮雨灣。", "旅病愔愔如困酒，鄉愁脈脈似連環。", "情知带眼從前緩，更恐顛毛自此斑。"]'),
('e581d6ee-cbc9-4981-ab9e-bc4a1aa12eda','嚴陵祠堂','王安石','宋','宋诗','song-poetry','','[]','漢庭來見一羊裘，默默俄歸舊釣舟。',64,'全唐诗/poet.song.32000.json','["漢庭來見一羊裘，默默俄歸舊釣舟。", "迹似磻溪應有待，世無西伯可能留。", "崎嶇馮衍才終廢，索寞桓譚道不謀。", "勺水果非鱣鮪地，放身滄海亦何求。"]'),
('96c93b35-fc4a-471f-b375-d6e54097426d','藏春塢詩獻刁十四丈學士','王安石','宋','宋诗','song-poetry','','[]','蒜山東渡得林丘，邂逅籃輿亦少留。',64,'全唐诗/poet.song.32000.json','["蒜山東渡得林丘，邂逅籃輿亦少留。", "今日更知萊氏隠，暮年長憶武陵遊。", "欲營垣屋隨穿斸，尚嘆塵沙隔獻酬。", "遥約勾吳亭下路，春風深駐五湖舟。"]'),
('02ef1095-5ec0-43db-85ab-15f161811c55','太湖恬亭','王安石','宋','宋诗','song-poetry','','["\u592a\u6e56"]','檻臨溪上綠陰圍，溪岸高低入翠微。',64,'全唐诗/poet.song.32000.json','["檻臨溪上綠陰圍，溪岸高低入翠微。", "日落斷橋人獨立，水涵幽樹鳥相依。", "清遊始覺心無累，靜處誰知世有機。", "更待夜深同徙倚，秋風斜月釣船歸。"]'),
('8e942a79-e300-4315-bf32-93c4a7bce433','蒙城清燕堂','王安石','宋','宋诗','song-poetry','','[]','清燕新碑得自蒙，行吟如到此堂中。',64,'全唐诗/poet.song.32000.json','["清燕新碑得自蒙，行吟如到此堂中。", "吏無田甲當時氣，民有莊周後世風。", "庭下早知閑木索，坐間遥想御絲桐。", "飄然一往何時得，俛仰塵沙欲作翁。"]'),
('7152e1d3-4ce4-4a23-8ae2-d55031b3b304','次韵酬吳彥珍見寄二首  其一','王安石','宋','宋诗','song-poetry','','[]','君作新詩故起予，一吟聊復報雙魚。',64,'全唐诗/poet.song.32000.json','["君作新詩故起予，一吟聊復報雙魚。", "杖藜高徑誰來往，散帙空堂自卷舒。", "樹外鳥啼催晚種，花間人語趁朝虛。", "春風處處堪携手，何事臨池苦學書。"]'),
('5bdab839-a2a3-40f4-9477-a37d71508ac7','次韵酬吳彥珍見寄二首  其二','王安石','宋','宋诗','song-poetry','','[]','篁竹荒茅五畝餘，生涯山蕨與泉魚。',64,'全唐诗/poet.song.32000.json','["篁竹荒茅五畝餘，生涯山蕨與泉魚。", "家貧殖貨羞端木，鄉里傳書比仲舒。", "白日憶君聊遠望，青林嗟我似逃虛。", "春風渺渺烏塘尾，漫得東來一紙書。"]'),
('cc559451-ed90-435e-9c72-1b5fe24ad278','自金陵如丹陽道中有感','王安石','宋','宋诗','song-poetry','','[]','數百年來王氣消，難將前事問漁樵。',64,'全唐诗/poet.song.32000.json','["數百年來王氣消，難將前事問漁樵。", "苑方秦地皆蕪沒，山借揚州更寂寥。", "荒埭暗雞催月曉，空場老雉挾春驕。", "豪華祇有諸陵在，往往黄金出市朝。"]'),
('740fa4cb-9b82-419f-bd73-0813d06c27bf','初去臨川','王安石','宋','宋诗','song-poetry','','[]','東浮溪水渡長林，上坂回頭一拊心。',64,'全唐诗/poet.song.32000.json','["東浮溪水渡長林，上坂回頭一拊心。", "已覺省煩非仲叔，安能養志似曾參。", "憂傷遇事紛紛出，疾病乘虛亹亹侵。", "未有半分求自贖，恐填溝壑更霑襟。"]'),
('5df42fd8-5bb4-4872-9c07-006ef1445111','讀史','王安石','宋','宋诗','song-poetry','','[]','自古功名亦苦辛，行藏終欲付何人。',64,'全唐诗/poet.song.32000.json','["自古功名亦苦辛，行藏終欲付何人。", "當時黮闇猶承誤，末俗紛紜更亂真。", "糟粕所傳非粹美，丹青難寫是精神。", "區區豈盡高賢意，獨守千秋紙上塵。"]'),
('c0c4cce2-45d8-46ab-af30-8fa7670f6b3e','讀詔書','王安石','宋','宋诗','song-poetry','','[]','去秋東出汴河梁，已見中州旱勢强。',64,'全唐诗/poet.song.32000.json','["去秋東出汴河梁，已見中州旱勢强。", "日射地穿千里赤，風吹沙度滿城黄。", "近聞急詔收群策，頗說新年又亢陽。", "賤術縱工難自獻，心憂天下獨君王。"]'),
('a760767d-5ff9-4573-b447-5c63ea2cfcc7','每見王太丞邑事甚冗而剸劇之暇猶能過訪山館兼出佳篇爲贈仰嘆才力因成小詩','王安石','宋','宋诗','song-poetry','','[]','我看繁訟頻搔首，君富才明見亦常。',64,'全唐诗/poet.song.32000.json','["我看繁訟頻搔首，君富才明見亦常。", "尚有閑襟尋水石，更留佳句似池塘。", "松苗地合分高下，鳬鶴天教有短長。", "徐上青雲猶未晚，可無音問及滄浪。"]'),
('6810008f-5f15-48e2-a15e-cc7002c082cd','王浮梁太丞之聽訟軒有水禽三巢于竹林之上恬而自得邑人作詩以美之因次元韵','王安石','宋','宋诗','song-poetry','','[]','水邊舟動多驚散，何事林間近絕疑。',64,'全唐诗/poet.song.32000.json','["水邊舟動多驚散，何事林間近絕疑。", "野意肯從威令至，舊巢猶有主人知。", "不關飲啄春江暖，自在飛鳴夏日遲。", "覽德豈無丹穴鳳，到時應讓向南枝。"]'),
('8b0cf59b-c36c-4bba-9a87-c10b46c01e75','寄虞氏兄弟','王安石','宋','宋诗','song-poetry','','[]','一身兼抱百憂虞，忽忽如狂久廢書。',64,'全唐诗/poet.song.32000.json','["一身兼抱百憂虞，忽忽如狂久廢書。", "疇昔心期俱喪勇，此來腰疾更乘虛。", "久聞陽羨安家好，自度淵明與世疏。", "亦有未歸溝壑日，會應相近置田廬。"]'),
('9c5b76e4-2f19-45e4-9b81-d3987e8d2fa7','除夜寄舍弟','王安石','宋','宋诗','song-poetry','','[]','一尊聊有天涯憶，百感翻然醉裏眠。',64,'全唐诗/poet.song.32000.json','["一尊聊有天涯憶，百感翻然醉裏眠。", "酒醒燈前猶是客，夢回江北已經年。", "佳時流落真何得，勝事蹉跎只可憐。", "唯有到家寒食在，春風因泛澦溪船。"]'),
('44d835b8-e4ef-4325-81ed-1d4919cf1d6e','答熊本推官金陵寄酒','王安石','宋','宋诗','song-poetry','','[]','鬰金香是蘭陵酒，枉入詩人賦咏來。',64,'全唐诗/poet.song.32000.json','["鬰金香是蘭陵酒，枉入詩人賦咏來。", "庭下北風吹急雪，坐間南客送寒醅。", "淵明未得歸三徑，叔夜猶同把一杯。", "吟罷想君醒醉處，鍾山相向白崔嵬。"]'),
('e18ce1b2-5eaf-4e64-a9ae-807c9b0ead5d','和錢學士喜雪','王安石','宋','宋诗','song-poetry','','[]','手把詩翁憶雪詩，坐愁窮海瘴煙霏。',128,'全唐诗/poet.song.32000.json','["手把詩翁憶雪詩，坐愁窮海瘴煙霏。", "誰令天上蒼茫合，忽見空中散漫飛。", "閶闔與風生氣勢，姮娥交月借光輝。", "山鴉瑟縮相依立，邑犬跳梁未肯歸。", "點綴丘園榮樹木，埋藏溝壍亂封圻。", "高歌業已傳都市，逸興何當叩隠扉。", "頗欲携樽邀使騎，幾忘溫席薦親闈。", "公今早晚班春去，强勸澇田補歲饑。"]'),
('f740eb7d-45b8-4d4a-af67-5478e201cb9e','送江寧彭給事赴闕','王安石','宋','宋诗','song-poetry','','[]','西江望士衆長兼，卓犖傳家在一男。',384,'全唐诗/poet.song.32000.json','["西江望士衆長兼，卓犖傳家在一男。", "壯志異時開史牒，妙齡終日對書龕。", "桂堂發策收科選，櫻苑頒詩豫宴酣。", "大邑援琴聊試可，小州懷紱果才堪。", "分臺拜職榮先入，抗疏辭恩恥橫覃。", "勁操比松寒不撓，忠言如藥苦非甘。", "龍鱗直爲當官觸，虎穴寧關射利探。", "朱轂獸頭終協夢，粉闈雞舌更須含。", "均輸北轉荆門鷁，勸課西臨蜀市蠶。", "期信有兒迎郭伋，食貧無地乞羊曇。", "櫜垂鈴棧駝鳴𡇼，節擁棠郊虎視眈。", "歸見廣墀瞻斧藻，對揚初服改朱藍。", "進班華省財方阜，出按窮邊虜稍戡。", "帝命賈琮當冀北，民歌姬奭次周南。", "投壺饗客魚無乙，伐鼓蒐兵馬有驔。", "鯨鬣掀紅旗杳杳，虬髯吒黑纛鬖鬖。", "威加諸部風霜肅，惠浸連營雨露涵。", "大斗時時能劇飲，輕裘往往祇清談。", "乾龍已應天飛五，晉馬徐觀晝接三。", "道在君臣方自合，德侔卿長亦誰慚。", "便蕃肯較平生寵，放曠皆知雅性妉。", "委佩去辭廷殖殖，揚舲來得府潭潭。", "一尊客語從容盡，千里人情委曲諳。", "豈但搢紳稱召杜，故多扶杖祝彭聃。"]'),
('c128dcf1-a413-498d-bab4-abd9acdb4d30','聊行','王安石','宋','宋诗','song-poetry','','[]','聊行弄芳草，獨坐隠團蒲。',24,'全唐诗/poet.song.32000.json','["聊行弄芳草，獨坐隠團蒲。", "問客茅簷日，君家有此無。"]'),
('173a9cae-f340-4685-b848-3d53b0c5d948','染雲','王安石','宋','宋诗','song-poetry','','[]','染雲爲柳葉，剪水作梨花。',24,'全唐诗/poet.song.32000.json','["染雲爲柳葉，剪水作梨花。", "不是春風巧，何緣有歲華。"]'),
('0b70b3d5-d788-4b7d-9986-73bc9a23dda5','溝港','王安石','宋','宋诗','song-poetry','','[]','溝港重重柳，山坡處處梅。',24,'全唐诗/poet.song.32000.json','["溝港重重柳，山坡處處梅。", "小輿穿麥過，狹徑礙桑回。"]'),
('cbfa061f-84fd-4b1a-b8fb-94c2545535ec','霹靂溝','王安石','宋','宋诗','song-poetry','','[]','霹靂溝西路，柴荆四五家。',24,'全唐诗/poet.song.32000.json','["霹靂溝西路，柴荆四五家。", "憶曾騎款段，隨意入桃花。"]'),
('12d4cc1b-3d51-4676-8c32-b41f3f66c1e1','午睡','王安石','宋','宋诗','song-poetry','','[]','檐日陰陰轉，床風細細吹。',24,'全唐诗/poet.song.32000.json','["檐日陰陰轉，床風細細吹。", "翛然殘午夢，何許一黄鸝。"]'),
('e8acd91c-1c19-4266-bb70-679f67dd00be','題齊安壁','王安石','宋','宋诗','song-poetry','','[]','日浄山如染，風暄草欲薰。',24,'全唐诗/poet.song.32000.json','["日浄山如染，風暄草欲薰。", "梅殘數點雪，麥漲一溪雲。"]'),
('54d007c1-88af-41e7-bfdd-6fa468706b81','昭文齋','王安石','宋','宋诗','song-poetry','','[]','我自山中客，何緣有此名。',24,'全唐诗/poet.song.32000.json','["我自山中客，何緣有此名。", "當緣琴不鼓，人不見虧成。"]'),
('f507ce3d-3179-46c3-a7be-26a0f6a55e65','臺上示吳願','王安石','宋','宋诗','song-poetry','','[]','細書妨老讀，長簟愜昏眠。',24,'全唐诗/poet.song.32000.json','["細書妨老讀，長簟愜昏眠。", "取簟且一息，拋書還少年。"]'),
